import{t as e}from"./rolldown-runtime-H_PjY6_i.js";var t=e({T0320:()=>a,default:()=>i}),a={title:"Bank Direct-Scan QR",keywords:["Bank Direct-Scan QR","bank app scan","banking QR transfer","direct bank scan","bank-channel QR","bank-to-bank scan","bank collection code","bank pay scan"],aliases:[],category:"Money Laundering",definition:"A money-laundering method that uses a payment QR code generated by a banking app for direct scan-and-transfer, disguising dirty money as ordinary bank transactions.",description:"Bank direct scanning uses the bank’s proprietary channel, keeping fund flow within the banking system. Fraud rings consider this more “stable” than third-party payment codes because risk controls tend to lag. Money-muling crews use bank direct-scan codes to receive large illicit sums; the payer completes the transfer by scanning the code via a banking app, and the transaction record resembles a normal person-to-person transfer. These codes are often paired with models like “code-to-code” or “code-to-USDT,” converting renminbi into cryptocurrency or foreign exchange to further sever the traceability chain.",usageExample:"Exchange rate ceiling, code-to-code, code-to-USDT, bank direct scan, UnionPay code.",relatedRisks:["R0060","R0093","R0121"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0006-005","A0016-002","A0051","A0037"],relatedAttackTools:["AT0026","AT0039","AT0040","AT0060"],relatedThreatActors:["TA0006-003","TA0014"],relatedBusinessScenes:["BS01","BS15"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},i={T0320:a},n=e({T0321:()=>r,default:()=>s}),r={title:"Unionpay QR",keywords:["Unionpay QR","Quick Response code for money laundering","UnionPay collection QR","payment code for illegal funds","UnionPay money receiving frontend","QR code for running score","bank settlement network QR","dynamic QR for illicit collection","static QR for dirty money"],aliases:[],category:"Money Laundering",definition:"A UnionPay-based payment QR code used to receive or transfer illicit funds, serving as a collection entry point in money muling operations that rely on bank clearing networks.",description:"UnionPay QR codes leverage the cross-bank clearing network of UnionPay, covering the vast majority of bank accounts. Criminal actors use them as a front-end tool for collecting funds in money muling schemes. During operations, money mule organizers or platform operators generate dynamic or static QR codes for victims to scan and pay. The funds are then rapidly consolidated into controlled accounts through UnionPay channels. Due to their broad bank-level coverage and instant settlement, these codes are often used to split large sums into small, multiple transactions to evade risk monitoring systems.",usageExample:"QR to QR, QR to USDT, UnionPay QR.",relatedRisks:["R0060","R0093"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0006-005","A0016-002","A0051","A0037"],relatedAttackTools:["AT0026","AT0039","AT0040"],relatedThreatActors:["TA0006-003","TA0014"],relatedBusinessScenes:["BS01"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},s={T0321:r},o=e({T0322:()=>l,default:()=>c}),l={title:"Tier-1 Bank Card",keywords:["Tier-1 Bank Card","high-limit savings account","full-permission bank account","unrestricted transfer account","tier-1 account for money laundering","large-value receiving card","daily large transfer card","online banking full access account","black market bank account"],aliases:[],category:"Money Laundering",definition:"A personal savings account with the highest transaction limits and permissions in the banking system, serving as the preferred entry point for illicit funds in money muling and laundering operations.",description:"Tier-1 accounts possess the highest permissions, including large daily transfer limits and full online banking functionality. Criminal networks specifically acquire these accounts to receive upstream illicit funds from fraud or gambling. Once funds enter, they are rapidly dispersed through multi-tier splitting and fast interbank transfers, exploiting the high quota to reduce the chance of triggering bank risk controls. On the black market, Tier-1 accounts are often sold in bundles with security tokens, credit cards, and corporate accounts to form a complete collection matrix.",usageExample:"Buying Tier-1 accounts, credit cards, token-secured accounts, corporate accounts, and unregistered account holders.",relatedRisks:["R0060","R0093"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044"],relatedAttackTools:["AT0026","AT0039","AT0040"],relatedThreatActors:["TA0006-003","TA0014","TA0015"],relatedBusinessScenes:["BS01","BS04"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},c={T0322:l},d=e({T0323:()=>u,default:()=>h}),u={title:"Corporate Account",keywords:["Corporate Account","shell company account","business bank account for laundering","high-capacity fund channel","corporate account for dirty money","fake trade account","public account for illegal funds","wholesale money laundering account","enterprise account for fraud"],aliases:[],category:"Money Laundering",definition:"A corporate bank account opened in the name of a business, used by criminal actors to receive and circulate large volumes of illicit funds, acting as a high-capacity channel in money muling systems.",description:"Compared to personal accounts, corporate accounts have higher single-transaction and daily cumulative transfer limits. A business background can also be used to fabricate trade flows to disguise the nature of the funds. Criminals acquire these accounts by purchasing shell companies or using fraudulently registered entities. After transferring large sums from fraud or gambling into the account, the money is split and moved out under the guise of payments for goods or services. Due to their large capacity and apparent compliance, they are often used as key nodes for laundering large sums, and any case involvement typically triggers a system-wide risk control upgrade for corporate accounts.",usageExample:"Buying all banks' corporate accounts nationwide, even unused junk accounts, as long as the bank acceptance draft service is activated. Turn them into cash!!!",relatedRisks:["R0060","R0093","R0121"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0061"],relatedAttackTools:["AT0026","AT0039","AT0040","AT0060"],relatedThreatActors:["TA0006-003","TA0014"],relatedBusinessScenes:["BS01","BS15"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},h={T0323:u},p=e({T0324:()=>m,default:()=>g}),m={title:"Card-and-QR Bundle",keywords:["Card-and-QR Bundle","payment card and QR combo","bundled payment resource","receiving channel bundle","card and code package","QR and bank card set","payment method combo","fragmented payment tool","card code bundle"],aliases:[],category:"Money Laundering",definition:"A bundled resource pack combining a bank card with a corresponding payment QR code, providing a ready-to-use collection channel set for downstream members in money muling operations.",description:"A card-code bundle pairs a bank card number with its associated payment QR code into a single resource unit, allowing money mules and code merchants to switch collection methods on demand. These bundles are distributed through chat groups or darknet markets. When receiving payments, operators select the appropriate card or code based on the transaction amount and payment channel requirements. This combination reduces the logistical cost of managing collection tools and fragments the entry points for funds, increasing the difficulty of tracing.",usageExample:"Direct drops for fresh data, 3,000 to 100,000. Both cards and codes accepted. Operating all day, looking for long-term drivers. All bosses welcome.",relatedRisks:["R0060","R0093"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0006-005","A0016-002","A0051","A0037","A0050","A0035","A0052","A0049"],relatedAttackTools:["AT0026","AT0039","AT0040"],relatedThreatActors:["TA0006-003","TA0014"],relatedBusinessScenes:["BS01"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},g={T0324:m},f=e({T0325:()=>y,default:()=>b}),y={title:"Four-Piece Bank Kit",keywords:["Four-Piece Bank Kit","identity theft kit","full account opening set","ID card bank card phone card U-shield","anonymous account bundle","complete verification package","account registration kit","four-piece identity set","black market account package"],aliases:[],category:"Money Laundering",definition:"A complete identity resource pack for account opening, containing an ID card, bank card, SIM card, and U-shield, serving as the basic configuration for building money laundering accounts in bulk.",description:"A four-piece set provides all the core elements needed for fraudulent account opening. After purchase, criminals can register for online banking, link third-party payment services, and activate large transfer permissions. These accounts are used to receive, split, and transfer illicit funds, forming an anonymous money flow chain. Because the complete identity set can bypass in-person bank verification, it is often used to build account pools for money muling on a large scale. Once such a set enters the market, it signifies a deep abuse of the corresponding citizen's personal information.",usageExample:"Selling four-piece bank card sets.",relatedRisks:["R0060","R0093"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044"],relatedAttackTools:["AT0039","AT0026"],relatedThreatActors:["TA0006-003","TA0014"],relatedBusinessScenes:["BS01"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},b={T0325:y},k=e({T0326:()=>w,default:()=>v}),w={title:"Third-Party Payment Platform",keywords:["Third-Party Payment Platform","payment isolation layer","wallet transfer platform","fund obfuscation intermediary","third-party payment for laundering","payment jump platform","money laundering isolation","third-party wallet for dirty money","payment gateway for fraud"],aliases:[],category:"Money Laundering",definition:"A third-party payment platform used by criminals as a buffer layer between bank cards and final recipient accounts to facilitate payment jumps in money laundering.",description:"Third-party payment platforms provide interfaces for wallet top-ups, transfers, and purchases. Criminals transfer illicit funds from bank cards into third-party accounts, then further obscure the money trail through inter-account transfers or purchases of virtual goods. Common tactics include using inter-account transfers, proxy payments, and red packet features to commingle funds. Because these platforms operate independently of the bank clearing system, they can form information silos, making them a critical isolation layer in the money muling chain.",usageExample:"Large amounts via third-party, large amounts via secondary cards, must pass through third-party, reverse scan.",relatedRisks:["R0060","R0093"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044"],relatedAttackTools:["AT0026","AT0039","AT0040"],relatedThreatActors:["TA0006-003","TA0014"],relatedBusinessScenes:["BS01"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},v={T0326:w},A=e({T0327:()=>T,default:()=>B}),T={title:"Digital Gift Card",keywords:["Digital Gift Card","virtual stored-value card","e-card for money laundering","gift card cash-out","digital card for illicit funds","prepaid card for fraud","online shopping card for laundering","card number and password trade","virtual card redemption"],aliases:[],category:"Money Laundering",definition:"Virtual stored-value cards, such as online E-cards and supermarket gift cards, which criminals purchase with illicit funds and then cash out by redeeming or reselling the card details, serving as a virtual liquidation channel for money laundering.",description:"E-cards exist as a card number and password without requiring physical delivery. Criminals buy them in bulk with illicit funds and then clean the money by reselling the card details or redeeming them to purchase physical goods for resale. Because the purchase and redemption actions can be separated across different accounts and IP addresses, this method inherently provides a fund isolation effect. Commonly found on e-commerce and lifestyle service platforms, these cards have small individual values but can be processed in bulk, making them suitable for high-frequency, small-sum money laundering.",usageExample:"Supplying, multiple channels for e-card details.",relatedRisks:["R0060","R0093"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0038","A0060","A0016-001","A0004"],relatedAttackTools:["AT0039","AT0040"],relatedThreatActors:["TA0014"],relatedBusinessScenes:["BS01","BS02"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},B={T0327:T},S=e({T0328:()=>R,default:()=>x}),R={title:"Digital RMB Gateway",keywords:["Digital RMB Gateway","digital yuan hijacking","e-CNY redirection","wallet top-up interception","device-switching for digital RMB","digital currency gateway","e-CNY recharge hijack","digital RMB man-in-the-middle","digital yuan wallet takeover"],aliases:[],category:"Money Laundering",definition:"A technical method that intercepts a user's digital yuan top-up request and redirects it to a device controlled by the criminal, allowing them to funnel fraudulent funds directly into their own wallet.",description:"A digital gateway hijacks a legitimate user's digital yuan top-up process through technical means. The top-up operation, which should be executed on the user's own device, is redirected to a device held by the criminal. Consequently, the victim's funds are deposited directly into the criminal's digital wallet, bypassing the user's own wallet binding and risk verification. This technique achieves fund diversion through device switching, with single transactions typically ranging from 300 to 20,000 yuan. It can operate automatically around the clock with a high degree of stealth.",usageExample:"Digital RMB gateway, single transaction 300-20,000, online 24/7 without interruption.",relatedRisks:["R0060","R0093","R0094"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044"],relatedAttackTools:["AT0026","AT0039","AT0040"],relatedThreatActors:["TA0014","TA0006-003"],relatedBusinessScenes:["BS01"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},x={T0328:R},C=e({T0329:()=>M,default:()=>L}),M={title:"Cryptocurrency",keywords:["Cryptocurrency","virtual currency for money laundering","crypto for illicit funds","anonymous transfer asset","crypto laundering medium","USDT for running score","BTC for fraud","cryptocurrency for criminal proceeds","digital asset for obfuscation"],aliases:[],category:"Money Laundering",definition:"Cryptocurrency refers to virtual assets used by cybercriminal networks to obscure fund flows, serving as a transfer medium for anonymously laundering illicit proceeds.",description:"In money laundering and layering schemes, cryptocurrencies such as USDT and BTC are used as core cleansing tools. Criminals convert illegal fiat currency into cryptocurrency, leveraging its decentralized and cross-border nature to sever the connection between the funds and the original crime. This method is commonly seen in cross-border online gambling and fraud repatriation scenarios, significantly complicating efforts by law enforcement to freeze and trace assets due to its inherent anonymity.",usageExample:"💰💰 High-quality clean funds, accepting cryptocurrency 💰💰 04 Operational model: common methods and profit distribution in layering schemes",relatedRisks:["R0060","R0093","R0121"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044"],relatedAttackTools:["AT0026","AT0060","AT0039"],relatedThreatActors:["TA0006-003","TA0014"],relatedBusinessScenes:["BS01","BS15"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},L={T0329:M},E=e({T0330:()=>z,default:()=>D}),z={title:"Score Running",keywords:["Score Running","account renting for illegal funds","money mule operation","payment proxy for fraud","card running for dirty money","account splitting for laundering","illegal fund transfer agent","money receiving and forwarding","criminal proceeds handling"],aliases:[],category:"Money Laundering",definition:"Layering is a money laundering activity where individuals or groups use their own accounts to receive and forward illicit funds on behalf of criminal enterprises, taking a commission in the process.",description:"Participants in layering, often referred to as 'money mules' or 'card mules,' provide their bank cards, payment QR codes, or third-party payment accounts to upstream criminals to receive proceeds from telecom fraud, online gambling, and other crimes. They then split and transfer the funds to other designated accounts as instructed, facilitating rapid dispersal. This act directly constitutes aiding and abetting criminal activity, exposing participants to frozen accounts and criminal liability.",relatedRisks:["R0060","R0093"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0006-005","A0016-002","A0051","A0037","A0061"],relatedAttackTools:["AT0026","AT0039","AT0040"],relatedThreatActors:["TA0006-003","TA0014"],relatedBusinessScenes:["BS01"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},D={T0330:z},I=e({T0331:()=>F,default:()=>P}),F={title:"Online Score Running",keywords:["Online Score Running","online score running platform","score running app","non-contact money laundering","digital score running","remote score running","online money muling","virtual account layering","internet-based money washing"],aliases:[],category:"Money Laundering",definition:"Online layering is a contactless money laundering operation conducted entirely through internet platforms.",description:"Unlike traditional models requiring physical meetings, online layering relies entirely on dedicated apps or web platforms. Participants accept tasks through the platform, using linked accounts to receive and transfer funds without ever meeting the upstream handler. This model has a low recruitment threshold and spreads rapidly, often disguised as 'part-time payment collection,' attracting individuals seeking quick money with extremely fast capital turnover.",usageExample:"Online layering app, officially recruiting master agents, limited spots available!",relatedRisks:["R0060","R0093"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0038","A0060","A0016-001","A0004"],relatedAttackTools:["AT0026","AT0039","AT0040"],relatedThreatActors:["TA0006-003","TA0014"],relatedBusinessScenes:["BS01"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},P={T0331:F},q=e({T0332:()=>H,default:()=>U}),H={title:"OTC Exchange",keywords:["OTC Exchange","OTC desk","crypto acceptance","fiat-to-crypto exchange","USDT acceptance","crypto settlement","acceptance agent","off-ramp","stablecoin conversion"],aliases:[],category:"Money Laundering",definition:"In the context of cybercrime, cashing out specifically refers to the operation of exchanging fiat currency for cryptocurrencies like USDT.",description:"The cash-out merchant is a key link between the fiat currency pool and the cryptocurrency pool. They receive fiat funds from illegal activities such as fraud and gambling, then pay out an equivalent value in cryptocurrency to the counterparty. This process helps criminal enterprises 'clean' high-risk fiat currency into relatively anonymous virtual assets, moving funds from the regulated banking system into a gray zone, and represents the core exchange link in the money laundering chain.",usageExample:"Accepting second-tier funds from Lingqiantong and Yu'ebao for cash-out back to USDT.",relatedRisks:["R0121","R0060"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0061"],relatedAttackTools:["AT0060","AT0039"],relatedThreatActors:["TA0014"],relatedBusinessScenes:["BS01","BS15"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},U={T0332:H},O=e({T0333:()=>j,default:()=>N}),j={title:"QR-to-USDT Settlement",keywords:["QR-to-USDT Settlement","QR code settlement","USDT return","QR-to-crypto","scan-and-pay laundering","code-to-U","payment code recycling","digital payment washing","QR settlement cycle"],aliases:[],category:"Money Laundering",definition:"QR-to-Crypto is a laundering technique where criminals use payment QR codes to receive fiat currency and then return the funds in the form of USDT.",description:"This method combines the convenience of QR code payments with the anonymity of cryptocurrency. Criminals use a large collection of personal payment QR codes to receive illicit funds; once the money enters the account, they purchase USDT to return to the upstream handler. This model splits the fund trail into 'fiat in, crypto out,' making tracking extremely difficult once it enters the virtual currency stage, and is commonly used for rapid profit distribution in telecom fraud.",usageExample:"Boss, can you do small amounts, 50-1000, QR-to-Crypto?",relatedRisks:["R0121","R0060"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0006-005","A0016-002","A0051","A0037"],relatedAttackTools:["AT0006","AT0060","AT0039"],relatedThreatActors:["TA0014"],relatedBusinessScenes:["BS01","BS15"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},N={T0333:j},_=e({T0334:()=>G,default:()=>Q}),G={title:"Card Receiving",keywords:["Card Receiving","card receiving account","money mule account","direct card deposit","card-based laundering","card drop","account takeover receiving","bank card relay","card collection"],aliases:[],category:"Money Laundering",definition:"Card receiving is the act of directly using a bank card to receive and process illicit funds.",description:"Card receiving is the most basic and direct form of layering. The operator provides their own bank card as a primary or secondary collection account, receiving funds from fraud or gambling operations, then transfers the money out through ATM withdrawals, over-the-counter cash-outs, or online transfers. Due to increasingly strict bank risk controls, such accounts are highly susceptible to rapid freezing, forcing criminal networks to constantly recruit new 'card mules' to supply fresh bank cards and maintain the funding chain.",relatedRisks:["R0060","R0093","R0094"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0061"],relatedAttackTools:["AT0026","AT0039","AT0040"],relatedThreatActors:["TA0005-001","TA0006-003","TA0014"],relatedBusinessScenes:["BS01"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},Q={T0334:G},W=e({T0335:()=>V,default:()=>K}),V={title:"Proxy Payout",keywords:["Proxy Payout","proxy payout service","payment proxy","payout mule","disbursement agent","third-party payout","ghost payee","pay-out intermediary","payout forwarding"],aliases:[],category:"Money Laundering",definition:"Proxy payment is the act of completing payments or cash-outs on behalf of criminal enterprises, serving as a transit point for illicit funds.",description:"Following instructions, a proxy payer uses their own payment account to make specific payments for criminal operations, such as paying fees, distributing salaries, or settling invoices. This is commonly seen when online gambling platforms cash out winnings for gamblers or fraud rings pay their 'call operators.' Proxy payment mixes illicit funds into everyday payment flows, obscuring the final destination of the money. The proxy earns a commission but faces extremely high legal risk.",usageExample:"Hey! Boss, need a proxy payer? 'Scan, buy, book, settle headhunting fees, settle any fee.'",relatedRisks:["R0060","R0093"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0051","A0006-005","A0061"],relatedAttackTools:["AT0039","AT0040"],relatedThreatActors:["TA0014"],relatedBusinessScenes:["BS01"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},K={T0335:V},J=e({T0336:()=>X,default:()=>Y}),X={title:"Small-Ticket Collection",keywords:["Small-Ticket Collection","micro-collection","small-ticket laundering","split deposit","smurfing collection","micro-payment mule","low-value aggregation","fragmented receiving","small-amount pooling"],aliases:[],category:"Money Laundering",definition:"Micro-collection is a money laundering tactic where criminals use other people's accounts to receive multiple small-value illicit payments to evade risk controls.",description:"To avoid bank and payment platform monitoring of large or frequent transactions, criminals split a large illicit sum into countless small payments, dispersing them across numerous collection accounts. The holders of these accounts receive the funds and then consolidate and transfer them to the upstream handler. This 'break it down' strategy is common in the initial task-acceptance phase of layering platforms, effectively reducing the risk of single-transaction interception and serving as a front-end dispersal measure in the laundering chain.",usageExample:"Layering, micro-collection, large supply of QR codes needed.",relatedRisks:["R0060","R0093"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044"],relatedAttackTools:["AT0026","AT0039","AT0040"],relatedThreatActors:["TA0006-003","TA0014"],relatedBusinessScenes:["BS01"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},Y={T0336:X},Z=e({T0337:()=>$,default:()=>ee}),$={title:"Redemption Laundering",keywords:["Redemption Laundering","voucher redemption","gift card washing","card redemption laundering","purchase-based cleaning","redemption mule","coupon conversion","prepaid card cycling","redemption agent"],aliases:[],category:"Money Laundering",definition:"In money laundering operations, write-off refers to the process of disguising illicit funds as legitimate transactions through purchases, redemptions, or card and voucher binding to complete the cleansing cycle.",description:"Criminal actors use proceeds from fraud or gambling to bulk-purchase virtual goods such as shopping cards, membership cards, or group-buying vouchers. These are then monetized through card-and-PIN recycling, resale, or account binding. The operation is typically coordinated by specialized card brokers or write-off agents on money-muling platforms or in private chat groups, with the goal of severing the fund trail and evading risk-control tracking. Once successfully written off, the illicit funds are laundered in the form of consumer spending, making tracing extremely difficult.",usageExample:"Anyone who can buy shopping cards, come through. Supermarket card-and-PIN write-off: you get 650 per recycled card.",relatedRisks:["R0060","R0093"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0061"],relatedAttackTools:["AT0026","AT0039","AT0040"],relatedThreatActors:["TA0003","TA0004","TA0006-003","TA0014"],relatedBusinessScenes:["BS01","BS04"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},ee={T0337:$},te=e({T0338:()=>ae,default:()=>ie}),ae={title:"Card-and-PIN Redemption",keywords:["Card-and-PIN Redemption","card-and-PIN washing","PIN redemption","gift card code redemption","e-card PIN conversion","virtual card cashing","code redemption","card secret cashing","digital voucher redemption"],aliases:[],category:"Money Laundering",definition:"In money laundering operations, card-and-PIN write-off refers to the act of binding illegally obtained electronic card numbers and PINs to accounts or consuming them to realize virtual assets.",description:"After purchasing electronic cards with fraudulent funds, downstream card-and-PIN write-off agents bind the card credentials to designated apps or platform accounts, converting them into usable balances or services. This process often involves e-commerce cards, gaming top-up cards, prepaid cards, and other virtual vouchers. Tasks are distributed through instant messaging groups or darknet postings seeking card-and-PIN recyclers. The practice transforms illicit proceeds into virtual assets that are difficult to trace, representing a common cleansing stage in money-muling and money-laundering schemes.",usageExample:"Anyone who can buy shopping cards, come through. Shopping card-and-PIN write-off: you get 650 per recycled card.",relatedRisks:["R0060","R0093"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044"],relatedAttackTools:["AT0026","AT0039","AT0040"],relatedThreatActors:["TA0006-003","TA0014"],relatedBusinessScenes:["BS01","BS02","BS06"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},ie={T0338:ae},ne=e({T0339:()=>re,default:()=>se}),re={title:"Cash-Out Disposal",keywords:["Cash-Out Disposal","cash-out mule","final extraction","ATM cash-out","physical cash withdrawal","last-mile laundering","value extraction","cash-out runner","offloading"],aliases:[],category:"Money Laundering",definition:"In money laundering operations, offloading refers to the final-stage cash-out act of withdrawing, converting, or spending illicit funds from accounts that have already received them.",description:"After fraudulent funds have been moved through multiple account layers, the final offloading stage is responsible for extracting the money completely. This is typically carried out by cash mules who withdraw cash at ATMs, purchase precious metals, or transfer funds into other controlled accounts. The operation demands speed and stealth, often with account monitors tracking account status in real time to prevent freezes. A successful offload closes the money-laundering loop, returning the funds to the criminal syndicate, and represents a critical node for disrupting money laundering.",usageExample:"Recruiting runners: first- and second-tier card runners, dual-custody maintenance, large-scale mixing, and step-by-step maintenance all the way to offload.",relatedRisks:["R0060","R0093","R0095"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044"],relatedAttackTools:["AT0039","AT0040"],relatedThreatActors:["TA0014-001","TA0014","TA0015"],relatedBusinessScenes:["BS01","BS04"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},se={T0339:re},oe=e({T0340:()=>le,default:()=>ce}),le={title:"Quick Burn",keywords:["Quick Burn","rapid burn","fast cash-out","lightning laundering","instant transfer scheme","quick-hit fraud","burn operation","speed laundering","flash payout"],aliases:[],category:"Money Laundering",definition:"In money laundering operations, quick-kill refers to a rapid attack method that completes fraud scripting and fund transfers within an extremely short window to evade victim detection and risk-control interception.",description:"Criminal syndicates exploit real-time online loan application data or victim information to complete fraudulent calls, induce transfers, and split funds across multiple accounts within minutes. This model requires tight coordination between phone operators and money mules, and is typically executed late at night or during periods of weak platform risk controls. Once a quick-kill succeeds, the funds immediately enter the laundering pipeline. Victims often only realize something is wrong after the money has already been offloaded, making recovery extremely difficult.",usageExample:"Selling real-time online loan application data, suitable for quick-kill/money muling. Looking for first-hand betting sites. Brokers stay away.",relatedRisks:["R0060","R0093"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0050","A0035","A0052","A0049","A0051","A0006-005","A0061"],relatedAttackTools:["AT0026","AT0039","AT0040"],relatedThreatActors:["TA0006-003","TA0014"],relatedBusinessScenes:["BS01"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},ce={T0340:le},de=e({T0341:()=>ue,default:()=>he}),ue={title:"Quick-Pay Card Charge",keywords:["Quick-Pay Card Charge","unauthorized card charge","payment interface abuse","express payment fraud","card-not-present theft","SMS interception","payment binding attack","card binding fraud","stolen card cashout"],aliases:[],category:"Money Laundering",definition:"In money laundering operations, express card deduction refers to a form of account theft where criminals illicitly invoke express payment interfaces to drain funds from victims' bank cards.",description:"Criminal actors exploit leaked bank card information to bind express payment agreements or intercept verification codes, completing deductions without requiring a second confirmation from the cardholder. This technique is often used in conjunction with four-piece identity kits supplied by card brokers, with funds flowing directly into money-mule accounts. Due to its stealth and instant settlement, express card deduction has become a common method for high-frequency, small-value theft and money laundering, with victims often only discovering the theft upon receiving their bank statements.",usageExample:"This group provides first-tier express card deduction. The receiving party must provide a payment video within 30 minutes. If the deadline is exceeded without providing it, the default is that funds have not arrived.",relatedRisks:["R0060","R0093","R0094"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0007","A0016-003","A0021"],relatedAttackTools:["AT0039","AT0026","AT0040"],relatedThreatActors:["TA0003","TA0004","TA0006-003","TA0014"],relatedBusinessScenes:["BS01"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},he={T0341:ue},pe=e({T0342:()=>me,default:()=>ge}),me={title:"Scam Platform",keywords:["Scam Platform","fake gambling site","investment scam platform","pig butchering platform","romance scam app","fake trading app","phony investment portal","scam site backend","bogus betting portal"],aliases:[],category:"Money Laundering",definition:"In money laundering operations, a platform refers to a fake gambling, investment, or wealth-management site or app built by fraud syndicates to induce victims to deposit funds and channel them into the money-laundering pipeline.",description:"Criminal technical teams develop websites or apps that mimic legitimate platforms, manipulating win/loss outcomes or profit data through backend controls to make victims continuously increase their bets or investments. These platforms are typically promoted through adult content, dating, or SMS-based traffic generation. Once funds are deposited, they are routed into pre-configured money-mule accounts. The platform serves as the intersection point where fraud meets money laundering, with victim funds being intercepted and beginning a multi-layered cleansing process.",relatedRisks:["R0150","R0060","R0093","R0097"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0007","A0016-003","A0021","A0006-005","A0016-002","A0051","A0037","A0050","A0035","A0052","A0049","A0061"],relatedAttackTools:["AT0066","AT0026"],relatedThreatActors:["TA0039","TA0006-003","TA0014","TA0016"],relatedBusinessScenes:["BS01","BS04","BS06"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},ge={T0342:me},fe=e({T0343:()=>ye,default:()=>be}),ye={title:"Transaction Limit",keywords:["Transaction Limit","single transaction cap","daily payment ceiling","per-transfer limit","account velocity limit","payment cap evasion","channel limit bypass","split transaction","limit monitoring"],aliases:[],category:"Money Laundering",definition:"In money laundering operations, limit-goose is a homophonic slang term for limit, referring to the single-transaction or daily transaction cap on payment accounts or transaction QR codes.",description:"Criminal operators conducting money-mule transfers must constantly monitor account limit-geese to avoid transaction failures or triggering risk controls due to exceeding caps. Limits vary significantly across different payment channels and account types, and dedicated maintenance personnel within the syndicate are assigned to track limit changes. Once an account hits its limit, a new account must be switched in immediately or order-splitting strategies adjusted; otherwise, the fund chain will be disrupted, impacting laundering efficiency.",relatedRisks:["R0060","R0093","R0094"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0006-005","A0016-002","A0051","A0037"],relatedAttackTools:["AT0026","AT0039","AT0040"],relatedThreatActors:["TA0006-003","TA0014"],relatedBusinessScenes:["BS01"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},be={T0343:ye},ke=e({T0344:()=>we,default:()=>ve}),we={title:"Commission Rate",keywords:["Commission Rate","percentage cut","tiered commission","water rate","profit-sharing ratio","money mule fee","layering fee","cashing-out fee","commission tier"],aliases:[],category:"Money Laundering",definition:"In money laundering operations, points refer to the commission rate taken proportionally by each participant at various stages of the laundering process for profit distribution.",description:"Within the money-mule laundering chain, every tier from the first layer to the offload stage takes a commission at an agreed point rate, typically ranging from 1% to 5% of the total flow. The rate depends on account quality, risk level, and fund volume. Criminal groups often post recruitment ads in formats like points 57+ to attract collaborators. The point-based allocation mechanism is the core profit bond that sustains the laundering network and a central focus of internal negotiation among criminal actors.",usageExample:"Recruiting first-tier large-scale mixing card-to-crypto runners: exchange rate 20+, points 57+, full maintenance through offload.",relatedRisks:["R0060","R0093","R0095"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044"],relatedAttackTools:["AT0026","AT0039","AT0040"],relatedThreatActors:["TA0006-003","TA0014","TA0015"],relatedBusinessScenes:["BS01","BS04"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},ve={T0344:we},Ae=e({T0345:()=>Te,default:()=>Be}),Te={title:"Commission Split",keywords:["Commission Split","account rental fee","mule account payout","drop account commission","percentage-based payout","flow-based commission","mule recruitment incentive","account leasing reward"],aliases:[],category:"Money Laundering",definition:"A commission model in money laundering operations where account providers are paid a percentage of the laundered amount.",description:"In underground money laundering, criminal groups use third-party bank or payment accounts to move illicit funds. Account holders receive a cut based on the transaction volume, incentivizing them to supply more accounts. This practice is prevalent in telecom fraud and online gambling, often ensnaring account providers who may be unaware of the full criminal context, exposing them to legal liability and account freezes.",usageExample:"Run all the A and B accounts with balances over 100k through the point system, using the standard rate.",relatedRisks:["R0060","R0093","R0094"],relatedAvoidances:["A0024","A0015","A0016","A0054","A0044","A0061"],relatedAttackTools:["AT0026","AT0039","AT0040"],relatedThreatActors:["TA0006-003","TA0014"],relatedBusinessScenes:["BS01"],references:[{title:"Exposing Fraud-Laundering Models: Order-Posting Recharge Laundering and Merchant Laundering Spread Rapidly",link:"https://k.sina.cn/article_7857201856_1d45362c001906fzea.html?from=tech"},{title:"The Current Card Vendor Ecosystem Under the Card-Crackdown Campaign",link:"https://www.secrss.com/articles/56050"}],updated:"2026-06-16"},Be={T0345:Te},Se=e({T0346:()=>Re,default:()=>xe}),Re={title:"Floor Runner",keywords:["Floor Runner","pit boss assistant","game recorder","shill","crowd warmer","table helper","runner","casino tout"],aliases:[],category:"Gambling",definition:"A junior operator or assistant in a gambling ring responsible for maintaining order, recording accounts, and enlivening the atmosphere during games.",description:"Pa Zai handle on-the-ground tasks at gambling sessions, such as tracking wins and losses, placating players, and creating a lively environment to keep games running smoothly. They operate under mid-level managers and are the grassroots workforce in underground casinos or mobile gambling dens.",relatedRisks:["R0097"],relatedAvoidances:["A0015","A0016","A0044","A0061"],relatedAttackTools:[],relatedThreatActors:["TA0016"],relatedBusinessScenes:["BS06"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},xe={T0346:Re},Ce=e({T0347:()=>Me,default:()=>Le}),Me={title:"Table Boss",keywords:["Table Boss","pit boss","game organizer","rake collector","loan shark","debt enforcer","casino manager","house manager"],aliases:[],category:"Gambling",definition:"A mid-level manager in a gambling ring who organizes games, collects house commissions, extends credit, and oversees operations.",description:"Pa Tou Zi control the core of gambling operations by setting commission rates, issuing high-interest loans, and maintaining order at the table. They serve as a critical link between gang leaders and junior staff, and their activities often involve violent debt collection and illegal detention.",relatedRisks:["R0097","R0060"],relatedAvoidances:["A0015","A0016","A0044","A0061","A0046","A0057","A0054"],relatedAttackTools:[],relatedThreatActors:["TA0016","TA0014"],relatedBusinessScenes:["BS06","BS01"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},Le={T0347:Me},Ee=e({T0348:()=>ze,default:()=>De}),ze={title:"Rake Rate Slang",keywords:["Rake Rate Slang","house cut","vig","juice","commission calculation","house edge","rake structure","water money"],aliases:[],category:"Gambling",definition:"Various commission calculation methods in gambling that describe the percentage the house takes from bets.",description:"These terms define the house edge: 'Ban Dian' refers to a 5% commission, 'Shang Yi Jiu' to 10%, and 'Ban Yi Jiu' typically around 7.5%. Operators adjust these rates flexibly based on the game type or player status, with regulars sometimes receiving lower rates. This is a core mechanism for controlling profitability and attracting bettors.",relatedRisks:["R0097","R0060"],relatedAvoidances:["A0015","A0016","A0044","A0061"],relatedAttackTools:[],relatedThreatActors:["TA0016","TA0014"],relatedBusinessScenes:["BS06","BS01"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},De={T0348:ze},Ie=e({T0349:()=>Fe,default:()=>Pe}),Fe={title:"Player Broker",keywords:["Player Broker","junket runner","referral agent","player scout","gambling affiliate","VIP room promoter","casino tout","commission agent"],aliases:[],category:"Gambling",definition:"A middleman who drifts between gambling sessions, earning commissions by bringing in players.",description:"Cang Ying Tou do not directly run games but profit by introducing gamblers to specific casinos or tables. They leverage social networks to drive traffic for gambling operators, acting as external promoters in the underground betting chain. Their earnings increase the more the referred players lose.",relatedRisks:["R0097"],relatedAvoidances:["A0015","A0016","A0044","A0061","A0006-005","A0016-002","A0051","A0037"],relatedAttackTools:[],relatedThreatActors:["TA0016"],relatedBusinessScenes:["BS06","BS04"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},Pe={T0349:Fe},qe=e({T0350:()=>He,default:()=>Ue}),He={title:"Shill Play",keywords:["Shill Play","fake action","house player","prop player","simulated gambling","fake volume","stage betting","dummy bettor"],aliases:[],category:"Gambling",definition:"A deceptive practice where gambling organizers fabricate a bustling scene to attract real bettors.",description:"When launching a new casino or game, organizers plant fake players to create an illusion of popularity, enticing onlookers to join. Online platforms may manipulate backend algorithms to let new users win initially before they start losing, trapping them in a cycle of gambling.",relatedRisks:["R0097"],relatedAvoidances:["A0015","A0016","A0044","A0061"],relatedAttackTools:[],relatedThreatActors:["TA0016"],relatedBusinessScenes:["BS06"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},Ue={T0350:He},Oe=e({T0351:()=>je,default:()=>Ne}),je={title:"Rake",keywords:["Rake","house commission","vig","vigorish","juice","table take","cut","croupier's edge","house advantage"],aliases:[],category:"Gambling",definition:"The percentage-based profit the house takes from every wager.",description:"The house commission is the primary revenue model for casinos. Regardless of whether a player wins or loses, the house deducts a fixed percentage from each bet. In physical venues, this is collected by managers like Pa Tou Zi, while online platforms automate the process. Over time, this edge ensures the house always wins.",relatedRisks:["R0097","R0060"],relatedAvoidances:["A0015","A0016","A0044","A0061"],relatedAttackTools:[],relatedThreatActors:["TA0016","TA0014"],relatedBusinessScenes:["BS06","BS01"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},Ne={T0351:je},_e=e({T0352:()=>Ge,default:()=>Qe}),Ge={title:"Remote Betting",keywords:["Remote Betting","phone betting","proxy betting","telephone wagering","live-stream wagering","off-site betting","remote table play","agent-assisted betting","cross-border phone gambling"],aliases:[],category:"Gambling",definition:"A gambling method where bettors use mobile phones to connect to a remote casino in real time and place wagers.",description:"Bettors watch a live video feed on their phones and call in their bets, commonly for simple games like odd-even. This approach bypasses geographic restrictions, allowing overseas casinos to reach domestic players. Funds are moved through underground banking channels, making transactions highly covert.",relatedRisks:["R0097","R0060"],relatedAvoidances:["A0015","A0016","A0044","A0061"],relatedAttackTools:[],relatedThreatActors:["TA0016","TA0014"],relatedBusinessScenes:["BS06","BS01"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},Qe={T0352:Ge},We=e({T0353:()=>Ve,default:()=>Ke}),Ve={title:"Loan Sharking",keywords:["Loan Sharking","juice loan","marker","casino credit","high-interest lending","debt collector","runner","enforcer","rollover debt"],aliases:[],category:"Gambling",definition:"The practice of issuing high-interest loans to gamblers.",description:"Casinos or their affiliates provide on-the-spot loans to desperate gamblers, charging interest by the day or by the game, leading to massive debts. Loan sharks often work in tandem with VIP rooms; once a gambler borrows money, repayment is frequently enforced through violent collection. This mechanism keeps gamblers trapped and is a core method for casinos to extract excessive profits.",relatedRisks:["R0097"],relatedAvoidances:["A0015","A0016","A0044","A0061","A0046","A0057","A0054"],relatedAttackTools:[],relatedThreatActors:["TA0016"],relatedBusinessScenes:["BS06","BS01"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},Ke={T0353:Ve},Je=e({T0354:()=>Xe,default:()=>Ye}),Xe={title:"Settlement House",keywords:["Settlement House","money washing hub","fund layering","cash depot","underground clearinghouse","transfer node","account splitting","capital pool","financial logistics cell"],aliases:[],category:"Gambling",definition:"A den or syndicate specializing in handling gambling fund flows and money laundering.",description:"A money-handling crew takes on the task of diverting funds from casinos or online gambling platforms. They rapidly split and consolidate gambling proceeds through multiple tiers of accounts to sever the traceability of the funds. Operators use numerous other people's accounts for high-frequency transfers, ultimately returning the laundered money to the behind-the-scenes organizers. When investigated, the money-handling crew is often the first link in the financial chain to be exposed.",relatedRisks:["R0097","R0060"],relatedAvoidances:["A0015","A0016","A0044","A0061","A0024","A0054"],relatedAttackTools:["AT0026"],relatedThreatActors:["TA0038","TA0006-003","TA0014","TA0016"],relatedBusinessScenes:["BS06","BS01"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},Ye={T0354:Xe},Ze=e({T0355:()=>$e,default:()=>et}),$e={title:"Rake Settlement",keywords:["Rake Settlement","drop count","cage reconciliation","pit settlement","table drop","chip count","cash box audit","shift settlement","soft count"],aliases:[],category:"Gambling",definition:"The process where casino staff count and settle the house's commission.",description:"After each gambling session, the dealer or cashier gathers the house's cut from the tables, counts the cash or chips on the spot, verifies the accounts, and seals them for storage. Counting the house's commission is a critical internal control action that directly reflects the table's daily commission revenue and prevents staff from embezzling funds or causing discrepancies.",relatedRisks:["R0097","R0060"],relatedAvoidances:["A0015","A0016","A0044","A0061","A0050","A0035","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0016","TA0014"],relatedBusinessScenes:["BS06","BS01"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},et={T0355:$e},tt=e({T0356:()=>at,default:()=>it}),at={title:"Bet Recorder",keywords:["Bet Recorder","chip watcher","table supervisor","floor observer","pit clerk","marker tracker","ladder man","commission recorder","drop box monitor"],aliases:[],category:"Gambling",definition:"A person at the gambling table responsible for recording each gambler's bet amounts and win/loss results.",description:"The bet recorder closely monitors chip movements on the table, reporting each gambler's wager amount and outcome in real-time to ensure the house's commission is accurate. This role requires sharp eyes and quick hands to prevent gamblers from cheating, serving as the first line of defense against fraud.",relatedRisks:["R0097","R0060"],relatedAvoidances:["A0015","A0016","A0044","A0061","A0051","A0006-005"],relatedAttackTools:[],relatedThreatActors:["TA0016","TA0014"],relatedBusinessScenes:["BS06","BS01"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},it={T0356:at},nt=e({T0357:()=>rt,default:()=>st}),rt={title:"Table-Opening Fee",keywords:["Table-Opening Fee","room licensing fee","table rental","seat fee","virtual room purchase","platform subscription","dealer seat cost","game room activation","per-table charge"],aliases:[],category:"Gambling",definition:"A fee paid by online gambling operators to software suppliers for opening virtual rooms.",description:"Online gambling platforms pay software providers based on the number of gambling rooms they open. The more rooms they purchase, the more concurrent games they can host. This fee is a fixed operational cost; software suppliers profit continuously, while platforms cover the cost and earn commission by attracting players to bet.",relatedRisks:["R0097","R0060"],relatedAvoidances:["A0015","A0016","A0044","A0061"],relatedAttackTools:[],relatedThreatActors:["TA0016","TA0014"],relatedBusinessScenes:["BS06","BS01"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},st={T0357:rt},ot=e({T0358:()=>lt,default:()=>ct}),lt={title:"Referral Rebate",keywords:["Referral Rebate","rolling commission","turnover rebate","loss rebate","junket incentive","dead chip program","cashback scheme","whale retention","play-based kickback"],aliases:[],category:"Gambling",definition:"A rebate or commission the casino gives to gamblers based on their wagering amount.",description:"To retain high-rollers, casinos return a percentage of the total betting turnover as cash or chips. This rebate is usually settled daily; the more a gambler wagers, the higher the kickback, incentivizing them to keep betting. This mechanism creates an illusion of recovering losses, while in reality, it further amplifies the gambler's overall losses.",relatedRisks:["R0097"],relatedAvoidances:["A0015","A0016","A0044","A0061"],relatedAttackTools:[],relatedThreatActors:["TA0016"],relatedBusinessScenes:["BS06"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},ct={T0358:lt},dt=e({T0359:()=>ut,default:()=>ht}),ut={title:"Accompanied Gambling",keywords:["Accompanied Gambling","junket companion","escort gambler","bring-in man","referral agent","host","greeter","commission chaser","entourage play"],aliases:[],category:"Gambling",definition:"The act of bringing people to gamble and sharing in the casino's commission revenue.",description:"A recruiter, posing as a regular customer, lures newcomers to the casino. They appear to be gambling companions but actually earn a commission from the house's cut based on the number of people they bring or the amount wagered. This model ensures a steady stream of customers for the casino, provides the recruiter with a share of the profits, and causes newcomers to quickly lose their principal in the accompanied gambling environment.",relatedRisks:["R0097","R0060"],relatedAvoidances:["A0015","A0016","A0044","A0061"],relatedAttackTools:[],relatedThreatActors:["TA0016","TA0014"],relatedBusinessScenes:["BS06","BS01"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},ht={T0359:ut},pt=e({T0360:()=>mt,default:()=>gt}),mt={title:"Chess-and-Card Gambling",keywords:["Chess-and-Card Gambling","private room poker","club-based card game","in-app gambling","social casino","card room app","hidden gambling module","agent-operated table","room-card betting"],aliases:[],category:"Gambling",definition:"A covert term used in underground circles for gambling activities conducted on board game platforms.",description:"While QP superficially stands for board games, within telecom fraud and online gambling circles, it specifically refers to online gambling sessions organized through a room-card model. Organizers create groups on social apps and open virtual rooms; gamblers buy room cards to enter, and the platform profits from the rake. This model is highly covert with rapid capital flows and has become a mainstream form of online gambling.",relatedRisks:["R0097","R0060"],relatedAvoidances:["A0015","A0016","A0044","A0061"],relatedAttackTools:[],relatedThreatActors:["TA0016","TA0014"],relatedBusinessScenes:["BS06","BS04","BS01"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},gt={T0360:mt},ft=e({T0361:()=>yt,default:()=>bt}),yt={title:"Money Mule",keywords:["Money Mule","Money Mule Recruitment","Mule Herder","Mule Network Operator","Funds Intermediary","Cash Courier","Illicit Fund Transfer","Underground Banking Agent","Betting Fund Conduit"],aliases:[],category:"Gambling",definition:"In the gambling black market, a 'basket carrier' is a middleman who uses their network to facilitate the transfer of illicit funds and resolve external troubles for casinos or gambling syndicates.",description:"This role typically does not involve direct gambling. Instead, the carrier leverages their 'background' to provide cover for the flow of gambling funds, moving cash, layered settlement money, or cryptocurrency from the bettor's side to the house's side, thereby evading risk controls and law enforcement. They are often connected to local power structures or insiders, acting as a dual insurance for both the money channel and relationship coordination. If the chain is compromised, the basket carrier becomes the key breakthrough point for cutting off the funds.",relatedRisks:["R0060","R0093","R0097"],relatedAvoidances:["A0015","A0016","A0044","A0061","A0024","A0054"],relatedAttackTools:["AT0026"],relatedThreatActors:["TA0006-003","TA0014","TA0016"],relatedBusinessScenes:["BS06","BS15","BS01"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},bt={T0361:yt},kt=e({T0362:()=>wt,default:()=>vt}),wt={title:"Hole-Card Peeking",keywords:["Hole-Card Peeking","Card Peeking Device","Hidden Camera Cheating","Cheating Software","Poker Sensor","Table Bugging","Live Stream Cheat","Game Backdoor Access","Marked Cards"],aliases:[],category:"Gambling",definition:"In gambling cheating scenarios, 'hole carding' refers to the technical means used by black market operators to spy on opponents' cards in real-time using camera equipment, cheating software, or system backdoors.",description:"Common methods include installing pinhole cameras or modified card sensors at physical tables or within gambling apps, or directly bribing platform operations staff to implant a backdoor, transmitting the opponent's hand to the cheater's terminal. This allows the house or card sharp to lock in a win before placing a bet, rapidly draining the gambler's funds, especially in pig-butchering or baccarat-style games. Discovery of such cheating often leads to violent confrontations or internal gang infighting.",relatedRisks:["R0097"],relatedAvoidances:["A0015","A0016","A0044","A0061","A0051","A0006-005"],relatedAttackTools:["AT0066"],relatedThreatActors:["TA0016"],relatedBusinessScenes:["BS06"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},vt={T0362:wt},At=e({T0363:()=>Tt,default:()=>Bt}),Tt={title:"Rebate Fee / Turnover Fee",keywords:["Rebate Fee / Turnover Fee","Turnover Commission","Rolling Fee","Agent Rebate","Referral Kickback","Running Fee","Wash Fee","Volume-Based Commission","Betting Brokerage"],aliases:[],category:"Gambling",definition:"In gambling-related black market operations, 'washing fee' or 'turnover fee' refers to the commission returned to agents or money mule teams by the casino or platform, calculated as a percentage of the total betting turnover.",description:"This fee is essentially a cut taken from the flow of gambling funds. It is typically deducted by the casino from the total turnover and distributed to intermediaries, junket operators, or money mule teams to incentivize the continuous recruitment of gamblers and the maintenance of fund channels. In scenarios combining telecom fraud and money muling, this fee is often disguised as a 'handling fee' or 'rebate,' but it actually serves as a lubricant for the money laundering chain, significantly diluting the gambler's principal after multiple layers of deductions.",usageExample:"Recruiting for manual money mule work, base salary plus bonus and an extra three points, with a 20% deduction for the turnover fee.",relatedRisks:["R0060","R0093","R0097"],relatedAvoidances:["A0015","A0016","A0044","A0061","A0038","A0060","A0016-001","A0004","A0024","A0054"],relatedAttackTools:["AT0026"],relatedThreatActors:["TA0006-003","TA0014","TA0016"],relatedBusinessScenes:["BS06","BS01"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},Bt={T0363:Tt},St=e({T0364:()=>Rt,default:()=>xt}),Rt={title:"House Boss",keywords:["House Boss","Gambling Den Operator","Underground Casino Manager","Criminal Ring Leader","Game Room Controller","Pit Boss","Illegal Gambling Syndicate Head","Backroom Financier","Gambling Operation Chief"],aliases:[],category:"Gambling",definition:"In gambling-related black market operations, 'rocker' refers to the top-level boss who controls the entire casino operation, managing funds and personnel.",description:"The 'rocker' typically does not directly participate at the tables but orchestrates operations from behind the scenes, overseeing venue rental, personnel recruitment, fund pool management, and peripheral security to ensure the gambling sessions run continuously. They form a vertical management chain with roles like the 'basket carrier' and 'table manager.' When trouble arises, they are often the first to cut off contact and move assets. In online casinos, the 'rocker' may act as the platform administrator, remotely controlling odds, suspending bets, and centralizing funds.",relatedRisks:["R0097"],relatedAvoidances:["A0015","A0016","A0044","A0061"],relatedAttackTools:[],relatedThreatActors:["TA0016"],relatedBusinessScenes:["BS06"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},xt={T0364:Rt},Ct=e({T0365:()=>Mt,default:()=>Lt}),Mt={title:"Winner's Service Fee",keywords:["Winner's Service Fee","House Cut","Table Fee","Winner's Levy","Rake","Service Charge","Transport Fee","Protection Fee","House Commission"],aliases:[],category:"Gambling",definition:"In gambling-related black market operations, 'kiln flower' refers to various fees forcibly taken from winners' profits, which is essentially a disguised commission for the house.",description:"This money is typically collected under the guise of transportation fees, water fees, cigarette fees, or labor costs, and is deducted directly from the winner's earnings. This ensures the house profits regardless of the game's outcome. The percentage for the 'kiln flower' is often agreed upon in advance but can be increased on the spot, serving as a covert method to squeeze gamblers' profits. In mobile gambling setups, this fee also covers costs like transportation and lookouts, sustaining the entire illegal ecosystem.",relatedRisks:["R0097"],relatedAvoidances:["A0015","A0016","A0044","A0061"],relatedAttackTools:[],relatedThreatActors:["TA0016"],relatedBusinessScenes:["BS06"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},Lt={T0365:Mt},Et=e({T0366:()=>zt,default:()=>Dt}),zt={title:"Casino Shuttle",keywords:["Casino Shuttle","Gambling Den Transport","Illegal Taxi","Runner Vehicle","Safe Passage Driver","Drop-off Driver","Lookout Vehicle","Shuttle Service","Ghost Plate Vehicle"],aliases:[],category:"Gambling",definition:"In gambling-related black market operations, a 'kiln car' refers to a vehicle specifically used to transport gamblers to and from an underground casino, forming part of the operation's logistics.",description:"These vehicles are typically dispatched by the casino and driven by individuals familiar with the routes and police checkpoints. They pick up gamblers from a meeting point, transport them to the secret venue, and return them afterward, all within a closed-loop management system. The cars often use fake or cloned license plates and may be equipped with communication jammers to prevent tracking. If compromised, the 'kiln car' can become a key lead for law enforcement to locate the casino's entrance.",relatedRisks:["R0097"],relatedAvoidances:["A0015","A0016","A0044","A0061"],relatedAttackTools:[],relatedThreatActors:["TA0016"],relatedBusinessScenes:["BS06","BS11"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},Dt={T0366:zt},It=e({T0367:()=>Ft,default:()=>Pt}),Ft={title:"Shill Player",keywords:["Shill Player","Decoy Gambler","Fake Player","Plant","Stooge","Crowd Warmer","Atmosphere Builder","House Plant","Prop Bettor"],aliases:[],category:"Gambling",definition:"In gambling-related black market operations, a 'hair-pricker' is a shill hired by the casino to create a lively atmosphere and lure real gamblers into betting by pretending to play.",description:"These shills are usually paid based on their effectiveness, blending in with real gamblers to create a false impression of winning and to drive the betting pace, energizing a slow table. They bear no real risk of loss; any money they lose is covered by the house, and they receive a cut of any winnings. In pig-butchering scams or mobile gambling stalls, 'hair-prickers' are a core tool for creating the illusion of a 'hot' table, tricking victims into believing the game is fair and winnable.",relatedRisks:["R0097"],relatedAvoidances:["A0015","A0016","A0044","A0061","A0051","A0006-005"],relatedAttackTools:[],relatedThreatActors:["TA0016"],relatedBusinessScenes:["BS06"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},Pt={T0367:Ft},qt=e({T0368:()=>Ht,default:()=>Ut}),Ht={title:"Table Banker",keywords:["Table Banker","Cage Cashier","Dealer","Chip Handler","Payout Clerk","Table Cash Handler","House Dealer","Pit Clerk","Money Handler"],aliases:[],category:"Gambling",definition:"In gambling-related black market operations, the 'table manager' is the operator directly responsible for handling cash payments and distributing winnings based on the game's outcome at the table.",description:"The 'table manager' is the terminal executor of fund flow for each round, responsible for counting cash, taking the house's cut, and paying out winnings, ensuring instant settlement between gamblers and the banker. They are usually deeply trusted by the 'rocker' and control the on-site cash pool, but they can also become a vulnerability for internal theft or a 'rip-off.' In online gambling, this role is replaced by automated system settlements, but in physical settings, they are essential for maintaining table order and the closed loop of funds.",relatedRisks:["R0097"],relatedAvoidances:["A0015","A0016","A0044","A0061","A0043","A0027"],relatedAttackTools:[],relatedThreatActors:["TA0016"],relatedBusinessScenes:["BS06"],references:[{title:"Black Market Big Data: 2025 H1 Internet Underground Economy Trend Review",link:"https://www.threathunter.cn/blog/2025-h1-anti-fraud-intelligence"},{title:"Black Market Big Data: 2025 Internet Underground Economy Trend Annual Review",link:"https://www.163.com/dy/article/KJ2QH6LE0518STKV.html"}],updated:"2026-06-16"},Ut={T0368:Ht},Ot=e({T0369:()=>jt,default:()=>Nt}),jt={title:"Forced Loan Activation",keywords:["Forced Loan Activation","Unauthorized Loan Origination","Coerced Lending","Account Takeover Lending","Identity Theft Loan","Forced Credit Line","Involuntary Debt","Ghost Loan","Loan Activation Fraud"],aliases:[],category:"Credit Fraud",definition:"Forcibly activating a loan service through illicit means, often involving theft of customer data or unauthorized deductions.",description:"Fraudsters use stolen or leaked personal information to activate loan products on behalf of victims without their knowledge or consent, then deduct fees or interest upfront. Operators typically bypass risk controls using technical exploits or insider access to process applications in bulk. This practice leaves victims with unexpected debt and limited recourse for recovery.",usageExample:"They got hold of a batch of personal data and forcibly opened loans on them. The victims only found out they were in debt when collection calls started coming in.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Nt={T0369:jt},_t=e({T0370:()=>Gt,default:()=>Qt}),Gt={title:"Fake Mortgage-Free Car",keywords:["Fake Mortgage-Free Car","Title Washing","Lien Avoidance","Fake Lien Release","Unrecorded Mortgage","Auto Loan Fraud","Title Jumping","Collateral Stripping","Vehicle Title Fraud"],aliases:[],category:"Credit Fraud",definition:"Colluding with a vehicle owner to transfer a financed car to a third party before the mortgage registration is completed, thereby evading the lien.",description:"Fraud rings exploit the time gap between loan disbursement and official vehicle mortgage registration. After the lender releases funds but before the lien is recorded, the intermediary helps the owner quickly transfer the vehicle to another party. This leaves the financial institution unable to enforce its security interest, resulting in a bad debt. Common in the used-car market, intermediaries charge high fees while lenders lose both the car and the money.",usageExample:"The intermediary said they could do a fake lien release. They told me to skip the vehicle registration office and transfer the car directly to a buyer they found. Now the bank is coming after me for the debt.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"Black Market Big Data: Deconstructing the Auto Loan Fraud Industry Chain",link:"https://www.threathunter.cn/blog/8acce28b732"},{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Qt={T0370:Gt},Wt=e({T0371:()=>Vt,default:()=>Kt}),Vt={title:"Hard Default",keywords:["Hard Default","intentional default","strategic default","debt refusal","ghost debtor","app uninstall evasion","contact cutoff","debt abandonment","run from debt"],aliases:[],category:"Credit Fraud",definition:"A borrower unilaterally ceases all loan repayments and deliberately cuts off contact with the lending platform.",description:"Borrowers who can no longer afford high interest or who develop resistance to aggressive collection tactics choose to abandon repayment entirely. They typically change their phone numbers, delete the lending app, and brace for consequences like contact-list harassment or credit blacklisting. In underground circles, this is often discussed as a last-resort measure against predatory high-interest lenders.",usageExample:"I'm going to go no-contact on that predatory lender. The interest is insane and I can't keep up. Has anyone here done this before? Will they freeze my payment accounts?",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Kt={T0371:Vt},Jt=e({T0372:()=>Xt,default:()=>Yt}),Xt={title:"Forced Disbursement",keywords:["Forced Disbursement","unsolicited loan","forced loan","loan bombing","ghost lending","predatory disbursement","involuntary debt","forced credit","unconsented loan"],aliases:[],category:"Credit Fraud",definition:"An illegal lending platform unilaterally disburses a loan to a user without their explicit consent, then demands repayment with exorbitant interest.",description:"Predatory lending platforms use technical means to harvest users' contact lists and other private data. Even if a user merely fills out a form without confirming a loan, the platform forcibly transfers money into their account. They then demand repayment on extremely short cycles with excessive fees, threatening to harass the user's contacts if they don't pay. This is a typical extortion tactic, and victims often pay far more than the principal out of fear.",usageExample:"Yesterday I downloaded a shopping app and clicked on a link inside. I registered, uploaded an ID photo, then logged out and deleted the app. Could I still be forced into a loan?",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Yt={T0372:Xt},Zt=e({T0373:()=>$t,default:()=>ea}),$t={title:"Loan Fishing",keywords:["Loan Fishing","credit fishing","application farming","shotgun application","credit inquiry spam","speculative application","approval probing","app spamming","blind app"],aliases:[],category:"Credit Fraud",definition:"An applicant with poor credit knowingly attempts to apply for a loan or credit card from a strict lender, hoping for a system loophole.",description:"Applicants who are aware of their bad credit history, including defaults or excessive inquiries, still submit applications to banks with stringent approval processes, hoping the risk control system will fail. Fraud rings often organize mass 'probing' attempts to identify weak points in a bank's defenses. A single success can trigger a wave of fraudulent applications.",usageExample:"My credit is a bit rough. I tried my luck with two banks last month and got rejected instantly. Guess I need to clean up my credit first.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ea={T0373:$t},ta=e({T0374:()=>aa,default:()=>ia}),aa={title:"Lead Brokering",keywords:["Lead Brokering","lead flipping","deal brokering","client handoff","app resale","lead resale","referral churn","lead pass","deal forwarding"],aliases:[],category:"Credit Fraud",definition:"A loan broker passes a client they cannot service to another broker in exchange for a commission split.",description:"When a broker finds a client's profile doesn't match their available lending channels, they sell the client's information to another broker who can process the loan. This practice leads to repeated reselling of personal data and increases the risk of information leaks. The referring broker earns a commission without further work, while the client may face higher fees or fall into a debt trap.",usageExample:"This client's profile is too weak for my channels. I'll pass them to Old Li's side; the referral fee is twenty thousand per client.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ia={T0374:aa},na=e({T0375:()=>ra,default:()=>sa}),ra={title:"Lead Intake",keywords:["Lead Intake","lead buying","app sourcing","client intake","lead pooling","deal sourcing","referral intake","app aggregation","lead procurement"],aliases:[],category:"Credit Fraud",definition:"A broker with active lending channels acquires loan-seeking clients from other brokers.",description:"Brokers with reliable lending channels post 'client acquisition' notices to attract other intermediaries to supply them with applicants. The acquiring broker prices the client based on their credit profile and pays a commission to the referring broker upon successful loan disbursement. This creates an illicit profit chain where client data is repeatedly traded, making it highly susceptible to secondary fraud.",usageExample:"ChengXin is acquiring clients. Twenty thousand upfront upon signing, plus a six percent internal rebate. No tricks, send your clients over.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},sa={T0375:ra},oa=e({T0376:()=>la,default:()=>ca}),la={title:"Assisted Lead Escort",keywords:["Assisted Lead Escort","deal escort","client chaperoning","app babysitting","payout supervision","commission escort","deal monitoring","escorted application","onsite monitoring"],aliases:[],category:"Credit Fraud",definition:"The referring broker accompanies the client throughout the entire loan application process to supervise the operation and ensure a fair commission split.",description:"In low-trust partnerships, the broker who provided the client will stay with them on-site to prevent being cut out of the deal. The supervising broker monitors the entire packaging, application, and disbursement process to guarantee they receive the agreed-upon percentage of the payout. This is common in cross-regional operations or between first-time collaborators.",usageExample:"Full escort service. Five thousand upfront when you see the client, fifty thousand if the loan fails. A one-thousand good-faith deposit is required after sending the client's documents.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ca={T0376:la},da=e({T0377:()=>ua,default:()=>ha}),ua={title:"Travel-Lodging Advance",keywords:["Travel-Lodging Advance","travel advance","expense float","upfront cost","front money","deal float","expense advance","client float","travel float"],aliases:[],category:"Credit Fraud",definition:"Upfront expenses for travel and accommodation that fraud rings advance to debt applicants, to be deducted from the final payout.",description:"In organized loan fraud schemes, intermediaries cover the travel and operational costs of participants traveling to designated cities. This advance, known as the 'three covers,' is a tactic to attract and lock in participants. Once the loan is approved and disbursed, the intermediary deducts these costs, often with interest, from the participant's share of the fraudulent proceeds.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"Black Market Big Data: Deconstructing the Auto Loan Fraud Industry Chain",link:"https://www.threathunter.cn/blog/8acce28b732"},{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ha={T0377:ua},pa=e({T0378:()=>ma,default:()=>ga}),ma={title:"Credit Easing",keywords:["Credit Easing","approval flood","underwriting gap","approval spike","credit window","lending loophole","approval surge","easy approval period","underwriting ease"],aliases:[],category:"Credit Fraud",definition:"A temporary loosening of a financial institution's risk controls, allowing even those with poor credit to secure loan approval.",description:"This is insider intelligence circulating within fraud rings, indicating that a bank or platform has relaxed its credit approval system for a short period. This weakening of risk controls may stem from system glitches, performance-driven targets, or strategic adjustments, creating a window of opportunity for those with poor credit or high debt to commit loan fraud. Fraud rings quickly mobilize to exploit this brief period for mass applications and illicit fund acquisition.",usageExample:"Bank X is secretly loosening its controls. Normally, I get no credit line, but this time I applied casually and got approved for 60,000 instantly.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ga={T0378:ma},fa=e({T0379:()=>ya,default:()=>ba}),ya={title:"Risk-Control Seasoning Period",keywords:["Risk-Control Seasoning Period","payment seasoning","goodpayer masking","repayment honeymoon","credit grooming","repayment facade","seasoning cycle","debt seasoning","masking period"],aliases:[],category:"Credit Fraud",definition:"A period of staged, on-time repayments orchestrated by fraud rings to evade detection by financial institutions.",description:"After obtaining a loan using false identities or fabricated documents, fraud rings will make the initial monthly payments on behalf of the straw borrower. This artificially created 'good repayment record' is the risk-control period, designed to lull the monitoring system into a false sense of security. The goal is to buy time to apply for larger loans or to abscond with the funds, with a longer period further delaying the exposure of the fraud.",usageExample:"Operating in XX area, the borrower gets XXX in hand, asset package, three-year risk-control period.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ba={T0379:ya},ka=e({T0380:()=>wa,default:()=>va}),wa={title:"Completion Window",keywords:["Completion Window","deal cycle","payout timeline","completion cycle","payout window","deal maturation","payout completion","deal graduation","cycle completion"],aliases:[],category:"Credit Fraud",definition:"The time it takes to complete a full cycle of a fraudulent loan application, from fabrication to fund disbursement.",description:"In the context of credit fraud, 'graduation' refers to the entire process, from packaging false documents and applying for a loan to the final successful disbursement of funds. Fraud rings often advertise their schemes with phrases like 'graduation in X days' to attract clients seeking quick cash or looking to default on debts. A shorter time indicates higher efficiency in the ring's fabrication capabilities and channel access, enabling faster fund extraction and risk transfer.",usageExample:"Direct channel, highest commission settlement, graduation in 15 to 30 days, payout of 3 to 8 million, no direct clients, intermediaries only.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},va={T0380:wa},Aa=e({T0381:()=>Ta,default:()=>Ba}),Ta={title:"Black Room",keywords:["Black Room","account restriction","account lock","risk control block","account suspension","blacklist status","frozen credit line","account quarantine"],aliases:[],category:"Credit Fraud",definition:"A state where a borrower's account is restricted by a financial institution's risk-control system due to suspicious behavior, preventing normal borrowing.",description:"When an account is flagged as being in the 'black room,' it means the user's actions, such as overdue payments, frequent applications, or abnormal profile data, have triggered the platform's risk-control rules. This results in a frozen credit line, instant application rejections, and a loss of access to financial services. It is an automatic punitive and isolation measure taken by the platform upon detecting risk.",usageExample:"I've been in the black room since last November. I forgot to pay yesterday, which was the due date. Will being one day late affect my credit report?",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ba={T0381:Ta},Sa=e({T0382:()=>Ra,default:()=>xa}),Ra={title:"Bank Channel",keywords:["Bank Channel","insider access","loan officer collusion","internal referral","underwriting bypass","private banking channel","backdoor approval"],aliases:[],category:"Credit Fraud",definition:"An internal partnership within a bank that fraud intermediaries leverage to secure irregular loan approvals or more lenient conditions.",description:"A 'channel' is a core asset in the credit fraud ecosystem, referring to a gray network of relationships intermediaries cultivate with bank insiders or third-party companies. Through these connections, they can secure loan approvals for clients with extremely poor qualifications who would normally be rejected, or bypass certain risk-control steps. Intermediaries who possess such channels operate at the top of the fraud chain, using them as leverage to attract downstream partners and charge higher service fees.",usageExample:"Direct channel, no regional restrictions, no upfront or mid-process fees, no guarantor required.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},xa={T0382:Ra},Ca=e({T0383:()=>Ma,default:()=>La}),Ma={title:"Bank Insider Connections",keywords:["Bank Insider Connections","loan officer bribery","approval manipulation","insider fraud ring","underwriter collusion","internal corruption","bank employee compromise"],aliases:[],category:"Credit Fraud",definition:"A corrupt network established by infiltrating a bank's internal operations, enabling the manipulation of the credit approval process.",description:"A 'bank relationship' is a deeper, more corrupt network than a standard 'channel.' It involves fraud rings bribing or colluding with key personnel inside a bank to systematically manipulate the loan approval process. This relationship guarantees irregular loan disbursement for unqualified applicants and is the core capital fraud intermediaries use to demonstrate their power and attract partners. The consequence is a sharp increase in bad debt risk for the financial institution and a fundamental undermining of the credit system's fairness.",usageExample:"Solid bank relationship, can handle single-data or full-package deals.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},La={T0383:Ma},Ea=e({T0384:()=>za,default:()=>Da}),za={title:"Hot-Market Product",keywords:["Hot-Market Product","easy approval loan","loophole product","lax underwriting","trending scam","quick cash window","bypass opportunity"],aliases:[],category:"Credit Fraud",definition:"A trending opportunity in fraud circles, referring to a loan product or scam that is currently easy to exploit due to lax risk controls.",description:"'Trending opportunity' is a popular term in fraud rings for short-lived arbitrage opportunities arising from market shifts, policy loopholes, or technical flaws. These opportunities are characterized by low barriers to entry, fast disbursement, and high credit limits, making them prime targets for concentrated fraud attacks. It could be a newly launched financial product or an older one with a temporarily disabled risk-control strategy, both carrying an extremely high risk of fraud.",usageExample:"Latest trending opportunity, no credit or big data checks, no upfront fees, purely online operation, you can get over 40,000 in hand.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Da={T0384:za},Ia=e({T0385:()=>Fa,default:()=>Pa}),Fa={title:"Sure-Win Deal",keywords:["Sure-Win Deal","guaranteed approval","no-fail method","foolproof deal","guaranteed payout","lock deal","sure-thing loan"],aliases:[],category:"Credit Fraud",definition:"In black market operations, 'steady skin-eater' is used to describe a loan service that is reliable and guaranteed to disburse funds, used to attract collaborators.",description:"Originating from Sichuan-Chongqing dialect, it originally meant having an advantage or being successful. In credit fraud, black market intermediaries use 'steady skin-eater' to package their loan services, emphasizing an extremely high success rate for loan disbursement to lure downstream agents or desperate clients. Once a client is hooked, they often face high fees or the risk of having their personal data stolen.",usageExample:"Steady skin-eater business, no restrictions on household registration, limited spots, come quickly.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0038","A0060","A0016-001","A0004","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Pa={T0385:Fa},qa=e({T0386:()=>Ha,default:()=>Ua}),Ha={title:"Underground Method",keywords:["Underground Method","unlicensed lender","illegal lending app","loan shark app","rogue platform","unregulated lending","shadow lender"],aliases:[],category:"Credit Fraud",definition:"Refers to unlicensed lending platforms or loan-sharking rings that operate outside regulatory oversight using illegal methods.",description:"These platforms typically operate beyond regulatory reach, lending privately through self-built apps or social groups. They are often associated with ultra-high interest rates and violent debt collection, making them hotbeds for fraudulent loan schemes and illegal operations. Borrowers who fall victim not only face financial loss but also potential physical threats.",usageExample:"For the past 9 months, I've basically been relying on underground lenders to make repayments.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ua={T0386:Ha},Oa=e({T0387:()=>ja,default:()=>Na}),ja={title:"Full-Service Packaging",keywords:["Full-Service Packaging","full package service","end-to-end fraud","application packaging","document fabrication service","turnkey fraud solution","managed fraud service"],aliases:[],category:"Credit Fraud",definition:"A full-package fraudulent service provided by black market operators, covering everything from document fabrication and data creation to bank relationship management and loan application.",description:"In credit fraud, 'one-stop service' means the black market intermediary handles all stages of the scam. They forge employment certificates and bank statements for unqualified clients, and may even bribe insiders at financial institutions to ensure loan approval. This all-inclusive service is extremely expensive and high-risk, often resulting in significant bad debt for financial institutions.",usageExample:"Recruiting pure white, white accounts, and real estate credit one-stop service nationwide, total graduation amount starting from 5 million.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"Black Market Big Data: Desperados in Financial Fraud",link:"https://www.threathunter.cn/blog/f17db99edff"},{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Na={T0387:ja},_a=e({T0388:()=>Ga,default:()=>Qa}),Ga={title:"One ID, One Card",keywords:["One ID, One Card","ID card only loan","minimal KYC loan","no-verification loan","simplified application","bare-minimum loan","ID-only car loan"],aliases:[],category:"Credit Fraud",definition:"A simplified loan application model requiring only an ID card and a bank card, commonly seen in car loan fraud.",description:"Exploiting lax review processes at some financial institutions, fraud rings apply for car loans using only an ID and bank card. In practice, they often forge supporting documents like driver's licenses to pass verification. This model is easily exploited for 'buy-and-cash-out' fraud schemes.",usageExample:"Two IDs one card, credit record, settle at 5.7; One ID one card, credit record, settle at 5.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0024","A0016"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Qa={T0388:Ga},Wa=e({T0389:()=>Va,default:()=>Ka}),Va={title:"Two IDs, One Card",keywords:["Two IDs, One Card","dual ID loan","ID plus license loan","enhanced fake docs","license-based fraud","two-document loan","ID and license loan"],aliases:[],category:"Credit Fraud",definition:"A loan application model requiring an ID card, driver's license, and bank card, adding one more layer of identity verification than the 'One ID, One Card' model.",description:"This is a common requirement in car loan fraud, where brokers forge a complete set of documents, including a driver's license, to meet the criteria. By increasing the number of documents, they create a false appearance of compliance to gain the financial institution's trust and secure a higher loan amount.",usageExample:"Two IDs one card, credit record, settle at 5.7; One ID one card, credit record, settle at 5.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0024","A0016"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ka={T0389:Va},Ja=e({T0390:()=>Xa,default:()=>Ya}),Xa={title:"Vehicle Green Book",keywords:["Vehicle Green Book","vehicle title","car ownership certificate","auto registration","pink slip","title fraud","title loan collateral"],aliases:[],category:"Credit Fraud",definition:"In the context of auto loan fraud, refers to the official motor vehicle registration certificate, essentially the vehicle's legal identity document.",description:"The motor vehicle registration certificate serves as legal proof of vehicle ownership. In auto loan fraud, it is a critical document for securing collateralized loans or illegally reselling vehicles. Fraud rings often obtain this certificate through methods such as reporting it lost and reapplying, or by deceiving clients, enabling them to illegally transfer ownership or mortgage the vehicle to cash out.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"Black Market Big Data: Deconstructing the Auto Loan Fraud Industry Chain",link:"https://www.threathunter.cn/blog/8acce28b732"},{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ya={T0390:Xa},Za=e({T0391:()=>$a,default:()=>ei}),$a={title:"Zero-Down Car Purchase",keywords:["Zero-Down Car Purchase","zero down car scam","car loan fraud","straw buyer auto loan","fronted down payment","buy here pay here fraud","auto loan stacking","car loan mule","debt assumption car"],aliases:[],category:"Credit Fraud",definition:"A fraud scheme disguised as a 'Zero Down Payment Car Purchase', where the fraud ring covers the down payment to trick victims into taking out a car loan, then cashes out the vehicle.",description:"Using 'zero down payment' as bait, fraud rings recruit clients desperate for cash or looking for a bargain. They front the down payment to help the client buy the car, then quickly mortgage or sell the new vehicle to cash out. The client ends up with no car and a full loan to repay, while the fraud ring disappears with the cashed-out money, shifting the debt risk to the victim and the financial institution.",usageExample:"0 down payment car purchase, ages 23-60, we handle the operation, must have social security or bank statements.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ei={T0391:$a},ti=e({T0392:()=>ai,default:()=>ii}),ai={title:"Straw Buyer Car",keywords:["Straw Buyer Car","credit mule auto","car loan proxy","straw purchase vehicle","auto loan nominee","fronted car buyer","ghost buyer car","car credit rental","loan stacking mule"],aliases:[],category:"Credit Fraud",definition:"A fraud model where a ring recruits individuals with good credit ('blank slates') to purchase a car for someone else; the actual user then defaults, shifting the debt to the straw buyer and the lender.",description:"The fraud ring pays a fee to lure clients with good credit to use their identity to finance a car for someone else. The vehicle is actually used by a ride-hailing company or a subprime borrower, who makes a few monthly payments before defaulting and disposing of the vehicle for profit. Ultimately, the straw buyer is left with massive debt, and the financial institution suffers a bad loan.",usageExample:"Straw buyer car deals, 2-5 cars per person, done in 10 days.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"[Loan Fraud] Anatomy of the 'Straw Buyer' Car Loan Fraud Technique",link:"https://mp.weixin.qq.com/s?__biz=MzI3NDY3NDUxNg==&mid=2247498306&idx=1&sn=f0b8ef9fd1c4af8416be162a7d37d9f1"},{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ii={T0392:ai},ni=e({T0393:()=>ri,default:()=>si}),ri={title:"Mortgage-Free Car",keywords:["Mortgage-Free Car","unencumbered car loan","title-in-hand financing","no lien auto","car loan without lien","clean title loan","skip title loan","auto loan bypass","lien-free car"],aliases:[],category:"Credit Fraud",definition:"A car financing arrangement where the vehicle is purchased through an installment loan but is not physically mortgaged to the lender, and the full set of ownership documents, including the motor vehicle registration certificate, is handed over to the buyer.",description:"In auto loan fraud schemes, intermediaries exploit a client's credit profile to secure installment financing for a car. After the loan is disbursed, they deliberately skip the vehicle mortgage registration, leaving the car in a \"mortgage-free\" state. Once the buyer receives the green book and invoice, the vehicle can be freely disposed of, while the intermediary collects daily commissions. This tactic bypasses the lender's risk control loop and is frequently used for obtaining multiple loans on a single vehicle or for quick resale to cash out.",usageExample:"Big credit lines or poor credit, based on client profile, mortgage or mortgage-free cars, remote system processing, settled every three days.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:'【Credit Fraud】Unveiling the "Mortgage-Free Car" Fraud Tactic in the Auto Loan Fraud Chain',link:"https://www.threathunter.cn/blog/a469288539b"},{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},si={T0393:ri},oi=e({T0394:()=>li,default:()=>ci}),li={title:"Car Loan Cashout",keywords:["Car Loan Cashout","auto equity stripping","car title loan cashout","vehicle liquidation scam","car loan flipping","auto loan cashout scheme","title washing car","car loan bust out","auto collateral stripping"],aliases:[],category:"Credit Fraud",definition:"A fraudulent scheme where individuals in urgent need of cash actively seek out or are recruited to purchase a car with a loan and immediately resell it to pocket the cash.",description:'Underground brokers specifically target "blacklisted" individuals with poor credit records but who still qualify for loans, packaging the scheme as a legitimate "car financing" service. The broker covers the down payment or fabricates the applicant\'s credentials. The car is registered under the individual\'s name, and within a week of purchase, it is sold at a discount to a car dealer, netting the seller around 150,000 yuan in cash. This model essentially defrauds financial institutions of credit funds; the car is quickly offloaded, and the loan defaults, resulting in bad debt.',usageExample:"Blacklisted car flipping, operating in Guangdong, can do 2-3 units, registered under personal name, one week to get 150k in hand, age 20-55.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},ci={T0394:li},di=e({T0395:()=>ui,default:()=>hi}),ui={title:"Nominee-Owned Property",keywords:["Nominee-Owned Property","mortgage mule","straw buyer property","air loan mortgage","property credit mule","nominee mortgage fraud","silent second mortgage","mortgage stacking scheme","fake homebuyer"],aliases:[],category:"Credit Fraud",definition:"A scheme where the actual property buyer is not the genuine end-user but a paid individual who holds the property title on behalf of a third party to fraudulently obtain a bank mortgage.",description:"In the mortgage fraud chain, developers seeking rapid cash flow or a clean exit recruit individuals with clean credit histories, known as \"nominee holders,\" to sign fake purchase contracts. The nominee applies for a mortgage, and once the bank disburses the funds, the money goes to the developer, while the property is nominally registered under the nominee's name. Both parties sign a private repurchase agreement, stipulating the developer will buy back the property within two to three years. If the market declines or the developer's capital chain breaks, the nominee is left solely responsible for the massive debt.",usageExample:"Sign a repurchase nominee property deal, the property will be bought back from the client within 2 years, property value around 700-800k.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},hi={T0395:ui},pi=e({T0396:()=>mi,default:()=>gi}),mi={title:"Loan Rollover",keywords:["Loan Rollover","debt reshuffling","loan stacking","refinance fraud","evergreening loan","debt restructuring scam","serial refinancing","kiting loans","double-dipping loan"],aliases:[],category:"Credit Fraud",definition:"A short-term borrowing practice of applying for a new loan to repay an existing debt, used to maintain cash flow or conceal overdue records.",description:'When insolvent clients cannot repay a maturing loan, intermediaries help fabricate their credentials to apply for a larger loan. The newly acquired funds are then used to fill the hole of the old debt. This "borrow new to repay old" tactic can temporarily protect a credit score from overdue marks, but the debt snowball grows larger. Intermediaries often boast about "no-liability debt rolling," but in reality, they shift all the risk onto the borrower and the financial institutions that eventually hold the bag, often triggering a cascade of defaults.',usageExample:"An older woman wants to carry debt, she can get a 1 million yuan bank loan. After doing this, how many years of rolling debt can be free of the intermediary's liability? The documents are fake. She's 54.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},gi={T0396:mi},fi=e({T0397:()=>yi,default:()=>bi}),yi={title:"Direct Debt Carry",keywords:["Direct Debt Carry","bad debt absorption","direct loss cover","bank loss takeover","debt assumption scheme","write-off front","loss booking scam","debt parking scheme","charge-off cover"],aliases:[],category:"Credit Fraud",definition:"A business model where a bank directly assumes the loan risk and bad debt losses and manages the recovery of non-performing asset portfolios; underground brokers often fabricate such a credit endorsement to deceive victims.",description:'Underground brokers falsely claim to have a "direct bank backing" channel, capable of handling internal bad debt digestion or non-performing asset portfolio disposal, using this as a fabricated official endorsement to attract clients. In reality, banks rarely outsource non-performing assets directly to external individuals. The intermediary merely uses this title to gain trust, while secretly operating illegal businesses like debt loading or loan packaging. Once hooked, clients are often tricked into signing fraudulent agreements and ultimately face legal recourse.',usageExample:"Local direct backing, get 3 million+ in hand, done in about ten days, clean credit, one or two inquiries are fine. The asset package window is closing soon, hurry up and send people, do a couple of deals and take a break.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},bi={T0397:yi},ki=e({T0398:()=>wi,default:()=>vi}),wi={title:"Short-Term Bridge Loan",keywords:["Short-Term Bridge Loan","bridge loan shark","payday bridge","loan renewal scam","debt rollover trap","hard money flip","balloon payment trap","bridge-to-default","refi trap"],aliases:[],category:"Credit Fraud",definition:"A short-term funding service provided by individuals or illegal financial organizations to clients whose bank loans are due and cannot be repaid, offering bridge capital at exorbitant interest rates.",description:'When a borrower\'s bank loan matures and they cannot raise the funds to repay it, underground "short-term bridge" intermediaries step in to provide the capital to clear the loan. Once the bank renews the loan and disburses the new funds, the intermediary recoups the principal and charges upfront interest or high service fees. This operation often targets small and medium-sized business owners, with amounts ranging from 100,000 to 5 million yuan. If the loan renewal is not approved, the borrower is saddled with both the bank loan and the high-interest private debt, making them highly vulnerable to violent debt collection.',usageExample:"Accepting [SME short-term bridge loans], 100k to 5 million.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},vi={T0398:wi},Ai=e({T0399:()=>Ti,default:()=>Bi}),Ti={title:"Payday Cannon Loan",keywords:["Payday Cannon Loan","loan shark app","usury loan","balloon interest","debt trap loan","cycle debt loan","predatory micro loan","exorbitant interest","loan flipping"],aliases:[],category:"Credit Fraud",definition:"An illegal loan product with an annualized interest rate far exceeding the legal limit, an extremely short term, and compounding interest that causes the debt to balloon rapidly.",description:"These loans typically calculate interest on a daily, weekly, or monthly basis, with annualized rates often exceeding 500%. Through upfront interest deductions and extension fees, the debt swells rapidly. Lenders are usually unlicensed underground banks or online cash loan platforms, specifically targeting people in urgent need of money with no other financing options. Once a borrower defaults, they face high-frequency harassment, contact list bombing, and other violent collection tactics, making the debt virtually impossible to repay.",usageExample:"Seriously, this loan shark has been around for years, persistently harassing me every few days. It was named and shamed on the 315 Gala, why isn't it shut down yet? Over two thousand for a card, got just over a thousand in hand, and they still have the nerve to demand money.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Bi={T0399:Ti},Si=e({T0400:()=>Ri,default:()=>xi}),Ri={title:"Predatory Loan Scam",keywords:["Predatory Loan Scam","debt trap scheme","false contract loan","phantom debt creation","loan fraud ring","asset stripping loan","forced debt assumption","debt bondage scam","fabricated default"],aliases:[],category:"Credit Fraud",definition:"A systematic scam disguised as private lending, designed to illegally seize a victim's property by fabricating debt, deliberately creating defaults, and destroying repayment evidence.",description:"Operators first lure victims with low barriers and fast disbursement to sign dual contracts or blank agreements. They then artificially inflate the loan amount, deliberately manufacture defaults, and conceal repayment records to create a false creditor's right. Once the victim is unable to repay, they initiate lawsuits or use threats of violence to force the victim to settle the debt with property or other assets. The entire process is tightly orchestrated, trapping victims in a debt snare without their knowledge, ultimately causing them to lose substantial assets.",usageExample:"\"The officer told me today that this kind of trap loan is illegal, and I shouldn't be afraid of being sued, they can't sue over this. The officer's exact words. Basically, just ignore it.\"",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},xi={T0400:Ri},Ci=e({T0401:()=>Mi,default:()=>Li}),Mi={title:"Blacklisted Borrower Loan",keywords:["Blacklisted Borrower Loan","credit invisible loan","bad credit loan","no credit check loan","subprime loan shark","underground lending","black credit borrower","loan sharking"],aliases:[],category:"Credit Fraud",definition:"Illegal high-interest loans targeting individuals with severely damaged credit histories or no credit records at all.",description:"These loans are operated by unregulated lenders who exploit borrowers’ inability to access formal financing, profiting through exorbitant interest rates and harsh terms. Commonly found on underground online lending platforms or among private lending rings, borrowers face violent debt collection or rapidly compounding debt once they fall behind on payments.",usageExample:"Black-credit loans—everyone who gets rejected elsewhere is guaranteed approval here. We don’t check liabilities, court lawsuits, court enforcement actions, or current delinquencies. All can be processed.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Li={T0401:Mi},Ei=e({T0402:()=>zi,default:()=>Di}),zi={title:"Account-ID Loan",keywords:["Account-ID Loan","Apple ID pawn","phone collateral loan","device-locked loan","mobile account hostage loan","ID pawn"],aliases:[],category:"Credit Fraud",definition:"A short-term illegal high-interest loan secured by handing over control of a mobile device account.",description:"Borrowers are required to surrender access to their Apple ID or Android account, giving the lender leverage to enforce repayment. Upon default, the lender locks the device or extracts private data. With extremely short cycles and sky-high interest, this loan targets people in urgent need of cash who lack other collateral, and is commonly circulated through social media and underground lending channels.",usageExample:"For black-credit applicants, we require at least an iPhone 12 Pro or higher. First-time ID loan: 1,800 approved, 1,200 in hand, repayment due in one week.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS04","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Di={T0402:zi},Ii=e({T0403:()=>Fi,default:()=>Pi}),Fi={title:"Device Rental Loan",keywords:["Device Rental Loan","rent-to-own scam","device leasing trap","tech rental shark","lease-to-loan scheme","electronic rental fraud"],aliases:[],category:"Credit Fraud",definition:"A high-interest lending scheme disguised as an electronics rental arrangement.",description:"Intermediaries lure students or financially strained individuals with promises of no verification and low barriers, signing them to rental contracts whose effective annual interest far exceeds legal limits. When a borrower defaults, they face not only steep penalties but also potential violent collection or litigation, blurring the line between leasing and lending.",usageExample:"Credit score 650+, device rental loan. Agencies looking to cash out, come discuss—high volume, top quality.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0051","A0006-005","A0016"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Pi={T0403:Fi},qi=e({T0404:()=>Hi,default:()=>Ui}),Hi={title:"55 Payday Loan",keywords:["55 Payday Loan","5-day loan","50 percent interest loan","payday lending","short-term shark","weekly loan shark","high-interest short loan"],aliases:[],category:"Credit Fraud",definition:"An illegal online loan product with an extremely short term and exorbitant interest rate.",description:"For example, borrowing 1,000 yuan and repaying 1,500 yuan after just five days, representing a 50% interest charge. Operated by unlicensed online lending platforms, these products prey on borrowers who have no other options, rapidly piling on penalty interest and collection pressure after default, which easily pushes borrowers into a debt spiral.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ui={T0404:Hi},Oi=e({T0405:()=>ji,default:()=>Ni}),ji={title:"Loan Harvesting",keywords:["Loan Harvesting","equity stripping","deed theft","home stealing loan","property deed scam","mortgage fraud scheme","loan-to-own fraud"],aliases:[],category:"Credit Fraud",definition:"A fraudulent scheme that uses a sham loan agreement to illegally seize a borrower’s real estate.",description:"Criminal rings entice property owners into signing loan contracts that embed property transfer clauses. Exploiting the borrower’s urgent need for cash or lack of legal awareness, the perpetrators ultimately take possession of the property through litigation or violent enforcement. The elderly are a primary target, and the entire process is meticulously designed to make recovery extremely difficult.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ni={T0405:ji},_i=e({T0406:()=>Gi,default:()=>Qi}),Gi={title:"Drop-In Borrower",keywords:["Drop-In Borrower","loan mule","credit mule","airborne mule","interstate loan fraud","synthetic identity applicant","straw borrower"],aliases:[],category:"Credit Fraud",definition:"Out-of-town recruits with no local ties who are used as disposable fronts in credit fraud operations.",description:"Underground brokers scout across the country for individuals with no stable employment or credit history, transporting them in batches to target cities to file concentrated loan applications. These individuals serve as figureheads to complete in-person verification steps, then vanish once the loan is disbursed, leaving lenders with little recourse for recovery.",usageExample:"Nationwide, disposable fronts, no-identity applicants, no driver’s license required.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Qi={T0406:Gi},Wi=e({T0407:()=>Vi,default:()=>Ki}),Vi={title:"Legit-Channel Operator",keywords:["Legit-Channel Operator","licensed lender","bank loan","regulated credit","institutional loan","prime loan"],aliases:[],category:"Credit Fraud",definition:"Loan products issued by state-licensed and regulated financial institutions.",description:"These products are offered by banks or licensed consumer finance companies with relatively transparent rates and terms, though subject to stricter vetting. In underground lending contexts, the term is often used to contrast legitimate channels with illicit ones, or as a filtering criterion when identifying targets for fraud.",usageExample:"Currently carrying over 300,000 in total liabilities. A regular loan has been granted a one-month extension. Right now I have no steady income stream, no business license, but I own a fully paid-off property worth 2 million with the deed in hand, unmarried.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ki={T0407:Vi},Ji=e({T0408:()=>Xi,default:()=>Yi}),Xi={title:"Dummy Car Loan",keywords:["Dummy Car Loan","vulnerable adult exploitation","incapacity car loan","car loan straw purchase","auto loan fraud","vehicle title scam"],aliases:[],category:"Credit Fraud",definition:"A fraudulent auto loan obtained by exploiting the identity of individuals with intellectual disabilities or those incapable of managing their own affairs.",description:"Criminal organizations recruit vulnerable people lacking sound judgment, take out car loans in their names, then immediately resell the vehicles for profit, shifting all risk onto financial institutions. The barrier to entry is extremely low; with minimal packaging, the fraudsters can bypass risk controls, leading to a high incidence of bad debt.",usageExample:"Disability-exploitation car loans, available for any household registration with a credit record. Three to five days to completion, guaranteed to pass three rounds of risk control, handled end-to-end by us.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Yi={T0408:Xi},Zi=e({T0409:()=>$i,default:()=>en}),$i={title:"Debt Mule",keywords:["Debt Mule","debt slave","credit mule","debt assumption fraud","bust-out scheme","credit washing","synthetic debt"],aliases:[],category:"Credit Fraud",definition:"In black-market fraud, a debt mule who is packaged and used to fraudulently obtain large loans.",description:"Fraud rings recruit individuals with no credit history or assets, then artificially build up their credit profile by fabricating property ownership, business operations, and other assets. After a period of credit grooming, they apply for large loans from financial institutions in the mule's name. Once the loan is disbursed, the ring and the mule split the proceeds, while the mule is left with the full debt and a ruined credit record. This scheme frequently results in bank bad debt and undermines financial order.",usageExample:"Taking orders province-wide. Business license must be at least two years old and transferred over six months ago! Genuine operations with a physical location, zero invoices and zero tax filings are all acceptable. Debt mules can be used, with credit lines ranging from 2 to 5 million.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0051","A0006-005","A0016"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},en={T0409:$i},tn=e({T0410:()=>an,default:()=>nn}),an={title:"Big Trouble",keywords:["Big Trouble","terminal illness discounting","viatical fraud","deathbed loan","terminally ill exploitation","patient recruitment scam","clinical trial fraud"],aliases:[],category:"Credit Fraud",definition:"In black-market fraud, a terminally ill patient exploited for financial discounting or insurance scams.",description:"Fraud rings specifically seek out patients with terminal diagnoses and critical-condition notices from hospitals, then exploit their identities for financial fraud. Common schemes include recruiting patients under the guise of drug trials, or using their identities to take out high-value insurance policies or loans that are then discounted for immediate cash before the patient dies. Family members are often lured by high payouts into signing fraudulent agreements, ultimately facing legal and financial liability.",usageExample:"Terminally ill clients wanted. Drug trial participants under 48, receive 700,000 in hand, cash paid upon signing!",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},nn={T0410:an},rn=e({T0411:()=>sn,default:()=>on}),sn={title:"Borrower-Sourcing Broker",keywords:["Borrower-Sourcing Broker","lead generation intermediary","traffic broker","client referral agent","loan applicant sourcing","underground lead gen","borrower recruitment","commission-based referral","black-market lead provider"],aliases:[],category:"Credit Fraud",definition:"In the black-market chain, a role responsible for referring clients to loan fraud intermediaries.",description:"A client broker does not directly process loans but uses their own channels to find individuals seeking loans and refers them to partner intermediaries or operators. They earn commissions or referral fees, making them a crucial link in the fraud supply chain. Many self-proclaimed brokers with large client networks are active in social media groups, though their actual conversion rates vary widely.",usageExample:"Always looking for client brokers. No time-wasters, no pie-in-the-sky dreamers, no drama.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0006-005","A0016-002","A0051","A0037"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS04","BS11"],references:[{title:"【Credit Fraud】Exposing the 'Repayment-Free Car' Scam in Auto Loan Fraud Rings",link:"https://www.threathunter.cn/blog/a469288539b"},{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},on={T0411:sn},ln=e({T0412:()=>cn,default:()=>dn}),cn={title:"Direct Source Operator",keywords:["Direct Source Operator","core fund controller","primary source operator","direct channel holder","top-tier orchestrator","funding source principal","insider connection handler","wholesale fraud operator","upstream capital controller"],aliases:[],category:"Credit Fraud",definition:"In black-market fraud, the key operator who directly controls core funding and channel resources.",description:"A primary operator typically holds ultimate control over the source of funds, insider bank connections, or core identity-packaging techniques, sitting at the top of the fraud chain. They rarely interact with clients directly, instead distributing business through layers of agents. Most intermediaries claiming to be 'direct operators' are actually middlemen. To avoid risk, true primary operators work only with specific channels and maintain a highly concealed identity.",usageExample:"Face-to-face, flexible communication. Big data score 65 and above. Local primary operator.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0038","A0060","A0016-001","A0004","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},dn={T0412:cn},un=e({T0413:()=>hn,default:()=>pn}),hn={title:"Clean Credit Thin File",keywords:["Clean Credit Thin File","no-hit credit file","zero-trade-line report","credit invisible applicant","unscored consumer","first-time borrower target","blank credit profile","thin file exploitation","pristine credit record"],aliases:[],category:"Credit Fraud",definition:"Refers to an individual with a completely blank credit report, containing no credit history whatsoever.",description:"These individuals have never applied for a credit card or loan, leaving their credit report entirely empty, referred to in fraud circles as a 'blank slate.' Fraud intermediaries exploit their clean records to commit first-time large-loan fraud with a higher success rate. With no repayment history, financial institutions find it difficult to assess their true credit risk, making them ideal targets for packaging and exploitation.",usageExample:"Accepting applications nationwide: doing pure unsecured loans, accepting blank slates, unlimited intake.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},pn={T0413:hn},mn=e({T0414:()=>gn,default:()=>fn}),gn={title:"Blacklisted Borrower",keywords:["Blacklisted Borrower","severely delinquent borrower","credit blacklist target","defaulted loan applicant","unbankable debtor","subprime fraud lead","charge-off candidate","blocklisted individual","hard-bounced credit"],aliases:[],category:"Credit Fraud",definition:"In black-market fraud, a borrower with an extremely poor credit history who has been blacklisted by financial institutions.",description:"These individuals are already unable to obtain loans through legitimate channels due to severe defaults or dishonesty. Fraud intermediaries exploit loopholes in some online lending platforms' risk controls, or use forged documents and identity packaging, to apply for loans specifically for these 'blacklisted' borrowers. Such operations often involve high fees and can easily lead to derivative problems like aggressive debt collection.",usageExample:"Exclusive for blacklisted borrowers, matrix product, available to blacklisted individuals.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},fn={T0414:gn},yn=e({T0415:()=>bn,default:()=>kn}),bn={title:"Loan Bro",keywords:["Loan Bro","professional non-payer","intentional defaulter","serial loan abuser","debt evasion community","malicious borrower","never-pay mindset","deliberate delinquency","bad-faith applicant"],aliases:[],category:"Credit Fraud",definition:"In black-market fraud, a professional loan fraudster who maliciously defaults after borrowing.",description:"Operating with a 'borrowing is earning' mentality, these individuals specifically target online lending platforms with lax risk controls. They are active in various communities, sharing tips on evading debt collection, delaying repayment, and identifying which platforms are easiest to borrow from. Their actions directly cause platform default rates to soar, making them a primary target for anti-fraud systems.",usageExample:"Guys, I applied for a collection suspension via online customer service, finally got transferred to a human to request it, but the agent ignored me and stopped replying. What's going on? Has anyone who got a suspension teach me what to say?",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},kn={T0415:bn},wn=e({T0416:()=>vn,default:()=>An}),vn={title:"Full Identity Fabrication",keywords:["Full Identity Fabrication","complete identity fabrication","full-document forgery","synthetic business setup","total profile counterfeiting","deep fake application","enterprise shell packaging","comprehensive credential fraud","wholesale identity manufacturing"],aliases:[],category:"Credit Fraud",definition:"A fraudulent scheme in which a borrower's entire profile is fabricated to appear creditworthy.",description:"Intermediaries forge a complete set of fake documents for unqualified clients, including fake business licenses, fake bank statements, fake social security and housing fund contribution records, and even rent physical spaces to pose as a business location. This operation is costly and time-consuming but can secure high-value loans. Once successful, the client and intermediary split the loan proceeds and abscond, leaving financial institutions with massive bad debt.",usageExample:"Full packaging for nearby clients, ages 25-49, no more than 6 credit inquiries in the last six months. Disbursement in 3 days, 400,000 per household.",relatedRisks:["R0146","R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},An={T0416:vn},Tn=e({T0417:()=>Bn,default:()=>Sn}),Bn={title:"Light Profile Enhancement",keywords:["Light Profile Enhancement","income inflation","cosmetic credit repair","document touch-up","selective profile enhancement","superficial data polishing","light-touch forgery","application window dressing","minor credential adjustment"],aliases:[],category:"Credit Fraud",definition:"A fraud tactic involving limited falsification of a borrower's profile to pass loan approval checks.",description:"Fraudsters engage in targeted embellishment of loan application materials by inflating income statements, optimizing credit reports, or adjusting asset-liability ratios. Commonly seen in credit fraud scenarios, the goal is to increase approval rates and credit limits from financial institutions. This type of packaging typically does not alter core identity information, only surface-level data, making it relatively covert.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Sn={T0417:Bn},Rn=e({T0418:()=>xn,default:()=>Cn}),xn={title:"Credit Seasoning",keywords:["Credit Seasoning","full-subsidy grooming","debt mule preparation","pre-funded credit building","three-expense coverage","sleeper asset cultivation","front-loaded maintenance","straw borrower nurturing","long-term credit priming"],aliases:[],category:"Credit Fraud",definition:"A preparatory fraud scheme where a syndicate provides full-chain financial support to a debt mule to secure higher loans.",description:"In debt mule fraud, intermediaries or syndicates provide the mule with full board and lodging and cover upfront costs such as mortgage down payments, car loan down payments, taxes, and even business license fees. Through this fully-funded model, the mule is packaged as a high-quality borrower. Once the loan is disbursed, the funds are split among the syndicate, while the mule assumes all the debt.",usageExample:"Mortgage, credit, business, car loans—fully-funded model. Looking for credit invisibles, age 23 to 48, all upfront costs covered.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Cn={T0418:xn},Mn=e({T0419:()=>Ln,default:()=>En}),Ln={title:"Existing Business License",keywords:["Existing Business License","pre-seasoned license","ready-to-transfer entity","aged shell company","immediate business transfer","pre-existing corporate vehicle","turnkey company registration","shelf corporation handover","pre-cultivated enterprise"],aliases:[],category:"Credit Fraud",definition:"A pre-prepared, seasoned business license that can be immediately transferred to a debt mule.",description:"In corporate debt fraud, syndicates register companies in advance and maintain them to create the illusion of good business performance. When a suitable mule is found, the company is directly transferred, eliminating the need for the mule to build a business credit profile from scratch. This significantly shortens the fraud cycle and enables rapid access to high-value business loans.",usageExample:"Ready-to-go business licenses available for immediate transfer. Deposit required for entry, transfer and change of ownership done quickly. Urgent call for agents with clients.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},En={T0419:Ln},zn=e({T0420:()=>Dn,default:()=>In}),Dn={title:"Four-Flow Consistency",keywords:["Four-Flow Consistency","fabricated transaction trail","synthetic business documentation","false contract alignment","fake logistics records","counterfeit invoice matching","artificial revenue proof","staged financial flows","documentary consistency fraud"],aliases:[],category:"Credit Fraud",definition:"The fabrication of contracts, logistics, capital flow, and invoices to create a false picture of a company's operational health.",description:"In corporate loan fraud, to make a shell company appear operational, fraudsters fabricate upstream and downstream transaction contracts, forge logistics documents, generate fake capital flows, and issue fraudulent invoices so that all four data streams corroborate each other. This highly realistic, closed-loop data set effectively deceives financial risk control systems to secure large corporate loans.",usageExample:"Nationwide trade volume and capital increase services, business incubation, upstream and downstream contract packages with invoices, four-flow integration, mid-year financial data beautification.",relatedRisks:["R0017","R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},In={T0420:Dn},Fn=e({T0421:()=>Pn,default:()=>qn}),Pn={title:"Show-Funds Placement",keywords:["Show-Funds Placement","proof of funds display","balance sheet window dressing","temporary capital injection","inflated bank balance","fake financial strength","capital verification fraud","asset falsification","loan qualification padding"],aliases:[],category:"Credit Fraud",definition:"A scheme where a large sum of money is temporarily deposited into an account to create a false impression of financial strength for loan fraud.",description:"When applying for large loans, fraudsters bring in external funds to temporarily deposit a large sum into the borrower's account to demonstrate financial capability to the bank. Once the loan is approved and disbursed, these funds are quickly transferred out. This causes financial institutions to issue loans based on a false credit profile, leading to significant bad debt risk.",usageExample:"Capital display and account padding services for projects, corporate capital increase and verification, pass-through transactions.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},qn={T0421:Pn},Hn=e({T0422:()=>Un,default:()=>On}),Un={title:"Matched Shell Company",keywords:["Matched Shell Company","shell company matching","corporate identity packaging","business entity forgery","fake business profile","straw company setup","enterprise fabrication","nominee director scheme","shell corp handover"],aliases:[],category:"Credit Fraud",definition:"The practice of equipping a debt mule with a shell company to fraudulently obtain loans from financial institutions.",description:"In debt mule fraud, syndicates transfer a pre-registered or purchased shell company to the mule, making them the nominal business owner. They then 'equip' the company by generating fake transaction flows and contracts, packaging the shell as an operational entity to apply for business loans. After the loan is disbursed, the mule is left with the debt while the syndicate splits the funds.",usageExample:"Bank connections nationwide, guaranteed approval of 3 to 5 million, strong communication, real shell company setup, inquiries welcome.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},On={T0422:Un},jn=e({T0423:()=>Nn,default:()=>_n}),Nn={title:"Housing-Credit-Enterprise Combo",keywords:["Housing-Credit-Enterprise Combo","mortgage-credit-enterprise stacking","multi-product loan cycling","sequential loan max-out","credit exhaustion scheme","asset-backed fraud layering","loan stacking attack","full-spectrum lending fraud"],aliases:[],category:"Credit Fraud",definition:"A sequential fraud model combining mortgage, credit, and business loans to maximize extraction from a single debt mule.",description:"This is a fixed operational process for multi-round loan fraud against a single mule. The syndicate first uses the mule to apply for a mortgage, then leverages the property for consumer credit or renovation loans, and finally packages the mule as a business owner for a corporate loan. This layered approach maximizes the mule's credit value in the shortest possible time.",usageExample:"Mortgage, credit, business, car loans. Looking for credit invisibles with total liabilities under 50,000. Upfront costs covered.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},_n={T0423:Nn},Gn=e({T0424:()=>Qn,default:()=>Wn}),Qn={title:"Credit Whitewashing",keywords:["Credit Whitewashing","credit repair scam","negative entry suppression","credit history manipulation","black mark removal","credit bureau dispute abuse","credit file tampering","debt record erasure"],aliases:[],category:"Credit Fraud",definition:"The illegal practice of erasing or concealing an individual's negative credit history.",description:"Operating under the guise of 'credit repair,' fraudsters attempt to delete or modify negative information like overdue payments and bad debts from credit reports by forging documents, maliciously complaining to financial institutions, or exploiting system vulnerabilities. This practice not only defrauds clients of high service fees but also severely disrupts the financial credit system, and the promised 'cleansing' is often unattainable.",usageExample:"Credit repair and cleansing, pay after processing, no charge if unsuccessful.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0038","A0060","A0016-001","A0004"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Wn={T0424:Qn},Vn=e({T0425:()=>Kn,default:()=>Jn}),Kn={title:"Break Out of the Black Room",keywords:["Break Out of the Black Room","black room breakout","account restriction bypass","risk control circumvention","frozen account reactivation","credit limit unblocking","device fingerprint spoofing","shadow credit line"],aliases:[],category:"Credit Fraud",definition:"Bypassing bank or online lending platform risk controls to restore frozen borrowing or credit limit increase functions through specific operations.",description:"In credit fraud, some users are placed in a “black room” by the system after triggering risk control rules, preventing them from borrowing or increasing their credit limit. Fraud syndicates or users forcibly restore account functions by fabricating transaction records, binding specific co-branded cards, or altering device fingerprints to circumvent the platform’s risk model. Such operations often involve fake transactions and identity forgery. Once detected by the platform, they may lead to stricter account freezes or legal liability.",usageExample:"A few days ago I successfully bypassed the blacklist using the XX co-branded card, and my limit is now 15k04.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Jn={T0425:Kn},Xn=e({T0426:()=>Yn,default:()=>Zn}),Yn={title:"Upfront Costs",keywords:["Upfront Costs","front-end loading costs","borrower packaging expense","qualification fabrication cost","synthetic identity investment","straw borrower prep","credit profile build cost","application grooming fee"],aliases:[],category:"Credit Fraud",definition:"The total upfront costs invested in packaging a borrower’s profile during debt assumption loan fraud operations.",description:"In large-scale loan fraud operations, debt assumption intermediaries need to create a false image of a high-quality borrower for the debt assumer, which involves a series of upfront investments. These costs include purchasing shell company licenses, processing fake asset transfers, fabricating business cash flows, and making back payments on social security or housing fund contributions. Intermediaries typically pass these costs onto the debt assumer or downstream intermediaries to reduce their own risk. If the loan fails or is blocked by risk controls, these investments become sunk costs, worsening the financial losses of the participants.",usageExample:"Accepting applications nationwide: 3.6% annualized rate, guaranteed loan approval, low upfront costs, interest-only payments initially with principal due at maturity, drawdown and repayment at any time, no pressure.",relatedRisks:["R0146","R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Zn={T0426:Yn},$n=e({T0427:()=>er,default:()=>tr}),er={title:"Settlement Split",keywords:["Settlement Split","profit-sharing ratio","proceeds split percentage","commission tier","payout allocation","fraud revenue share","kickback percentage","settlement cut"],aliases:[],category:"Credit Fraud",definition:"The agreed percentage split of the loan disbursement among parties in a loan fraud scheme.",description:"In the chain of debt assumption or intermediary-facilitated loan fraud, after the loan is disbursed, the capital provider, operator, debt assumer, and intermediaries at various levels split the proceeds according to a pre-agreed ratio. This ratio is often expressed in “tenths,” e.g., 7 tenths means taking 70% of the total disbursed amount. The settlement tier determines the profit distribution at each stage; the higher the tier and the more core the resources controlled, the larger the share. This profit-sharing mechanism incentivizes multi-level intermediary referrals and amplifies the scale of credit fraud.",usageExample:"Direct capital source settles at 70% (net profit) with generous rebates, priority given to dual-clean applicants.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},tr={T0427:er},ar=e({T0428:()=>ir,default:()=>nr}),ir={title:"Commission Rate",keywords:["Commission Rate","commission percentage","service fee rate","risk-adjusted fee","brokerage point","facilitation fee rate","cut of proceeds","channel fee percentage"],aliases:[],category:"Credit Fraud",definition:"The service fee percentage charged by fraud syndicates to clients based on the risk level of the operation.",description:"In credit fraud, money muling, and other underground activities, intermediaries or operators charge different fee percentages based on the risk level of the business. The more covert the operation channel, the larger the amount involved, and the higher the probability of being blocked by risk controls, the higher the fee percentage. For example, the fee for large-scale debt assumption using a fake business is far higher than for ordinary personal consumer loan packaging. The fee percentage is a core metric for fraud syndicates to measure risk and return; a high percentage often implies a higher fraud success rate or more severe legal consequences.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0024","A0016"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},nr={T0428:ir},rr=e({T0429:()=>sr,default:()=>or}),sr={title:"Upfront Interest Deduction",keywords:["Upfront Interest Deduction","prepaid interest deduction","loan principal skimming","disbursement shorting","interest front-loading","usurious deduction","off-the-top fee","principal haircut"],aliases:[],category:"Credit Fraud",definition:"The portion of interest deducted upfront from the principal when a predatory loan is disbursed.",description:"In illegal lending or underground banking operations, the lender does not disburse the full principal amount but directly deducts a large sum as interest, so the borrower actually receives far less than the contract amount. This practice conceals the true interest rate and traps the borrower in a debt cycle from the start. Upfront interest deductions are common in short-term cash loans and trap loans, serving as a means for fraud syndicates to quickly extract funds from borrowers, and often lead to violent debt collection and serial fraud.",usageExample:"For this loan, a total of over 600 was deducted as upfront interest. The service fee was over a hundred. This was my last drawdown, and it’s been overdue for nearly ten years.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},or={T0429:sr},lr=e({T0430:()=>cr,default:()=>dr}),cr={title:"Ten-Grand Cash Brick",keywords:["Ten-Grand Cash Brick","cash bundle","currency brick","ten-thousand note stack","banded banknotes","bulk cash unit","physical cash block","paper bundle"],aliases:[],category:"Credit Fraud",definition:"Slang term used in underground circles for ten thousand yuan in cash.",description:"In cash-intensive underground transactions, money muling, or debt assumption settlements, fraud operators often use “brick” to refer to ten thousand yuan in cash, as a bank-strapped bundle of hundred-yuan notes resembles a brick. This jargon facilitates discreet communication about sums of money without explicitly mentioning the amount. The movement of large numbers of “bricks” typically involves offline cash handovers, gambling fund transfers, or illegal fund splitting, and is a hallmark of money laundering and illegal settlement.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0024","A0016"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},dr={T0430:cr},ur=e({T0431:()=>hr,default:()=>pr}),hr={title:"Bring-Your-Own Upfront Costs",keywords:["Bring-Your-Own Upfront Costs","upfront capital","self-funded packaging","pre-loan qualification","business license purchase","bank flow fabrication","social security top-up","debt farming prep","front-end cost"],aliases:[],category:"Credit Fraud",definition:"The debt assumer or intermediary provides their own funds to cover upfront costs for borrower profile packaging and daily expenses.",description:"In debt assumption fraud operations, some participants must bear all upfront costs required to package the borrower’s profile, including purchasing business licenses, fabricating cash flows, making back payments on social security and housing fund contributions, and even daily expenses to maintain the appearance of business operations. This model usually means the intermediary does not advance funds, shifting the capital risk onto the debt assumer or downstream parties. Self-funded upfront operations often target larger corporate loans with stricter scrutiny; if the packaging fails, the participant faces massive financial losses.",usageExample:"Direct channel, judicial protection guaranteed, daily settlement, foreign exchange: recruiting many people, must have passport, 30-day cycle, guaranteed 6 to 10 million, self-funded upfront costs.",relatedRisks:["R0146","R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},pr={T0431:hr},mr=e({T0432:()=>gr,default:()=>fr}),gr={title:"Discount Lead Intake",keywords:["Discount Lead Intake","low-cost lead intake","bulk client acquisition","channel consolidation","lead dumping","discount lead flow","lead arbitrage","cold point intake"],aliases:[],category:"Credit Fraud",definition:"A customer acquisition model where loan intermediaries accept client resources from other channels at extremely low fees.",description:"In loan fraud intermediary networks, when an intermediary has sufficient processing capacity or capital sources, they accept client resources in bulk from other intermediaries at fees far below market rates, a model known as “freezing-point acquisition.” It leverages resource complementarity among intermediaries to quickly match borrowing needs with fraud channels, improving client conversion rates. Freezing-point acquisition often implies relaxed client qualification requirements and is frequently accompanied by fake document packaging and risk control circumvention, concentrating risk heavily.",usageExample:"Instant approval of 200k with just an ID card! Approved on the spot if you have a repayment record, freezing-point acquisition.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},fr={T0432:gr},yr=e({T0433:()=>br,default:()=>kr}),br={title:"Client Buyout",keywords:["Client Buyout","one-time payout","full asset purchase","account buyout","card buyout","lifetime buy","permanent card purchase","no-recourse buy"],aliases:[],category:"Credit Fraud",definition:"A one-time payment made by fraud operators to intermediaries to acquire exclusive control over a customer or bank account and all subsequent proceeds.",description:"In loan fraud, fraud operators pay a fixed fee to intermediaries to buy out customer profiles, after which the operators independently handle loan applications, cash-outs, and other operations without sharing profits with the intermediary. In money laundering, this refers to purchasing a bank card outright without returning it to the original holder, using it to receive and move illicit funds until the card is flagged or frozen. This model breaks the traceability chain and complicates tracking.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0024","A0016"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},kr={T0433:br},wr=e({T0434:()=>vr,default:()=>Ar}),vr={title:"Interest Suspension Arrangement",keywords:["Interest Suspension Arrangement","interest waiver negotiation","penalty interest removal","debt restructuring scam","fake hardship proof","medical certificate forgery","debt settlement fraud","blacklist risk"],aliases:[],category:"Credit Fraud",definition:"A practice where proxy agencies negotiate with banks on behalf of debtors to waive interest and penalty fees and allow repayment of the principal in installments.",description:"Proxy agencies negotiate with banks in the debtor's name, claiming they can have credit card overdue interest and penalty fees waived, so that only the principal is repaid in installments. In practice, these agents often fabricate poverty certificates, medical records, and other documents, charge exorbitant service fees, and expose debtors' personal information. This often leaves the debtor with unresolved debts, additional costs, and blacklisting by the bank.",usageExample:"For those with overdue credit cards or online loans, or about to become overdue, we can arrange a principal-only installment plan with waived interest.",relatedRisks:["R0096","R0096-001"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0038","A0060","A0016-001","A0004","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0029"],relatedBusinessScenes:["BS01","BS11"],references:[{title:'Credit Fraud: Exposing the Black Industry Behind Illegal "Proxy Rights Protection" in the Financial Sector',link:"https://www.threathunter.cn/blog/e78513e348b"},{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ar={T0434:vr},Tr=e({T0435:()=>Br,default:()=>Sr}),Br={title:"Customized Installment Plan",keywords:["Customized Installment Plan","debt rescheduling","fake complaint pressure","negotiated repayment","forged poverty proof","debt optimization scam","malicious complaint","debtor exploitation"],aliases:[],category:"Credit Fraud",definition:"A black-market debt relief service in which illicit agencies negotiate adjusted repayment plans with lenders on behalf of overdue borrowers.",description:"Illicit debt-relief agencies exploit borrowers' financial distress by filing proxy complaints or conducting sham negotiations with banks and online lending platforms to restructure installment repayment plans. These operations often involve forging supporting documents and exerting pressure through malicious complaints. Borrowers risk having their personal data resold and may face legal liability due to falsified materials.",usageExample:"Debt optimization, credit report dispute appeals, capital services, credit card personalized installment plans up to 60 months.",relatedRisks:["R0096","R0096-001"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0038","A0060","A0016-001","A0004","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0029"],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Sr={T0435:Br},Rr=e({T0436:()=>xr,default:()=>Cr}),xr={title:"Debt Custody",keywords:["Debt Custody","collection call takeover","debt relief scam","custody fee","harassment shielding","debt negotiation fraud","fake material submission","debt mismanagement"],aliases:[],category:"Credit Fraud",definition:"A service in which a debt-relief agency promises to handle debt collection calls and negotiate debt reduction on behalf of the debtor.",description:"Under the guise of debt management, agencies take over collection calls for debtors and claim they can negotiate debt forgiveness, while in reality charging high management fees. Their operations often involve forging documents, filing malicious complaints, and other illegal tactics, leading to misuse of personal information, worsening debt problems, and missed repayment opportunities due to false promises.",usageExample:"Debt management service, no need to check your account, just 150 a month.",relatedRisks:["R0096","R0096-001"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0038","A0060","A0016-001","A0004","A0050","A0035","A0016","A0052","A0049"],relatedAttackTools:[],relatedThreatActors:["TA0029"],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Cr={T0436:xr},Mr=e({T0437:()=>Lr,default:()=>Er}),Lr={title:"Aggressive Collector",keywords:["Aggressive Collector","debt collector harassment","phone bombing","contact list explosion","abusive collection","third-party collection abuse","predatory collector","collection harassment"],aliases:[],category:"Credit Fraud",definition:"A derogatory term used by debtors to refer to third-party debt collectors.",description:"In the context of loan fraud and debt collection, debtors use this term for collection agencies or individuals who employ threats, intimidation, harassment, and other high-pressure tactics. These collectors disregard the debtor's actual situation, using frequent phone bombardment, verbal abuse, and contact list exposure to force repayment, often provoking intense confrontation.",usageExample:"The caller immediately asked when I would settle my debt on xx platform. I was confused, then asked if they had the wrong number. Only later did they say they weren't a debt collector thug but a specialist handling interest, and asked if I needed help.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Er={T0437:Lr},zr=e({T0438:()=>Dr,default:()=>Ir}),Dr={title:"Get Clear of Debt",keywords:["Get Clear of Debt","debt-free life","debt clearance","escape debt cycle","debt relief completion","loan payoff","end debt harassment","debt freedom"],aliases:[],category:"Credit Fraud",definition:"The state in which a borrower has fully repaid all debts and escaped a debt trap.",description:"In the context of financial fraud and underground lending, this term refers to a debtor who has completely settled all outstanding obligations, either through personal effort or by leveraging debt relief agencies, thereby breaking the cycle of borrowing from one lender to pay another. Once 'ashore,' the debtor is no longer subject to collection harassment and can resume a normal life, though the process may involve gray-area practices such as illegal cash-outs or negotiated debt reductions.",usageExample:"I owe less than 60k—how can I get ashore? My credit report has charge-offs, my loan records have been blacklisted twice, and my salary is too low to get out of this right now.",relatedRisks:["R0096","R0096-001"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044","A0038","A0060","A0016-001","A0004"],relatedAttackTools:[],relatedThreatActors:["TA0029"],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},Ir={T0438:Dr},Fr=e({T0439:()=>Pr,default:()=>qr}),Pr={title:"Fall Into Debt Spiral",keywords:["Fall Into Debt Spiral","debt spiral","borrowing to repay","loan stacking","debt trap","cycle of debt","debt accumulation","compound debt"],aliases:[],category:"Credit Fraud",definition:"The process by which a borrower takes out an initial loan and gradually sinks into a cycle of borrowing to repay existing debts until the situation spirals out of control.",description:"Unable to repay the initial loan, the debtor is forced to take new loans to pay old ones, causing interest and principal to snowball until the debt becomes completely unmanageable. During this process, borrowers are often lured into illegal channels such as loan sharking and fraudulent lending schemes, sinking deeper into financial distress—the opposite of getting ashore.",usageExample:"I sent a message but haven't heard back. Not sure if it'll work out. I really can't borrow anymore! I've gotten ashore twice but sank back down both times.",relatedRisks:["R0096"],relatedAvoidances:["A0015","A0046","A0057","A0054","A0044"],relatedAttackTools:[],relatedThreatActors:[],relatedBusinessScenes:["BS01","BS11"],references:[{title:"2024 H1 Credit Fraud Risk Landscape Report",link:"https://www.threathunter.cn/blog/2024-ab1e8b8c-509b-44e7-9dbe-d7271765ae2c"},{title:"Black Market Big Data: Exposing Malicious Loan Brokers",link:"https://zhuanlan.zhihu.com/p/17601711058"}],updated:"2026-06-16"},qr={T0439:Pr},Hr=e({T0440:()=>Ur,default:()=>Or}),Ur={title:"Underground Economy",keywords:["Underground Economy","Black Industry","Gray Industry","Cyber Crime Industry"],aliases:["Black Industry","Gray Industry"],definition:"Underground economy refers to industrial chains that exploit network vulnerabilities or regulatory loopholes through technical means or organized operations to carry out illegal profit-making activities.",description:"The underground economy is a collective term for black and gray industries on the internet. Black industry refers to clearly illegal criminal activities such as fraud, theft, and money laundering, while gray industry operates in legal gray zones, including fake transactions, bonus abuse, and data scraping. The underground economy has formed a complete industrial chain with distinct divisions of labor and high professionalization. Upstream actors provide tools and resources such as card merchants who supply payment cards, account sellers who provide bulk registered accounts, and data brokers who trade stolen credentials. Midstream operators implement specific attacks including credential stuffing to take over accounts, traffic manipulation to game platform algorithms, and direct fraud schemes targeting users. Downstream participants handle monetization through various channels and conduct money laundering to obscure the illegal origins of funds. This sophisticated ecosystem continuously evolves its techniques to evade detection and enforcement, causing severe harm to internet companies through financial losses and reputation damage, while exposing users to fraud, identity theft, and privacy violations.",usageExample:"This gang is a typical underground economy organization"},Or={T0440:Ur},jr=e({T0441:()=>Nr,default:()=>_r}),Nr={title:"Credential Stuffing",keywords:["Credential Stuffing","Account Takeover","Password Reuse Attack"],definition:"Credential stuffing is an attack method where cybercriminals use leaked username-password combinations to attempt bulk logins across other websites or applications to obtain valid accounts.",description:"Credential stuffing attacks exploit users' habits of reusing the same credentials across multiple platforms. Attackers obtain massive collections of username-password combinations from data breaches and use automated tools to attempt bulk logins on target platforms. When a match succeeds, they gain account control and proceed with theft, fraud, or account resale for profit. Unlike brute-force attacks which try random password combinations, credential stuffing uses real user credential pairs that have been verified to work on at least one platform, resulting in significantly higher success rates and making detection much harder with traditional defense mechanisms. The attack typically employs sophisticated techniques including distributed IP addresses to avoid rate limiting, rotating user agents to mimic legitimate browsers, and advanced evasion methods to bypass security controls such as CAPTCHAs and behavioral analysis. Successful attacks can lead to unauthorized access to financial accounts, exposure of personal data, and enable further downstream fraud activities including identity theft, financial fraud, and unauthorized purchases. The impact extends beyond individual victims to platforms that suffer reputation damage and regulatory scrutiny."},_r={T0441:Nr},Gr=e({T0442:()=>Qr,default:()=>Wr}),Qr={title:"Store Matrix",keywords:["Store Matrix","Multiple Stores","Batch Store Opening"],definition:"Store matrix refers to an e-commerce black-hat practice of creating numerous stores in bulk and listing products across them to increase exposure and sales volume.",description:"The store matrix model exploits platform traffic allocation mechanisms by registering multiple store accounts in bulk and listing identical or similar products across these stores, forming a store network to increase product exposure opportunities and order acquisition probability. This practice often operates alongside dropshipping models and directly violates platform rules that typically allow one store per person, effectively monopolizing platform resources and disrupting fair market competition. Store matrix operators usually employ automated tools to manage stores at scale, handling product listing, price adjustments, order processing, and other operations in a coordinated fashion, forming a scaled black-gray industry chain. This approach artificially inflates search results by creating multiple duplicate or near-duplicate listings for the same products, misleads consumers who believe they are comparing different sellers when in reality all stores are controlled by the same operator, and undermines the platform's ranking algorithms which are designed to surface quality merchants based on genuine performance metrics. The practice also creates unfair competitive advantages for bad actors while legitimate sellers who follow the rules struggle to gain visibility.",usageExample:"This gang operated hundreds of stores on the platform through the store matrix model"},Wr={T0442:Qr},Vr=e({T0443:()=>Kr,default:()=>Jr}),Kr={title:"Dropshipping Store",keywords:["Dropshipping","No Inventory","Cross-platform Reselling"],definition:"A dropshipping store is a business model that involves scraping products from other platforms to resell on one's own platform, then ordering from the original store and shipping directly to customers after receiving orders.",description:"The dropshipping model is essentially a form of reselling or product scraping where operators hold no physical inventory. Instead, they collect product information from other platforms through manual copying or automated scraping tools, mark up prices to include their profit margin, and list these products in their own stores as if they were the original sellers. When buyers place orders, operators then purchase the items from the source platform using the buyer's shipping address, effectively acting as middlemen who profit from the price difference without adding value. This model carries multiple serious risks and legal issues. It frequently involves infringement of intellectual property rights by unauthorized use of others' product images, descriptions, and brand materials. Product quality cannot be guaranteed since operators never inspect the merchandise and have no control over supplier standards. After-sales service is severely compromised because operators lack direct supplier relationships and cannot efficiently handle returns, exchanges, or complaints. Logistics timing becomes unpredictable as orders pass through multiple handlers, leading to delayed deliveries and customer dissatisfaction. Some dropshipping operations also engage in false advertising and selling inferior products marketed as premium goods, seriously damaging consumer rights and platform credibility.",usageExample:"This store uses the dropshipping model, with all products drop-shipped from other platforms"},Jr={T0443:Kr},Xr=e({T0444:()=>Yr,default:()=>Zr}),Yr={title:"Algorithmic Discrimination",keywords:["Algorithmic Discrimination","Algorithm Bias","Price Discrimination"],aliases:["Algorithm Bias"],definition:"Algorithmic discrimination refers to the phenomenon where algorithmic systems produce unfair differential treatment toward different user groups, causing specific groups to suffer adverse impacts.",description:"Algorithmic discrimination stems from multiple sources including biases embedded in training data that reflect historical prejudices, flaws in model design that fail to account for fairness considerations, or improper business objective settings that prioritize profit maximization over equitable treatment. This leads algorithms to produce systematic differential treatment toward different groups during decision-making processes. Common manifestations include price discrimination based on detailed user profiles where loyal customers are charged more, restrictions on credit approval or employment opportunities for specific demographic groups based on proxy variables, and biased display of search and recommendation results that favor certain products or viewpoints while suppressing others. Algorithmic discrimination not only violates fundamental fairness principles but may also solidify and amplify existing social biases by encoding them into automated systems that affect millions of users. It infringes upon users' legitimate rights to equal treatment and can perpetuate existing inequalities while creating economic harm to vulnerable groups. The Algorithmic Recommendation Regulations for Internet Information Services explicitly require that algorithm service providers must not use algorithms to implement unreasonable differential treatment, and regulatory authorities have begun penalizing platforms that engage in such practices.",usageExample:"This platform was penalized by regulators for implementing price discrimination against loyal customers through algorithmic discrimination"},Zr={T0444:Yr},$r=e({T0445:()=>es,default:()=>ts}),es={title:"Filter Bubble",keywords:["Filter Bubble","Echo Chamber","Information Cocoon"],aliases:["Echo Chamber","Information Cocoon"],definition:"Filter bubble refers to the phenomenon where overly personalized recommendation algorithms narrow users' information access, trapping them in homogeneous information environments.",description:"The filter bubble concept originates from scholar Cass Sunstein's research on how algorithmic recommendation systems filter and push content based on users' historical behaviors, causing users to be exposed to similar information over extended periods while rarely encountering different viewpoints and diverse content. To improve user retention metrics and click-through rates, algorithms continuously recommend content aligned with user preferences, forming a positive feedback loop that leads to progressively narrowed user perspectives and deepened cognitive biases. This phenomenon can trigger several serious consequences for individuals and society. At the individual level, filter bubbles lead to group polarization where people become more extreme in their views due to lack of exposure to moderate or opposing perspectives, reduced information diversity that limits knowledge and understanding of complex issues, and impaired independent thinking abilities as users become accustomed to content that simply confirms their existing beliefs. The Algorithmic Recommendation Regulations for Internet Information Services specifically address this issue by requiring platforms to provide options not targeting personal characteristics, thereby safeguarding users' algorithmic transparency and choice rights. Breaking out of filter bubbles requires conscious effort from both platforms implementing diversification mechanisms and users actively seeking varied information sources.",usageExample:"This user lacked awareness of external changes due to long-term exposure to a filter bubble"},ts={T0445:es},as=e({T0446:()=>is,default:()=>ns}),is={title:"Differential Pricing",keywords:["Differential Pricing","Price Discrimination","Big Data Price Gouging"],aliases:["Big Data Price Gouging"],definition:"Differential pricing is a fraudulent practice where platforms use big data analysis to implement price discrimination against loyal customers, charging higher prices to existing customers for the same products or services.",description:"Differential pricing is an improper practice where platforms leverage user profiles and consumption habit data to implement differentiated pricing strategies for different users. Platforms conduct sophisticated analysis of users' order history to understand purchase patterns, payment capacity to gauge willingness to pay premium prices, brand loyalty to identify customers unlikely to switch competitors, and other behavioral signals to assess overall price sensitivity. Based on these insights, they display higher prices to price-insensitive users or those with high platform stickiness who are less likely to comparison shop, while simultaneously showing discounted prices to new users to attract them or to price-sensitive customers who actively seek deals. This behavior fundamentally violates the principle of good faith that should govern commercial transactions, directly infringes upon consumers' fair transaction rights guaranteed by law, and systematically undermines market trust mechanisms that are essential for healthy commerce. The E-Commerce Law and Consumer Rights Protection Law explicitly prohibit such price fraud practices, recognizing them as deceptive and harmful to consumer welfare. Regulatory authorities have increasingly penalized multiple high-profile cases of differential pricing as awareness of this exploitative practice has grown among consumers and policymakers.",usageExample:"This user discovered that the same product displayed a price 30% higher on their account compared to new users"},ns={T0446:is},rs=e({T0447:()=>ss,default:()=>os}),ss={title:"Social Engineering Database",keywords:["Social Engineering Database","Personal Info Database","Doxing Database"],aliases:["Doxing Database","Personal Info Lookup"],definition:"A social engineering database is an illegal database that stores and retrieves citizens' personal information, used to implement social engineering attacks and other cybercrime activities.",description:"Social engineering databases are massive collections of citizens' personal information obtained by cybercriminals through various illicit means including data breaches where hackers penetrate corporate or government systems, network attacks targeting vulnerable websites and services, insider theft by corrupt employees with access to sensitive databases, and other illegal acquisition methods. These raw data collections are then systematically organized, deduplicated to remove redundant entries, categorized by data type and completeness, and formed into searchable databases with query interfaces. The databases contain extensive sensitive information including full legal names, government-issued ID numbers, mobile phone numbers, residential and work addresses, bank card numbers and financial account details, social media accounts and associated profile information, passwords for various online services, and numerous other personal identifiers. Cybercriminals actively exploit these databases to conduct targeted fraud schemes with personalized scripts, account theft operations to take over valuable accounts, extortion and blackmail using exposed private information, and various other profit-driven criminal activities. The establishment, ongoing maintenance, commercial sale, and operational use of social engineering databases all constitute serious illegal criminal acts under data protection and cybercrime statutes, specifically violating Article 253-1 of the Criminal Law regarding infringement of citizens' personal information, with maximum penalties reaching seven years imprisonment.",usageExample:"This criminal gang obtained detailed victim information through social engineering databases to implement telecom fraud"},os={T0447:ss},ls=e({T0448:()=>cs,default:()=>ds}),cs={title:"Seed Phrase",keywords:["seed phrase","mnemonic phrase","mnemonic","recovery phrase","12-word phrase","24-word phrase","wallet recovery","private key backup","BIP39"],aliases:["Recovery Phrase","Mnemonic Phrase"],definition:"A sequence of words used to recover and backup cryptocurrency wallets, typically consisting of 12, 18, or 24 words, serving as a human-readable form of private keys.",description:"A seed phrase is a word sequence generated based on the BIP39 standard, allowing users to recover wallets by memorizing or physically backing up these words. Essentially an encoded form of private keys, anyone who obtains the seed phrase gains complete control over the corresponding cryptocurrency assets. Common seed phrase lengths are 12 or 24 words, selected from a predefined list of 2048 words. The security of a seed phrase directly relates to asset security; once leaked, it leads to asset theft. Users should store seed phrases offline in secure locations, avoiding screenshots, cloud storage, or network transmission. In blockchain security incidents, seed phrase leaks are a primary cause of user asset losses, with threat actors stealing them through phishing, malware, and social engineering.",usageExample:"When creating a new wallet, users receive a 12-word seed phrase that must be written down in order and securely stored to recover the wallet in case of device loss or damage.",references:[{title:"BIP39: Mnemonic code for generating deterministic keys"},{title:"Cryptocurrency Wallet Security Best Practices"}]},ds={T0448:cs},us=e({T0449:()=>hs,default:()=>ps}),hs={title:"Cold Wallet",keywords:["cold wallet","cold storage","hardware wallet","offline wallet","Ledger","Trezor","air-gapped wallet"],aliases:["Cold Storage","Offline Wallet"],definition:"A hardware device or physical medium that stores cryptocurrency private keys offline, providing the highest level of asset security protection through internet isolation.",description:"A cold wallet is a form of wallet that keeps private keys completely offline, primarily including hardware wallets and paper wallets. Hardware wallets like Ledger and Trezor store private keys in secure chips, and even when connected to computers for transaction signing, private keys remain unexposed to the network. The core advantage of cold wallets is isolating the attack surface from networks, preventing hackers from stealing private keys remotely. Suitable for users holding large amounts of cryptocurrency long-term. When using cold wallets, users generate and store private keys in offline environments, physically connecting devices for signing during transactions before broadcasting to the blockchain network. Compared to hot wallets, cold wallets sacrifice convenience for higher security, making them the preferred storage solution for institutions and high-net-worth users.",usageExample:"Exchanges store over 95% of user assets in cold wallets, keeping only small amounts in hot wallets for daily withdrawal needs.",references:[{title:"Hardware Wallet Best Practices"},{title:"Cold Wallet vs Hot Wallet Security Comparison"}]},ps={T0449:hs},ms=e({T0450:()=>gs,default:()=>fs}),gs={title:"Hot Wallet",keywords:["hot wallet","online wallet","software wallet","mobile wallet","web wallet","MetaMask","Trust Wallet","browser extension wallet"],aliases:["Online Wallet","Software Wallet"],definition:"An online cryptocurrency wallet that remains connected to the internet, with private keys stored on networked devices, enabling quick transaction operations.",description:"A hot wallet stores private keys on internet-connected devices such as smartphones, computers, or cloud services, including mobile app wallets, browser extension wallets, and exchange custodial wallets. The advantage of hot wallets lies in their convenience, allowing users to initiate transfers and trades anytime, suitable for daily small payments and frequent trading scenarios. However, since private keys are continuously exposed to network environments, hot wallets face higher security risks, vulnerable to phishing attacks, malware, and network hijacking. Threat actors commonly steal hot wallet private keys or seed phrases through fake wallet apps, phishing websites, and clipboard hijacking. To reduce risks, users should only store small amounts for daily use in hot wallets, transferring large assets to cold wallets. Additionally, users should choose reputable wallet service providers, enable multi-factor authentication, and regularly update software versions.",usageExample:"Users utilize the MetaMask browser extension wallet to interact with DeFi protocols, conveniently connecting to decentralized applications for staking, swapping, and other operations.",references:[{title:"Hot Wallet Security Usage Guide"},{title:"Cryptocurrency Wallet Security Threat Analysis"}]},fs={T0450:gs},ys=e({T0451:()=>bs,default:()=>ks}),bs={title:"Multi-Signature Wallet",keywords:["multisig","multi-signature","multi-sig wallet","M-of-N signature","joint signature","Gnosis Safe","threshold signature"],aliases:["Multisig Wallet","Joint Signature Wallet"],definition:"A cryptocurrency wallet requiring multiple private keys to jointly sign before completing transactions, enhancing fund security through distributed control.",description:"Multi-signature wallets employ an M-of-N signature mechanism, setting N authorized signers where at least M must agree to execute transactions. For example, a 2-of-3 multisig wallet requires at least 2 of 3 private key holders to sign for confirmation. This mechanism effectively prevents single points of failure and internal malfeasance, widely applied in corporate fund management, DAO governance, and exchange hot wallet protection. Multi-signature wallets are implemented through smart contracts or Bitcoin scripts, distributing fund control among multiple independent parties; even if one party's private key is lost or stolen, funds remain secure. In enterprise applications, CFO, CEO, and audit roles can jointly manage funds, requiring multi-party approval for any large transfers. The multisig mechanism also resists internal malfeasance, as single private key holders cannot independently transfer funds. Common multisig wallet solutions include Gnosis Safe and BitGo, which have become standard configurations for institutional-grade crypto asset management.",usageExample:"A DAO organization uses a 3-of-5 multisig wallet to manage community funds, requiring at least 3 of 5 core members to sign and approve any proposal expenditure before execution.",references:[{title:"Gnosis Safe: The most trusted platform to manage digital assets"},{title:"Multi-Signature Wallet Technical Principles and Best Practices"}]},ks={T0451:bs},ws=e({T0452:()=>vs,default:()=>As}),vs={title:"Smart Contract",keywords:["smart contract","Solidity","on-chain contract","DApp","decentralized application","blockchain contract","self-executing contract"],aliases:[],definition:"Self-executing program code deployed on blockchains that automatically triggers and executes transactions or operations based on preset conditions.",description:"Smart contracts are automated programs running on blockchain networks, with their code and execution results being completely transparent and immutable. Once deployed, contracts execute automatically according to written logic without human intervention. Widely applied in DeFi, NFT, DAO, and other decentralized application scenarios, though code vulnerabilities may lead to asset losses. Smart contracts eliminate intermediaries in traditional agreements, enabling trustless automated execution. Written in languages like Solidity and Vyper, they are deployed on platforms such as Ethereum and BNB Chain. Every contract interaction is recorded on-chain, ensuring traceability and transparency. However, smart contract security is crucial; vulnerabilities like reentrancy attacks, integer overflows, and logic errors have caused billions in losses. Major protocols undergo professional security audits and formal verification before launch. Smart contracts form the foundation of the Web3 ecosystem, enabling innovations like decentralized exchanges, lending protocols, and automated market makers.",usageExample:"A DeFi lending protocol uses smart contracts to automatically execute collateral deposits, loan distributions, interest calculations, and liquidations without requiring centralized platform operators.",references:[{title:"教程丨三分钟教你制作专属NFT智能合约|区块链|应用程序|源代码|元数 ...",link:"https://dy.163.com/article/GJANNOBQ0514832I.html"},{title:"开启新纪元: 隐私计算在金融领域应用发展报告2021(完整版)|数据源|...",link:"https://www.163.com/dy/article/GN95K1P805198086.html"},{title:"智能合约概述:挑战、进展和平台 - 简书",link:"https://www.jianshu.com/p/b5be22f3f3ff"}]},As={T0452:vs},Ts=e({T0453:()=>Bs,default:()=>Ss}),Bs={title:"Flash Loan",keywords:["flash loan","flash loan attack","uncollateralized loan","atomic transaction","DeFi exploit","Aave flash loan"],aliases:[],definition:"An instant blockchain borrowing mechanism without collateral requirements, demanding funds be borrowed and returned within the same transaction block, otherwise the transaction automatically reverts.",description:"Flash loans are a specialized lending method provided by DeFi protocols, allowing users to borrow large amounts without collateral, but requiring completion of the entire borrow-use-repay process within a single transaction. This mechanism is widely used for legitimate purposes like arbitrage and liquidations, but is also frequently exploited by attackers for price manipulation, reentrancy attacks, and other malicious activities. The atomic nature of blockchain transactions ensures that if repayment conditions aren't met, the entire transaction reverts, protecting lenders. Flash loans enable capital-efficient strategies previously impossible in traditional finance, such as instant arbitrage across multiple exchanges or collateral swaps. However, attackers leverage flash loans to manipulate oracle prices, drain liquidity pools, or exploit smart contract vulnerabilities. Notable attacks have resulted in tens of millions in losses. DeFi protocols implement defenses including price oracle decentralization, transaction slippage limits, and time-weighted average prices to mitigate flash loan attack risks.",usageExample:"An attacker borrows 100 million dollars via flash loan, manipulates a DEX price oracle through massive swaps, exploits the distorted price to drain a lending protocol, repays the loan, and profits from the difference—all within a single transaction.",references:[{title:"科普|无抵押借巨资的闪电贷是什么?缘何频频成为DeFi暴雷帮凶...",link:"https://new.qq.com/omn/20211229/20211229A049IH00.html"},{title:"金色观察丨一文带你读懂什么是闪电贷 - 知乎",link:"https://zhuanlan.zhihu.com/p/385431947"}]},Ss={T0453:Bs},Rs=e({T0454:()=>xs,default:()=>Cs}),xs={title:"DeFi",keywords:["DeFi","decentralized finance","on-chain finance","permissionless finance","yield farming","liquidity mining"],aliases:["Decentralized Finance"],definition:"A blockchain-based decentralized financial service system implementing lending, trading, wealth management, and other financial functions through smart contracts.",description:"DeFi eliminates intermediaries in traditional finance, enabling users to directly engage in asset trading, collateralized lending, and liquidity mining through smart contracts. All transaction records are publicly transparent and immutable, operating without centralized authorities. DeFi protocols offer services including decentralized exchanges (DEXs), lending platforms, stablecoins, derivatives, and insurance. Users maintain custody of their assets, accessing financial services permissionlessly through wallet connections. The Total Value Locked (TVL) in DeFi has reached hundreds of billions, demonstrating significant adoption. However, DeFi faces security risks including smart contract vulnerabilities, flash loan attacks, price manipulation, rug pulls, and oracle failures. The composability of DeFi protocols enables innovation but also creates systemic risks where vulnerabilities in one protocol can cascade across interconnected systems. Regulatory uncertainty and user experience challenges remain barriers to mainstream adoption.",usageExample:"A user deposits USDC into an Aave lending pool to earn interest, then uses the deposited assets as collateral to borrow ETH for leveraged trading—all executed through smart contracts without bank intermediaries.",references:[{title:"探索DeFi协议预言机实施的设计空间和挑战_腾讯新闻",link:"https://new.qq.com/rain/a/20240202A07N0A00"},{title:"教程丨三分钟教你制作专属NFT智能合约|区块链|应用程序|源代码|元数 ...",link:"https://dy.163.com/article/GJANNOBQ0514832I.html"}]},Cs={T0454:xs},Ms=e({T0455:()=>Ls,default:()=>Es}),Ls={title:"NFT",keywords:["NFT","non-fungible token","digital collectible","ERC-721","ERC-1155","digital art","tokenized asset"],aliases:["Non-Fungible Token"],definition:"Blockchain-based non-fungible tokens where each token has a unique identifier and ownership record, used to represent digital or physical assets.",description:"NFTs provide proof of uniqueness and ownership for digital assets through blockchain technology, widely applied in digital art, gaming items, virtual real estate, and more. Each NFT has unique metadata and a Token ID, making them non-interchangeable and indivisible, though they face risks including counterfeiting, theft, and copyright disputes. NFTs revolutionized digital ownership by enabling verifiable scarcity and provenance tracking. Implemented through standards like ERC-721 and ERC-1155 on Ethereum and other chains, NFTs have created new markets for creators and collectors. Major use cases include profile picture projects, generative art, metaverse assets, event tickets, and tokenized real-world assets. The NFT market experienced explosive growth with multi-million dollar sales, though also faces challenges including market volatility, wash trading, intellectual property infringement, and environmental concerns regarding energy consumption. Smart contract vulnerabilities and phishing attacks targeting NFT holders remain ongoing security concerns.",usageExample:"A digital artist mints their artwork as an NFT on Ethereum, selling it through OpenSea marketplace where blockchain records permanently verify authenticity and ownership, with royalties automatically paid to the creator on secondary sales.",references:[{title:"区块链法律研究系列——浅析NFT概念、交易模式及其法律风险|区块链...",link:"https://www.163.com/dy/article/HAS1AA3E0534BL67.html"},{title:"科技巨头纷纷布局NFT,万物皆可NFT的时代来临?|区块链|马云|推特|苏群...",link:"https://dy.163.com/article/GFFFG6CP0552D26Z.html"}]},Es={T0455:Ls},zs=e({T0456:()=>Ds,default:()=>Is}),Ds={title:"Data Broker",keywords:["Data Broker","data dealer","PII seller","underground data trade","credential merchant","leaked data vendor"],aliases:["Liaoshang"],definition:"Underground vendors who specialize in trading stolen personal information, credentials, and user databases acquired through hacking, data breaches, or insider threats.",description:"Data brokers operate in the cybercrime underground economy, acting as middlemen between data thieves and fraudsters. They aggregate vast quantities of personally identifiable information (PII) including phone numbers, ID cards, bank accounts, and login credentials obtained from data breaches, phishing campaigns, or corrupt insiders. These vendors categorize data by freshness, completeness, and industry sector, selling them through private channels, dark web marketplaces, or encrypted messaging groups. Pricing varies based on data quality and verification status. Data brokers enable downstream fraud operations including account takeovers, identity theft, precision phishing, and credential stuffing attacks. Their services are foundational to the fraud ecosystem, providing the raw material that powers various illicit schemes.",usageExample:"Fraudsters purchased 100,000 verified phone numbers from a data broker to conduct SMS phishing campaigns targeting online banking users.",references:[{title:"40倍杠杆锁价、场外期货“对赌”,黄金料商却在金价新高时悄悄消失了|...",link:"https://www.163.com/dy/article/K9M68T6C0519DDQ2.html"},{title:"化妆品行业专题报告:国产原料兴起,助力本土美妆升级_腾讯新闻",link:"https://new.qq.com/rain/a/20230601A01MD500"},{title:"面料采购常见问题与解决方案? - 知乎",link:"https://zhuanlan.zhihu.com/p/449164483"}]},Is={T0456:Ds},Fs=e({T0457:()=>Ps,default:()=>qs}),Ps={title:"Card Dealer",keywords:["Card Dealer","payment card vendor","bank card seller","virtual card provider","prepaid card merchant","carded account seller"],aliases:["Kashang"],definition:"Underground vendors who provide stolen payment cards, compromised bank accounts, virtual cards, or anonymous prepaid cards used for fraudulent transactions and money laundering operations.",description:"Card dealers are key suppliers in the fraud economy, offering multiple card-related services. They sell stolen credit/debit card information (fullz) obtained from skimmers, malware, or dark web breaches, complete with CVV codes and cardholder data. They also provide registered bank accounts with verified identities for money mule operations, virtual prepaid cards that bypass KYC requirements, and anonymous payment instruments for illegal marketplaces. Card dealers often guarantee card validity through replacement policies and offer testing services before bulk purchases. Their inventory is categorized by issuing country, bank, card type, balance range, and verification status. These services enable payment fraud, money laundering, carding operations, and circumvention of financial controls.",usageExample:"A fraud ring purchased 50 virtual cards from a card dealer to register merchant accounts on multiple e-commerce platforms for refund scams.",references:[{title:"注册卡商,注册卡商平台_客户_服务_需求",link:"https://m.sohu.com/sa/809848247_121753462"},{title:"全球支付的未来?万字解析Web3支付赛道_腾讯新闻",link:"https://news.qq.com/rain/a/20240710A05LXK00"},{title:"卡商,移动电信联通卡商干什么用?还有猫池有哪些利益链? - 知乎",link:"https://www.zhihu.com/question/41642313/answer/97925667"}]},qs={T0457:Ps},Hs=e({T0458:()=>Us,default:()=>Os}),Us={title:"SMS Reception Platform",keywords:["SMS Reception Platform","online SMS receiver","virtual phone service","OTP reception service","temporary number provider","verification bypass tool"],aliases:["Jiema Platform"],definition:"Online services that provide temporary virtual phone numbers for receiving SMS verification codes, enabling fraudsters to bypass phone-based authentication and register mass accounts anonymously.",description:"SMS reception platforms operate as commercial services offering temporary or disposable phone numbers that can receive SMS messages online without requiring physical SIM cards. These platforms maintain pools of real phone numbers from various countries and carriers, accessible through web interfaces or APIs. Users pay per message or through subscription models to receive verification codes for account registration, enabling mass account creation while circumventing anti-fraud phone verification systems. Advanced platforms offer dedicated numbers, number selection by region, and immediate message delivery. These services are heavily utilized in account farming operations, bonus abuse schemes, and review manipulation campaigns where operators need hundreds or thousands of verified accounts. While some legitimate uses exist for privacy protection, the overwhelming adoption by fraud actors has made these platforms a critical infrastructure for automated abuse.",usageExample:"A scalper group used an SMS reception platform to register 5,000 e-commerce accounts within hours to exploit a limited-time promotional offer.",references:[{title:"【依法守“复”】《明码标价和禁止价格欺诈规定》解读|价格法|标价...",link:"https://www.163.com/dy/article/H9C40P960534128J.html"},{title:"揭秘网络黑产—接码平台",link:"https://paper.dzwww.com/sdfzb/data/20210928/7/pdf/202109283.pdf"}]},Os={T0458:Us},js=e({T0459:()=>Ns,default:()=>_s}),Ns={title:"SIM Box",keywords:["SIM Box","GoIP Gateway","SIM bank","GSM gateway","multi-SIM device","SMS farm hardware"],aliases:["Maochi"],definition:"Hardware devices that host dozens to hundreds of SIM cards simultaneously, enabling automated SMS reception, voice calls, and mobile network operations for fraud, spam, or telecom bypass purposes.",description:"SIM boxes are specialized hardware devices designed to manage large quantities of SIM cards in a centralized system, often connected to computers for automated control. These devices range from small 8-port units to industrial racks holding 128+ cards, featuring remote management interfaces and API integration. Originally used for legitimate VoIP termination, SIM boxes are now predominantly employed by fraud operations for receiving verification codes at scale, bypassing SMS rate limits, distributing spam messages across multiple numbers, and rotating phone numbers to evade detection. Advanced setups include automatic SIM rotation, geographic distribution to avoid carrier detection, and integration with device farms for complete account creation workflows. Telecom operators actively combat SIM box operations as they facilitate fraud and result in revenue loss from bypass traffic.",usageExample:"Authorities seized a SIM box containing 256 active SIM cards used by fraudsters to register accounts on social media platforms for spreading phishing links.",references:[{title:"铲屎官为伺候喵星主子开发了新利器 你们感受下-国际在线",link:"https://news.cri.cn/20160518/ad4d6d3c-e677-fc88-a72f-1a3f9604c156.html"},{title:"“猫池”有毒!四人非法售卖验证码被抓",link:"https://m.gmw.cn/2023-10/25/content_1303549640.htm"}]},_s={T0459:Ns},Gs=e({T0460:()=>Qs,default:()=>Ws}),Qs={title:"Four-piece Set",keywords:["Four-piece Set","identity package","full ID kit","KYC bypass bundle","complete identity set","bank account package"],aliases:["Sijiantao"],definition:"A complete identity fraud package containing four essential items: ID card, bank card, phone SIM card, and mobile device, used to create untraceable accounts for money laundering or fraud.",description:"The four-piece set represents a complete criminal identity toolkit enabling fraudsters to register fully verified accounts that pass KYC checks while remaining untraceable to the actual operator. This package typically includes a real or forged ID card with matching name and photo, a bank card or account registered under that identity, a phone SIM card with a matching registered number, and often a mobile device or device fingerprint tied to that identity. These sets are assembled through identity theft, purchase from willing sellers in vulnerable populations, or document forgery operations. They enable money mule operations where fraudsters need authentic-looking accounts to receive stolen funds, launder money through multiple transfers, or conduct high-value fraud without personal exposure. The term reflects the minimum viable identity infrastructure needed to operate in regulated financial systems. Law enforcement agencies actively track four-piece set distribution networks as they represent a critical enabler for organized financial crime.",usageExample:"A money laundering operation purchased 20 four-piece sets to establish transfer accounts that received funds from telecom fraud victims before dispersing them internationally.",references:[{title:"四件套包括什么_装修全知道_学堂_齐家网",link:"https://zixun.jia.com/article/1112668.html"}]},Ws={T0460:Qs},Vs=e({T0461:()=>Ks,default:()=>Js}),Ks={title:"CAPTCHA Solving Service",keywords:["CAPTCHA Solving Service","CAPTCHA bypass","human verification farm","OCR solving service","anti-bot circumvention","verification code breaking"],aliases:["Dama Platform"],definition:"Commercial services that provide automated or human-powered solutions to bypass CAPTCHA challenges, enabling bots and scrapers to circumvent anti-automation protections on websites and applications.",description:"CAPTCHA solving services operate as intermediary platforms connecting clients who need CAPTCHAs solved with either AI-powered OCR systems or crowdsourced human workers in low-wage regions. These services offer APIs that seamlessly integrate into automation scripts, accepting CAPTCHA images and returning solved text within seconds. Advanced platforms support multiple CAPTCHA types including text recognition, reCAPTCHA v2/v3, hCaptcha, image classification challenges, and slider puzzles. Pricing is typically per-solve with volume discounts, ranging from $0.50 to $3 per 1,000 solves. While marketed as tools for testing and accessibility, these services are predominantly used by scalpers, account farmers, credential stuffers, and web scrapers to defeat security controls. The existence of these services creates an asymmetry where defense mechanisms are systematically bypassed through economic outsourcing.",usageExample:"A ticket scalping operation integrated a CAPTCHA solving API to automatically purchase concert tickets within seconds of release, bypassing anti-bot protections.",references:[{title:"西山居靠着满屏的马赛克,重新定义了二次元_腾讯新闻",link:"https://new.qq.com/rain/a/20240712A0982C00"},{title:"事儿: 这家同性恋色情片公司彻底改变了毛片的定义|163_手机网易网",link:"https://m.163.com/dy/article/C06PI8MH05308025.html"},{title:"【Python爬虫--scrapy+selenium框架】超详细的Python爬虫scrapy+selenium...",link:"https://blog.csdn.net/m0_67844671/article/details/139361507"}]},Js={T0461:Ks},Xs=e({T0462:()=>Ys,default:()=>Zs}),Ys={title:"Pig Butchering Scam",keywords:["Pig Butchering Scam","romance investment fraud","crypto romance scam","long-con investment fraud","relationship-based fraud","fattening before slaughter"],aliases:["Shazhuipan"],definition:"A sophisticated long-term fraud scheme where scammers build romantic or friendship relationships with victims over weeks or months before convincing them to invest in fake cryptocurrency or investment platforms.",description:"Pig butchering scams represent an evolution of romance scams combined with investment fraud, named after the practice of fattening a pig before slaughter. Scammers initiate contact through dating apps, social media, or wrong number messages, then invest weeks or months building trust and emotional connection with victims. Once rapport is established, scammers gradually introduce investment opportunities, typically fake cryptocurrency trading platforms or foreign exchange schemes. Victims are initially allowed to withdraw small profits to build confidence, then encouraged to invest larger sums. When victims attempt to withdraw substantial amounts, they encounter fabricated fees, taxes, or account freezes. Scammers often operate from organized compounds in Southeast Asia where trafficked workers are forced to execute these schemes under coercion. The combination of emotional manipulation and fake financial gains makes these scams devastatingly effective, with individual losses often exceeding hundreds of thousands of dollars.",usageExample:"A victim lost $450,000 in a pig butchering scam after a months-long online relationship led them to invest life savings into a fake cryptocurrency platform that showed fabricated returns.",references:[{title:"什么是杀猪盘?|电信诈骗|骗子|骗局_手机网易网",link:"https://m.163.com/dy/article/H2K05NLP0552AU0G.html"},{title:"什么是“杀猪盘”,你了解吗?",link:"https://mp.weixin.qq.com/s?__biz=MzIwMTM3MTc3Mg==&mid=2651529425&idx=1&sn=ec637dec1c70f5c120ab460c0be5ca51&chksm=8d1179c2ba66f0d47946aaada2ef190428bc91aa5f585018fe970e50b9f5f868f93dc29c0b44&scene=27"}]},Zs={T0462:Ys},$s=e({T0463:()=>eo,default:()=>to}),eo={title:"Money Mule Service",keywords:["Money Mule Service","payment running","transaction relay","fund transfer service","laundering relay","scoring service"],aliases:["Paofen"],definition:"A money laundering scheme where individuals use personal payment accounts to receive and quickly transfer illicit funds for criminals, earning commissions while obscuring the money trail for law enforcement.",description:"Money mule services operate as intermediary laundering infrastructure where recruited individuals or compromised accounts serve as transfer nodes for stolen funds. Criminals send illicit money from fraud, gambling, or other illegal sources to mule accounts, which then rapidly disperse the funds through multiple channels including cryptocurrency exchanges, overseas transfers, or cash withdrawals. Mules typically earn 1-10% commission on transferred amounts. Recruitment targets include students, unemployed individuals, or financially desperate people lured by promises of easy income, often unaware they're committing crimes. Organized operations use four-piece identity sets to scale up with anonymous accounts. This practice enables criminals to break the direct connection between victims and final recipients, creating complex transaction chains that complicate investigation and asset recovery. Financial institutions actively monitor for mule behavior patterns including rapid in-and-out transfers, unusual transaction volumes, and connections to known fraud networks.",usageExample:"A college student recruited through social media earned $5,000 monthly as a money mule, transferring over $2 million in telecom fraud proceeds before being arrested for money laundering.",references:[{title:"科技早报:Redmi Turbo 3跑分超175万|谷歌AI竞赛失利|微星为中国推出新...",link:"https://www.163.com/dy/article/IV8GLGN2051189P5.html"},{title:"一场“去参数化”的发布会,用AI定义汽车的AIVA凭什么让人记住...",link:"https://view.inews.qq.com/a/20260610A0749O00"},{title:"系统级芯片(SoC)的复杂设计选择(二) - 简书",link:"https://www.jianshu.com/p/b38bf97ada18"}]},to={T0463:eo},ao=e({T0464:()=>io,default:()=>no}),io={title:"Money Laundering",keywords:["Money Laundering","proceeds concealment","illegal fund integration","dirty money cleaning","financial crime concealment","illicit fund legitimization"],aliases:["Xiqian"],definition:"The criminal process of disguising the origins of illegally obtained money by passing it through complex transfers and transactions to make it appear legitimate and difficult to trace.",description:"Money laundering is a systematic process typically divided into three stages: placement (introducing illegal funds into the financial system), layering (executing complex transactions to obscure the money trail), and integration (returning laundered funds to criminals in seemingly legitimate form). Modern laundering operations utilize diverse channels including shell companies, cryptocurrency mixing services, trade-based laundering, real estate purchases, online gambling platforms, and cross-border transfers through jurisdictions with weak oversight. Digital currencies and decentralized finance platforms have introduced new laundering vectors that exploit regulatory gaps and pseudonymity. Criminals employ money mules, nested service providers, and professional laundering networks to maximize distance between illicit sources and final destinations. Financial institutions implement Anti-Money Laundering (AML) programs using transaction monitoring, Know Your Customer (KYC) procedures, and suspicious activity reporting to detect and prevent laundering operations.",usageExample:"An organized crime group laundered $50 million in drug proceeds by purchasing cryptocurrency, transferring through multiple mixers, converting to stablecoins, and investing in overseas real estate through shell companies.",references:[{title:"什么是洗钱?",link:"https://xining.pbc.gov.cn/xining/118296/118312/3153247/index.html"},{title:"什么是洗钱罪?_中国人大网",link:"http://www.npc.gov.cn/zgrdw/npc/flsyywd/flwd/2002-04/19/content_293387.htm"}]},no={T0464:io},ro=e({T0465:()=>so,default:()=>oo}),so={title:"Telecom Fraud",keywords:["Telecom Fraud","phone scam","voice phishing","impersonation scam","SMS fraud","caller ID spoofing"],aliases:["Dianxin Zhapian"],definition:"Criminal schemes that use telephone, SMS, or internet communication to deceive victims into transferring money or revealing sensitive information by impersonating authorities, institutions, or trusted contacts.",description:"Telecom fraud encompasses a wide range of scam methodologies that exploit communication technologies to reach and manipulate victims at scale. Common schemes include impersonating law enforcement or government officials claiming legal issues, posing as banks reporting security problems, pretending to be kidnapped relatives demanding ransom, offering fake investment opportunities, and conducting tech support scams. Sophisticated operations use caller ID spoofing to display legitimate-looking numbers, employ psychological manipulation tactics to create urgency and fear, and utilize prepared scripts optimized through A/B testing. Modern telecom fraud operations are highly organized, often operating from overseas compounds with segmented teams handling lead generation, social engineering, money mule coordination, and technical infrastructure. They leverage data broker information for precision targeting, use VoIP systems to obscure locations, and employ money laundering networks to extract proceeds. Governments combat these operations through international cooperation, real-time call blocking systems, and public awareness campaigns.",usageExample:"A victim transferred $200,000 to fraudsters after receiving a spoofed call from someone claiming to be a prosecutor investigating the victim for money laundering, demanding immediate fund transfer to a 'safe account' for verification.",references:[{title:"关于办理电信网络诈骗等刑事案件适用法律若干问题的意见(全文)_中华人民共和国...",link:"https://www.spp.gov.cn/zdgz/201612/t20161221_176278.shtml"},{title:"公安部公布十大高发电信网络诈骗类型--公安部网站",link:"https://www.mps.gov.cn/n2255079/n4876594/n5104076/n5104077/c9077908/content.html"}]},oo={T0465:so},lo=e({T0466:()=>co,default:()=>uo}),co={title:"Online Gambling",keywords:["Online Gambling","illegal betting","offshore casino","unlicensed gaming","rigged gambling platform","underground lottery"],aliases:["Bocai"],definition:"Illegal or unlicensed online gaming operations that offer betting, casino games, or lottery services, often rigged against players and serving as vehicles for money laundering and fraud.",description:"Illegal online gambling operations typically operate from jurisdictions with lax enforcement while targeting users in countries where gambling is restricted or heavily regulated. These platforms offer sports betting, casino games, lottery, and increasingly cryptocurrency-based gambling without proper licensing, player protection, or fair gaming oversight. Many operations employ rigged algorithms that guarantee house advantages beyond statistical norms, manipulate odds dynamically based on player profiles, or simply refuse large withdrawals. These platforms serve multiple criminal purposes: extracting money from addicted players, laundering proceeds from other crimes through fabricated gambling transactions, and collecting user financial information for subsequent fraud. Promotion relies on affiliate networks, social media advertising, and influencer partnerships that often violate platform policies. Players face not only unfair games but also risks of identity theft, credit card fraud, and inability to recover winnings. Regulators combat these operations through domain blocking, payment processor restrictions, and international enforcement cooperation.",usageExample:"An illegal gambling platform operating from offshore servers defrauded users of $30 million before authorities blocked access, with many players unable to withdraw their winnings due to fabricated verification requirements.",references:[{title:"私彩不是“彩票”,是赌博;不是“生意”,是犯罪|洗钱|违法_网易订阅",link:"https://www.163.com/dy/article/KPC6CLPD0550B6IS.html"},{title:"往事如烟||大宋时期开封的博彩业 - 知乎",link:"https://zhuanlan.zhihu.com/p/614920673"}]},uo={T0466:co},ho=e({T0467:()=>po,default:()=>mo}),po={title:"Private Server",keywords:["Private Server","unauthorized game server","pirate server","unofficial game server","emulated MMO server","copyright-infringing server"],aliases:["Sifu"],definition:"Unauthorized game servers that reverse-engineer and host commercial online games without permission, often with modified game mechanics, accelerated progression, or monetization schemes that compete with official servers.",description:"Private servers are unauthorized implementations of online games that operate independently from official publishers by reverse-engineering server protocols, emulating game logic, and hosting modified versions of games. These operations typically emerge for popular MMORPGs, mobile games, or service-based titles. Private server operators often modify game parameters to attract players: dramatically increased experience rates, free distribution of premium currency, custom content, or pay-to-win mechanics that generate revenue through alternative monetization. While some serve preservation purposes for discontinued games or cater to players seeking different gameplay experiences, most constitute copyright infringement and trademark violations that harm developers' business models. Private servers pose security risks as they may collect user credentials potentially reused on official servers, inject malware, or harvest payment information. Publishers combat private servers through legal action, technical protection measures, and community engagement, though enforcement is challenging when operators host in jurisdictions with weak IP protection.",usageExample:"A private server for a popular MMORPG attracted 50,000 players by offering 10x experience rates and free premium items, generating revenue through pay-to-win enhancements before being shut down through legal action.",references:[{title:"私服魔兽世界-制造不再复杂:“至暗之夜”重新定义手艺人的价值|暴雪...",link:"https://www.163.com/dy/article/KJ5G61HA0556JJLK.html"},{title:"人精虞书欣,重新定义了女明星的最高标准_腾讯新闻",link:"https://new.qq.com/rain/a/20240723A08U6U00"}]},mo={T0467:po},go=e({T0468:()=>fo,default:()=>yo}),fo={title:"Social Engineering",keywords:["Social Engineering","psychological manipulation","human hacking","pretexting","trust exploitation","manipulation attack"],aliases:["Shehui Gongcheng"],definition:"The practice of manipulating individuals through psychological tactics to divulge confidential information, grant unauthorized access, or perform actions that compromise security, bypassing technical controls by exploiting human psychology.",description:"Social engineering represents a class of attack vectors that target human decision-making rather than technical vulnerabilities. Attackers exploit psychological principles including authority bias, urgency, fear, curiosity, reciprocity, and trust to manipulate targets into compromising security. Common techniques include phishing emails impersonating trusted entities, pretexting scenarios that establish false contexts for information requests, baiting schemes that promise rewards for risky actions, tailgating to gain physical access, and impersonation of IT support or executives to extract credentials. Advanced operations conduct reconnaissance through social media and public records to craft convincing pretexts, use multiple communication channels to reinforce legitimacy, and establish long-term rapport before making requests. Social engineering attacks succeed because they exploit universal human cognitive biases that persist regardless of technical security measures. Defense requires security awareness training, verification procedures for sensitive requests, incident reporting channels, and organizational cultures that encourage questioning suspicious interactions without fear of repercussions.",usageExample:"An attacker called an employee impersonating IT support, created urgency by claiming a security incident required immediate password reset, and successfully obtained credentials that provided access to corporate systems.",references:[{title:"译文| 详解社会工程学:犯罪分子如何利用人类行为|黑客_网易订阅",link:"https://www.163.com/dy/article/GKHSJNIP0511DM95.html"},{title:"杜金:自由主义2.0_腾讯新闻",link:"https://new.qq.com/omn/20210506/20210506A011X400.html"},{title:"什么是 IP 地址 – 定义和解释 - 知乎",link:"https://zhuanlan.zhihu.com/p/418179348"}]},yo={T0468:fo},bo=e({T0469:()=>ko,default:()=>wo}),ko={title:"Traffic Hijacking",keywords:["Traffic Hijacking","network interception","man-in-the-middle","session hijacking","BGP hijacking","HTTP redirection"],aliases:["Liuliang Jiechi"],definition:"The unauthorized interception and redirection of network traffic between users and legitimate destinations, enabling attackers to steal data, inject malicious content, or redirect users to fraudulent sites.",description:"Traffic hijacking encompasses multiple attack vectors that intercept communications between clients and servers. Network-level hijacking exploits vulnerabilities in routing protocols like BGP to redirect traffic at the ISP or backbone level, while local attacks compromise routers, DNS servers, or wireless networks to intercept traffic within specific networks. Proxy-based hijacking installs malicious software that forces all network traffic through attacker-controlled servers. HTTP hijacking injects advertisements, malware, or phishing content into unencrypted web traffic, commonly executed by compromised ISPs or public Wi-Fi operators. Session hijacking steals authentication cookies or tokens to impersonate legitimate users. These attacks enable credential theft, financial fraud, malware distribution, surveillance, and censorship. HTTPS encryption protects against many hijacking vectors but remains vulnerable to certificate authority compromise, downgrade attacks, or user acceptance of invalid certificates. Defense measures include HTTPS enforcement, DNSSEC implementation, VPN usage, certificate pinning, and network monitoring for anomalous routing.",usageExample:"Attackers hijacked BGP routes for a cryptocurrency exchange, redirecting traffic to a phishing clone for two hours and stealing login credentials from over 300 users attempting to access their accounts.",references:[{title:"流量劫持判几年?DNS域名劫持、网页跳转、弹窗广告犯罪判几年 ?|反...",link:"https://www.163.com/dy/article/H4CE5N670541BQVC.html"},{title:"前DeepSeek骨干罗福莉官宣加入小米/iPhone霸榜双11手机销量前三/...",link:"https://new.qq.com/rain/a/20251113A019ET00"},{title:"广告流量反作弊风控中的模型应用 - 简书",link:"https://www.jianshu.com/p/e6888e9efe5c"}]},wo={T0469:ko},vo=e({T0470:()=>Ao,default:()=>To}),Ao={title:"DNS Hijacking",keywords:["DNS Hijacking","DNS poisoning","DNS cache poisoning","DNS redirection","pharming","DNS spoofing"],aliases:["DNS Jiechi"],definition:"An attack that manipulates DNS resolution processes to redirect users from legitimate domains to attacker-controlled IP addresses, enabling phishing, malware distribution, or surveillance without user awareness.",description:"DNS hijacking operates by corrupting the domain name resolution mechanism that translates human-readable domains into IP addresses. Attackers employ various techniques: compromising routers or DNS servers to modify resolution tables, poisoning DNS caches with false records that persist and spread to other servers, exploiting vulnerabilities in DNS protocols to inject malicious responses, or conducting man-in-the-middle attacks that intercept and alter DNS queries. Router-level hijacking through compromised home or enterprise routers affects all devices on the network, while ISP-level hijacking can impact thousands of users simultaneously. Malware-based hijacking modifies local host files or DNS settings on individual devices. Once DNS is hijacked, users typing legitimate URLs are transparently redirected to attacker-controlled sites that may harvest credentials, distribute malware, or serve fraudulent content while appearing authentic. DNSSEC (Domain Name System Security Extensions) provides cryptographic verification of DNS responses, preventing many hijacking techniques. Defense strategies include DNSSEC adoption, monitoring DNS infrastructure for tampering, using trusted DNS resolvers, and browser security features that detect domain mismatches.",usageExample:"A DNS hijacking attack compromised residential routers, redirecting banking domain queries to phishing sites that collected login credentials from thousands of users who believed they were accessing legitimate bank websites.",references:[{title:"DNS劫持_360百科",link:"https://upimg.baike.so.com/doc/5394872-5632022.html"},{title:"什么是DNS劫持(非常详细),零基础入门网络安全,看这一篇就够了-CSDN博...",link:"https://blog.csdn.net/SpringJavaMyBatis/article/details/143905018"},{title:"什么是 DNS 劫持?如何检测与预防 - 知乎",link:"https://zhuanlan.zhihu.com/p/637366489"}]},To={T0470:Ao},Bo=e({T0471:()=>So,default:()=>Ro}),So={title:"Phishing",keywords:["Phishing","credential harvesting","spear phishing","email spoofing","fake login page","impersonation attack"],aliases:["Diayu"],definition:"A deceptive attack technique where fraudsters impersonate trusted entities through email, SMS, or websites to trick victims into revealing credentials, financial information, or downloading malware.",description:"Phishing represents one of the most prevalent and effective attack vectors in cybercrime, exploiting human trust rather than technical vulnerabilities. Generic phishing campaigns cast wide nets with mass emails impersonating banks, delivery services, or popular platforms, leading victims to fake login pages that harvest credentials. Spear phishing targets specific individuals or organizations using personalized information from reconnaissance, increasing credibility and success rates. Whaling attacks target executives with high-value access. Smishing (SMS phishing) and vishing (voice phishing) extend these techniques to text messages and phone calls. Modern phishing operations employ sophisticated infrastructure including lookalike domains, SSL certificates for fake sites, email spoofing that bypasses SPF/DKIM checks, and hosting on compromised legitimate servers to evade blocklists. Attackers increasingly use legitimate services like cloud storage sharing or calendar invites to bypass security filters. Defense requires multi-layered approaches: technical controls including email authentication, URL filtering, and sandboxing; user education on identifying suspicious indicators; multi-factor authentication to mitigate credential compromise; and incident response procedures for rapid containment.",usageExample:"A spear phishing campaign targeted finance employees with emails mimicking the CFO's communication style, instructing urgent wire transfers that resulted in $3.2 million stolen before the fraud was detected.",references:[{title:"【钓鱼技巧】笨重的铅头钩,钓不了轻口鱼?不,朝天钩冬钓更高效|冬...",link:"https://dy.163.com/article/FT8DMORE0517EQE6.html"},{title:"男子陪师傅钓鱼却设局强奸师娘后求保密,师娘:你对得起师傅吗?|...",link:"https://m.163.com/dy/article/H3CI5P7A0552LUWF.html"},{title:"终身成长:重新定义成功的思维模式 - 简书",link:"https://www.jianshu.com/p/e268cc7cdbe1"}]},Ro={T0471:So},xo=e({T0472:()=>Co,default:()=>Mo}),Co={title:"Man-in-the-Middle Attack",keywords:["Man-in-the-Middle Attack","MITM","session interception","eavesdropping attack","proxy attack","network interception"],aliases:["Zhongjianren Gongji"],definition:"A cyberattack where an adversary secretly intercepts and potentially alters communications between two parties who believe they are directly communicating, enabling data theft, credential capture, or message manipulation.",description:"Man-in-the-middle (MITM) attacks position an attacker between a client and server, intercepting all traffic that passes between them. Common implementation methods include ARP spoofing on local networks to redirect traffic through the attacker's device, rogue Wi-Fi access points that impersonate legitimate networks, SSL stripping that downgrades HTTPS connections to unencrypted HTTP, and DNS hijacking that redirects connections to attacker-controlled proxies. Advanced attacks exploit vulnerabilities in TLS/SSL implementations, compromise certificate authorities to issue fraudulent certificates, or use social engineering to install proxy certificates on victim devices. MITM attacks enable real-time credential theft, session hijacking, injection of malicious content into legitimate communications, surveillance of sensitive data, and manipulation of transactions. Public Wi-Fi networks present high MITM risk due to lack of encryption between clients and access points. Defense strategies include mandatory HTTPS with certificate pinning, VPN usage on untrusted networks, certificate transparency monitoring, mutual authentication protocols, and network monitoring for suspicious proxy or routing behavior.",usageExample:"An attacker operated a rogue Wi-Fi hotspot named 'Airport_Free_WiFi' that performed MITM attacks on connected users, capturing passwords and credit card numbers from unencrypted connections and HTTP traffic.",references:[{title:"【网络安全】——中间人攻击-CSDN博客",link:"https://blog.csdn.net/ewii12567/article/details/140102109"}]},Mo={T0472:Co},Lo=e({T0473:()=>Eo,default:()=>zo}),Eo={title:"Deepfake",keywords:["Deepfake","synthetic media","AI-generated impersonation","face swap","voice cloning","neural network manipulation"],aliases:["Shendu Weizao"],definition:"AI-generated synthetic media that convincingly replaces or manipulates a person's appearance, voice, or actions in videos, images, or audio, enabling sophisticated impersonation and misinformation.",description:"Deepfake technology leverages deep learning models, particularly generative adversarial networks (GANs) and diffusion models, to create highly realistic but fabricated media. Face-swapping deepfakes replace one person's face with another in video footage, voice cloning replicates speech patterns and timbre from small audio samples, and full-body synthesis generates entirely artificial personas. Initially requiring significant technical expertise, deepfake creation has become accessible through user-friendly applications and online services. Malicious applications include financial fraud through impersonating executives in video calls to authorize fraudulent transfers, creating non-consensual pornography, spreading political disinformation, manipulating evidence, and conducting sophisticated social engineering attacks. Detection techniques analyze inconsistencies in facial movements, lighting, audio-visual synchronization, and artifacts introduced by generation algorithms, but the arms race between creation and detection continues to escalate. Watermarking, blockchain provenance tracking, and multi-factor authentication for high-stakes communications serve as mitigation strategies.",usageExample:"Fraudsters used deepfake video technology to impersonate a company CEO in a video conference call, convincing a finance manager to transfer $35 million to an attacker-controlled account.",references:[{title:"刘宪权:人工智能时代深度伪造行为的刑法规制 | 政治与法律202511|...",link:"https://www.163.com/dy/article/KDTR0FTO0530W1MT.html"},{title:"01 生成式人工智能背景下提升学生批判性思维素养:深度伪造内容...",link:"https://www.jianshu.com/p/ed9316cb5b5d"}]},zo={T0473:Eo},Do=e({T0474:()=>Io,default:()=>Fo}),Io={title:"Web Scraper",keywords:["Web Scraper","data extraction bot","web crawler","content harvesting","automated data collection","spider bot"],aliases:["Pachong"],definition:"Automated software programs that systematically extract data from websites by parsing HTML, executing JavaScript, and navigating pages to collect content, prices, or user information at scale.",description:"Web scrapers range from simple scripts parsing static HTML to sophisticated browser automation frameworks that execute JavaScript, solve CAPTCHAs, and mimic human behavior to evade detection. Legitimate use cases include search engine indexing, price comparison services, academic research, and business intelligence. However, malicious scrapers harvest personal data for spam lists, steal copyrighted content, enable competitive price undercutting, extract proprietary business data, and overwhelm servers with excessive requests. Advanced scrapers employ residential proxy networks to distribute requests across genuine IP addresses, implement randomized delays and request patterns to avoid rate limiting, use headless browsers for JavaScript-heavy sites, and integrate CAPTCHA solving services. Website operators defend through rate limiting, IP blocking, CAPTCHA challenges, honeypot traps, fingerprinting, and legal enforcement under terms of service or computer fraud statutes. The ethical and legal boundaries of scraping remain contested, particularly regarding publicly accessible but copyrighted content.",usageExample:"An e-commerce competitor deployed scrapers to extract real-time pricing data from thousands of product pages daily, enabling them to systematically undercut prices by minimal margins.",references:[{title:"专业文章丨从数据合规角度论爬虫技术应用合规边界|爬取|服务器|搜索...",link:"https://www.163.com/dy/article/I47KBH2E0538RIAP.html"},{title:"什么是Python爬虫?一篇文章带你彻底搞懂爬虫!!!-CSDN博客",link:"https://blog.csdn.net/Candyz7/article/details/139738552"},{title:"爬虫:互联网背后的“隐形抓手”,程序员都该懂! - 知乎",link:"https://zhuanlan.zhihu.com/p/16731422344"}]},Fo={T0474:Io},Po=e({T0475:()=>qo,default:()=>Ho}),qo={title:"SQL Injection",keywords:["SQL Injection","SQLi","database injection","query manipulation","blind SQL injection","union-based injection"],aliases:["SQL Zhuru"],definition:"A code injection technique that exploits vulnerabilities in database queries by inserting malicious SQL statements through user inputs, enabling unauthorized data access, modification, or deletion.",description:"SQL injection attacks occur when applications fail to properly sanitize user inputs that are incorporated into SQL queries, allowing attackers to manipulate query logic. Classic injection techniques insert SQL syntax through input fields, URL parameters, or HTTP headers that break out of intended query structure. Union-based injection uses UNION operators to retrieve data from additional tables, error-based injection triggers database errors that reveal structure information, blind injection infers data through boolean logic or timing delays, and stacked queries execute multiple commands in succession. Successful exploitation enables complete database compromise: extracting sensitive user data, credentials, and business information; modifying or deleting records; bypassing authentication; executing administrative operations; and in some cases achieving remote code execution on the database server. Modern web frameworks provide protection through parameterized queries and prepared statements that separate code from data, input validation, least privilege database accounts, and web application firewalls that detect injection patterns.",usageExample:"An attacker exploited SQL injection in a login form by entering `admin' OR '1'='1` as username, bypassing authentication and gaining administrative access to extract the entire user database containing 500,000 records.",references:[{title:"什么是SQL 注入?SQL 注入及防范措施(非常详细)零基础入门到精通,收藏这...",link:"https://blog.csdn.net/Libra1313/article/details/143759210"},{title:"什么是SQL注入?SQL注入详解(非常详细)零基础入门到精通,收藏这...",link:"https://www.yunweipai.com/45863.html"}]},Ho={T0475:qo},Uo=e({T0476:()=>Oo,default:()=>jo}),Oo={title:"Cross-Site Scripting",keywords:["Cross-Site Scripting","XSS","script injection","DOM-based XSS","reflected XSS","stored XSS"],aliases:["XSS Gongji"],definition:"A web security vulnerability where attackers inject malicious JavaScript code into websites that executes in victims' browsers, enabling session hijacking, phishing, or defacement.",description:"Cross-site scripting exploits insufficient input sanitization and output encoding in web applications, allowing injection of client-side scripts that execute in other users' contexts. Stored (persistent) XSS saves malicious scripts in databases that execute for every user viewing the compromised content, reflected XSS delivers payloads through URLs that trick victims into clicking malicious links, and DOM-based XSS manipulates client-side JavaScript to execute attacks without server involvement. Successful XSS enables stealing authentication cookies and session tokens, capturing keystrokes and form inputs, redirecting users to phishing sites, modifying page content to spread misinformation, and executing actions on behalf of victims. Modern attack techniques bypass basic filters using encoding obfuscation, polyglot payloads that work across contexts, and mutation-based XSS that exploits browser quirks. Defense requires input validation and sanitization, context-aware output encoding, Content Security Policy headers that restrict script sources, HTTPOnly cookies to prevent JavaScript access, and security libraries that automatically handle escaping.",usageExample:"An attacker injected XSS payload into a forum post that stole session cookies from 2,000 logged-in users who viewed the thread, enabling account takeover across the platform.",references:[{title:"Cross Site Scripting (XSS) | OWASP Foundation",link:"https://www.owasp.org/index.php/XSS_Attacks"},{title:"跨站脚本攻击 XSS 详解:一篇文章吃透核心知识_xss 跨站-CSDN博客",link:"https://blog.csdn.net/2301_77472496/article/details/156947232"}]},jo={T0476:Oo},No=e({T0477:()=>_o,default:()=>Go}),_o={title:"Exclusive Dealing",keywords:["Exclusive Dealing","forced exclusivity","choose-one-of-two","platform exclusivity requirement","anti-competitive practice","vendor lock-in"],aliases:["Erxuanyi"],definition:"An anti-competitive practice where dominant platforms force merchants or service providers to exclusively cooperate with them and prohibit participation on competing platforms, restricting market competition.",description:"Exclusive dealing, commonly known in China as 'choosing one of two' (二选一), occurs when platforms with significant market power leverage their position to force business partners into exclusivity arrangements. Dominant e-commerce platforms may require merchants to delist from competing marketplaces, delivery platforms may prohibit restaurants from partnering with rivals, or app stores may demand exclusive content distribution rights. These practices harm market competition by preventing smaller platforms from accessing supply, reduce consumer choice by fragmenting available products across platforms, increase costs for merchants who lose multi-channel distribution, and entrench dominant positions by blocking competitive challenges. Enforcement mechanisms include algorithmic demotion of non-exclusive partners, withholding promotional resources, terminating partnerships, or imposing financial penalties. Antitrust regulators increasingly scrutinize these practices under abuse of dominance provisions, particularly in digital markets where network effects amplify the harm from foreclosure. Legal boundaries depend on market share, competitive alternatives, and business justifications.",usageExample:"A dominant e-commerce platform forced thousands of merchants to choose exclusivity, threatening to remove search visibility for those maintaining presence on competing marketplaces, resulting in antitrust penalties exceeding $2.7 billion.",references:[{title:"简单使用spring cache - 简书",link:"https://www.jianshu.com/p/c387ba9a8617"},{title:"苏号朋:优势电商平台“二选一”行为中的消费者权益保护 | 法律适用20...",link:"https://dy.163.com/article/G87QJMVP0530W1MT.html"},{title:"C语言学习记录_.c文件在目标码中的位置-CSDN博客",link:"https://blog.csdn.net/weixin_51753483/article/details/142723098"}]},Go={T0477:_o},Qo=e({T0478:()=>Wo,default:()=>Vo}),Wo={title:"Self-Preferencing",keywords:["Self-Preferencing","preferential treatment","first-party advantage","platform favoritism","discriminatory ranking","vertical foreclosure"],aliases:["Ziwo Youdai"],definition:"The practice where platform operators give preferential treatment to their own products or services over third-party competitors in search rankings, recommendations, or access to platform features.",description:"Self-preferencing occurs when vertically integrated platforms that both operate marketplaces and sell products exploit their gatekeeper position to favor their own offerings. Common manifestations include prominently displaying first-party products in search results regardless of relevance or quality, providing internal products with better algorithmic treatment in recommendation systems, granting exclusive access to valuable user data or platform features, applying stricter policies to competitors, or bundling platform services with proprietary offerings. This conduct harms competition by making it impossible for superior third-party alternatives to compete fairly, stifles innovation as potential competitors face structural disadvantages, misleads consumers who assume neutral rankings, and enables platforms to extend dominance from one market into adjacent markets. Regulatory responses include mandatory disclosure of self-preferencing, algorithmic auditing requirements, structural separation of platform and merchant operations, and equal access obligations for platform infrastructure. The practice has become central to antitrust debates regarding digital platforms.",usageExample:"A platform operator's shopping service consistently appeared at the top of search results for product queries despite offering higher prices than third-party merchants, leveraging algorithmic preferencing to capture sales.",references:[{title:"每个人都需要自我关怀! - 简书",link:"https://www.jianshu.com/p/d8b00cdbd219"},{title:"高校学报及社科类综合刊2022年第6期法学要目汇编|公司法|经济法_网易...",link:"https://www.163.com/dy/article/HPHP8VEM0530W1MT.html"}]},Vo={T0478:Wo},Ko=e({T0479:()=>Jo,default:()=>Xo}),Jo={title:"Algorithm Recommendation",keywords:["Algorithm Recommendation","personalized recommendation","algorithmic curation","content ranking","recommendation engine","filter bubble"],aliases:["Suanfa Tuijian"],definition:"Automated systems that use machine learning algorithms to personalize content, product, or service recommendations for users based on behavioral data, preferences, and predictive modeling.",description:"Algorithmic recommendation systems analyze vast quantities of user interaction data including browsing history, purchase patterns, engagement metrics, and demographic information to predict and surface content likely to maximize specific objectives such as engagement, conversion, or time-on-platform. These systems power content feeds on social media, product suggestions in e-commerce, video recommendations, news curation, and advertisement targeting. While offering personalization benefits, these algorithms raise significant concerns: creation of filter bubbles that limit exposure to diverse viewpoints, amplification of misinformation and extreme content that generates engagement, manipulation of user behavior through addiction-optimizing designs, discriminatory outcomes when training data reflects societal biases, and lack of transparency regarding ranking criteria. Regulatory frameworks increasingly require disclosure of algorithmic ranking factors, user controls to disable personalization, human review of high-impact decisions, and regular auditing to detect discriminatory patterns or harmful content amplification.",usageExample:"A social media platform's recommendation algorithm progressively showed users more extreme political content to maximize engagement, contributing to polarization and amplification of misinformation during election periods.",references:[{title:"解决终身学习迁移学习:30年ILP介绍,四万字|算法|二阶|示例|alice...",link:"https://www.163.com/dy/article/JB4CHNCJ05567BBF.html"},{title:"“强化学习可解释性”最新2022综述_腾讯新闻",link:"https://new.qq.com/omn/20220117/20220117A0539600.html"}]},Xo={T0479:Jo},Yo=e({T0480:()=>Zo,default:()=>$o}),Zo={title:"Data Compliance",keywords:["Data Compliance","data protection regulation","data governance","regulatory compliance","data localization","cross-border data transfer"],aliases:["Shuju Heguі"],definition:"The organizational practices and legal obligations to collect, process, store, and transfer data in accordance with applicable privacy laws, security standards, and regulatory requirements.",description:"Data compliance encompasses adherence to diverse regulatory frameworks governing how organizations handle personal and sensitive information. Key regulations include GDPR in Europe requiring consent mechanisms and data subject rights, China's Personal Information Protection Law (PIPL) and Data Security Law establishing strict data localization and security requirements, and sector-specific standards like HIPAA for healthcare and PCI DSS for payment data. Compliance obligations include obtaining valid consent for data collection, implementing appropriate technical and organizational security measures, maintaining data processing records, conducting privacy impact assessments for high-risk processing, establishing data breach notification procedures, appointing data protection officers, and implementing cross-border transfer mechanisms like Standard Contractual Clauses or Binding Corporate Rules. Non-compliance results in substantial fines (up to 4% of global revenue under GDPR), operational restrictions, reputational damage, and civil liability. Organizations require comprehensive data governance programs mapping data flows, classifying information sensitivity, implementing privacy-by-design principles, and maintaining ongoing compliance monitoring.",usageExample:"A multinational corporation faced €50 million in GDPR fines for inadequate consent mechanisms, unlawful cross-border data transfers, and failure to honor data deletion requests from European users.",references:[{title:"什么是数据合规_数据合规简介_数据合规的优势以及应用场景-腾讯云...",link:"https://cloud.tencent.com/developer/techpedia/2571"},{title:"数据合规是什么意思?数据合规性如何运作?数据合规标准有哪些类型...",link:"https://www.zhihu.com/question/605801619/answer/3520316687"}]},$o={T0480:Zo},el=e({T0481:()=>tl,default:()=>al}),tl={title:"Privacy Compliance",keywords:["Privacy Compliance","privacy regulation","user consent","privacy rights","data subject rights","privacy-by-design"],aliases:["Yinsi Heguі"],definition:"The legal and ethical obligations to protect individuals' personal information privacy through transparent practices, user consent, data minimization, and respect for privacy rights.",description:"Privacy compliance focuses specifically on protecting individual privacy rights within broader data protection frameworks. Core principles include transparency through clear privacy notices explaining collection and use purposes, lawful basis for processing such as explicit consent or legitimate interest, data minimization collecting only necessary information, purpose limitation using data only for stated purposes, accuracy maintaining correct information, storage limitation retaining data only as long as needed, and security protecting against unauthorized access. Individuals possess rights including access to their data, correction of inaccuracies, deletion (right to be forgotten), data portability, objection to processing, and restriction of automated decision-making. Organizations must implement privacy-by-design principles integrating privacy considerations into system architecture, conduct privacy impact assessments for high-risk processing, establish consent management platforms, provide accessible privacy controls, and maintain audit trails of processing activities. Emerging privacy regulations emphasize proportionality, accountability, and user agency over data.",usageExample:"An app company received regulatory sanctions for collecting precise location data without explicit user consent, failing to provide clear privacy notices, and sharing user data with third parties beyond stated purposes.",references:[{title:"隐私政策的性质与法律规制 - 理论 - 中工网",link:"https://www.workercn.cn/c/2022-06-15/6979173.shtml"},{title:"【数说法律】App隐私政策的合规之道(上)",link:"https://mp.weixin.qq.com/s?__biz=MzI2NzkwMjA0Mg==&mid=2247504728&idx=4&sn=287c09619f0fb41a7db0bbd8980725e0&chksm=eaf55e6ddd82d77b426e5414ba1b60fd66a7375249d17ed99f25a503cf9fe78d2359d93ed894&scene=27"}]},al={T0481:tl},il=e({T0482:()=>nl,default:()=>rl}),nl={title:"Antitrust",keywords:["Antitrust","competition law","anti-monopoly","market dominance","anticompetitive practices","merger control"],aliases:["Fanlongduan"],definition:"Laws and regulations that prevent monopolistic practices, promote market competition, prohibit abuse of dominant positions, and regulate mergers to protect consumer welfare and competitive markets.",description:"Antitrust law addresses three primary concerns: monopolization and abuse of dominant market positions through exclusionary conduct, anticompetitive agreements between competitors such as price-fixing cartels or market allocation schemes, and anticompetitive mergers that substantially reduce competition. Digital platforms face heightened antitrust scrutiny due to network effects that naturally concentrate markets, control over essential infrastructure and data, vertical integration creating conflicts of interest, and acquisition strategies that eliminate potential competitors. Enforcement actions target conduct including predatory pricing to eliminate rivals, exclusive dealing arrangements, tying and bundling products, refusal to deal or provide access to essential facilities, discriminatory treatment of business partners, and killer acquisitions of emerging competitors. Remedies range from behavioral constraints and ongoing monitoring to structural remedies requiring divestitures or operational separation. Modern antitrust debates center on whether traditional consumer welfare standards adequately address digital market dynamics and whether preemptive intervention is justified given winner-take-all dynamics.",usageExample:"Regulators blocked a dominant platform's proposed acquisition of an emerging competitor, finding the transaction would eliminate future competitive constraint and entrench market power in violation of antitrust law.",references:[{title:"什么是政府管制 政府管制名词解释定义是什么?_搜狐网",link:"https://m.sohu.com/sa/820882633_121977025"},{title:"互联网平台经济反垄断市场界定问题刍议|云计算|谷歌|阿里巴巴_网易...",link:"https://www.163.com/dy/article/G5N1QJFO0511BK66.html"}]},rl={T0482:nl},sl=e({T0483:()=>ol,default:()=>ll}),ol={title:"Script",keywords:["Script","automation script","bot script","scripting attack","automated action","macro program"],aliases:["Jiaoben"],definition:"Automated programs or code sequences that perform repetitive tasks, often used by fraudsters to execute mass operations like account registration, credential testing, or transaction automation.",description:"Scripts in the fraud context range from simple browser automation using tools like Selenium or Puppeteer to sophisticated programs that integrate CAPTCHA solving, proxy rotation, and anti-detection measures. Attackers deploy scripts for credential stuffing attacks testing stolen password databases against multiple sites, inventory snatching for limited-release products, vote manipulation, review posting, social media engagement fraud, and mass account creation. Modern scripts employ headless browsers to execute JavaScript, randomize timing and interaction patterns to mimic human behavior, rotate IP addresses through proxy pools, solve or bypass CAPTCHA challenges through third-party services, and handle complex multi-step workflows. Detection relies on behavioral analysis identifying superhuman speed or consistency, device fingerprinting detecting reused browser profiles, CAPTCHA challenges that scripts struggle to solve, and honeypot techniques that trap automated interactions. While scripting technology itself is neutral, enabling legitimate automation and testing, the accessibility of fraud-focused scripting frameworks has lowered barriers for abuse operations.",usageExample:"Scalpers used custom scripts to purchase 10,000 concert tickets within 30 seconds of release by automatically solving CAPTCHAs and submitting orders faster than human purchasers could complete checkout.",references:[{title:"链接脚本(Linker Script)解析 - 简书",link:"https://www.jianshu.com/p/5945ff76fd41"},{title:"脚本Script介绍-CSDN博客",link:"https://blog.csdn.net/qq_51522554/article/details/153683187"}]},ll={T0483:ol},cl=e({T0484:()=>dl,default:()=>ul}),dl={title:"Bot",keywords:["Bot","automated agent","software robot","internet bot","web bot","malicious bot"],aliases:["Jiqiren"],definition:"Automated software agents that perform tasks on the internet, ranging from legitimate applications like search engine crawlers to malicious bots conducting fraud, spam, or cyberattacks.",description:"Bots represent automated programs that interact with online services, executing tasks with speed and scale impossible for human operators. Legitimate bots include search engine crawlers indexing web content, monitoring bots checking site availability, chatbots providing customer service, and trading bots executing algorithmic strategies. Malicious bots constitute a significant threat: credential stuffing bots testing stolen passwords, scraper bots harvesting content and data, spam bots posting unwanted content, click fraud bots generating fake advertising engagement, DDoS bots overwhelming servers, and social media bots spreading misinformation. Advanced bots employ residential proxies to appear as genuine users, solve CAPTCHAs through automation services, execute JavaScript to bypass basic bot detection, and coordinate in botnets controlled by command-and-control infrastructure. Bot detection technologies analyze behavioral patterns, device fingerprints, network characteristics, and challenge-response tests to distinguish automated traffic. Industry estimates suggest 30-50% of internet traffic originates from bots, with malicious bots representing substantial portions.",usageExample:"A botnet comprising 50,000 compromised devices launched coordinated attacks on e-commerce platforms during sales events, creating fake traffic to slow site performance while automated purchasing bots grabbed limited inventory.",references:[{title:"机器人(自动执行工作的机器装置)_360百科",link:"https://upimg.baike.haosou.com/doc/5374986-5611047.html"}]},ul={T0484:dl},hl=e({T0485:()=>pl,default:()=>ml}),pl={title:"Emulator",keywords:["Emulator","device emulation","virtual device","Android emulator","mobile emulator","environment simulation"],aliases:["Moniqi"],definition:"Software that replicates the functionality of mobile devices or other systems on computers, enabling fraudsters to run mobile apps in controlled environments for automated abuse or testing.",description:"Emulators in fraud operations serve as scalable platforms for running mobile applications without physical devices. Attackers use Android emulators like BlueStacks, Nox, or custom builds to operate multiple virtual devices simultaneously from a single computer, each appearing as distinct mobile devices to target applications. This enables mass account registration, automated gameplay for virtual currency farming, bonus abuse across device-based promotions, testing of fraud techniques without device costs, and circumventing device-based rate limits. Advanced fraud operations combine emulators with device spoofing to randomize device fingerprints, GPS spoofing for location-based restrictions, automation frameworks for scripted interactions, and cloud infrastructure for massive parallel operations. Apps attempt to detect emulators by checking for emulator-specific files and properties, analyzing hardware characteristics, detecting virtualization artifacts, and examining sensor data patterns. The cat-and-mouse game continues as emulator technologies improve realism while detection techniques become more sophisticated.",usageExample:"A fraud operation ran 500 emulator instances on cloud servers to farm virtual currency in a mobile game, creating automated accounts that completed tasks 24/7 before selling the currency to legitimate players.",references:[{title:"复旦发布「新闻推荐生态系统模拟器」SimuLine:单机支持万名读者、千...",link:"https://dy.163.com/article/I6TI20LI0511ABV6.html"},{title:"ZOMI酱:从艺术生到大模型训练专家_腾讯新闻",link:"https://new.qq.com/rain/a/20240410A05CWF00"},{title:"iOS下的自定义键盘(译) - 简书",link:"https://www.jianshu.com/p/0713849954de/"}]},ml={T0485:pl},gl=e({T0486:()=>fl,default:()=>yl}),fl={title:"Device Farm",keywords:["Device Farm","mass control","phone farm","multi-device control","device cluster","synchronized control"],aliases:["Qunkong"],definition:"Systems that enable centralized control of dozens to hundreds of physical mobile devices simultaneously, allowing operators to execute coordinated actions across multiple accounts for fraud or manipulation.",description:"Device farms consist of physical mobile devices, typically mounted on racks with USB hubs for charging and data connectivity, controlled through specialized software that broadcasts commands to all devices simultaneously or executes scripted workflows. These setups enable one operator to control 50-200+ devices, each running separate accounts with unique identities. Applications include coordinating engagement manipulation (likes, follows, reviews), executing synchronized purchasing for limited inventory, farming virtual currency or game rewards, conducting A/B testing of fraud techniques, and maintaining large-scale account networks. Each device appears as a genuine mobile user to platforms since they possess authentic hardware identifiers, sensors, and network characteristics that emulators struggle to replicate perfectly. Advanced farms implement automation frameworks like Appium for scripted interactions, custom ROM modifications to enhance control, proxy or VPN integration for IP diversity, and physical robots for precise touchscreen interactions. The capital investment in devices makes farms primarily economically viable for high-value fraud operations.",usageExample:"Authorities raided a device farm containing 300 smartphones running coordinated social media engagement fraud, generating fake followers and engagement worth over $2 million annually for clients seeking artificial popularity.",references:[{title:"投票功能系统怎么制作_如何防止微信投票活动中存在刷票行为?|手机...",link:"https://www.163.com/dy/article/KUOM8QLL0518FDSE.html"},{title:"防治“虚假种草”,小红书技术团队干了这几件大事-小红书团队",link:"https://www.51cto.com/article/741091.html"},{title:"嵌入式知识图谱WiKi(嵌入式开发/研发入门教程和路线图)_硬件开发入门...",link:"https://blog.csdn.net/qq582880551/article/details/123013592"}]},yl={T0486:fl},bl=e({T0487:()=>kl,default:()=>wl}),kl={title:"Device Spoofing Tool",keywords:["Device Spoofing Tool","device fingerprint changer","IMEI spoofer","hardware ID modification","device identity faker","fingerprint masking"],aliases:["Gaiji Gongju"],definition:"Software tools that modify or randomize device identifiers and hardware fingerprints, enabling fraudsters to evade device-based detection and create unlimited 'new' device identities on the same hardware.",description:"Device spoofing tools manipulate the identification parameters that platforms use to track and rate-limit devices. On rooted Android devices, these tools can modify IMEI numbers, Android ID, MAC addresses, device serial numbers, build properties, sensor fingerprints, and other hardware identifiers. They may also spoof GPS locations, modify screen resolution and DPI, randomize font lists and installed app signatures, and alter network parameters. Combined with account rotation, these tools enable a single physical device to appear as unlimited unique devices, defeating device bans and rate limits. Advanced tools offer profile management for saving and switching between consistent device identities, randomization algorithms that generate realistic fingerprint combinations, and anti-detection features that hide root access or tool presence. Platforms defend through multi-factor device fingerprinting combining dozens of parameters that are difficult to spoof consistently, behavioral analysis detecting unnatural patterns, and server-side validation of claimed device characteristics.",usageExample:"Scalpers used device spoofing tools to reset device fingerprints after each purchase attempt, allowing a single phone to appear as hundreds of different devices to circumvent per-device purchase limits on a flash sale.",references:[{title:"IEMI工具详解:IMEI修改技术原理与合法应用实战-CSDN博客",link:"https://blog.csdn.net/weixin_35364187/article/details/151773439"},{title:"设备风控攻防新挑战——定制ROM改机 - 知乎",link:"https://zhuanlan.zhihu.com/p/143740629"}]},wl={T0487:kl},vl=e({T0488:()=>Al,default:()=>Tl}),Al={title:"Automation Framework",keywords:["Automation Framework","test automation","Selenium","Appium","browser automation","UI automation"],aliases:["Zidonghua Kuangjia"],definition:"Software frameworks designed for automated testing and interaction with applications, repurposed by fraudsters to programmatically control browsers or mobile apps for scaled abuse operations.",description:"Automation frameworks like Selenium for web browsers, Appium for mobile apps, and Puppeteer for headless Chrome provide APIs for programmatic control of user interfaces, enabling scripts to navigate pages, fill forms, click buttons, and extract data. While created for legitimate software testing, these powerful tools are widely adopted in fraud operations due to their ability to mimic human interactions convincingly. Attackers leverage these frameworks for credential stuffing campaigns, account registration automation, web scraping, form submission spam, and complex multi-step fraud workflows. Advanced usage includes headless mode operation for efficiency, proxy integration for IP rotation, CAPTCHA solving service integration, user agent randomization, and sophisticated wait strategies to handle dynamic content. Detection focuses on identifying framework artifacts like WebDriver properties, timing patterns inconsistent with human behavior, and execution environments characteristic of automation. Platforms must balance blocking malicious automation while allowing legitimate testing and accessibility tools.",usageExample:"Fraudsters deployed Selenium-based scripts across thousands of proxies to automate credential stuffing attacks, testing 10 million stolen username-password combinations against banking sites and achieving 50,000 successful account compromises.",references:[{title:"...RPA财务数据分析机器人:理论框架与研发策略|自动化|计算机_网易...",link:"https://www.163.com/dy/article/HH5VJ6490519APOB.html"},{title:"自动化测试框架如果总结成这样,人人都能学好 - 简书",link:"https://www.jianshu.com/p/d604b10ecf98"},{title:"自动化测试框架:从零开始搭建一个简单的测试框架_软件测试项目搭建-C...",link:"https://blog.csdn.net/hlsxjh/article/details/154949168"}]},Tl={T0488:Al};export{Rr as $,S as $n,Sa as $t,js as A,Oe as An,Oi as At,us as B,de as Bn,di as Bt,lo as C,ot as Cn,ln as Ct,Xs as D,Je as Dn,Ji as Dt,$s as E,Ze as En,Zi as Et,Rs as F,Se as Fn,Si as Ft,Xr as G,J as Gn,Ja as Gt,rs as H,ne as Hn,ni as Ht,Ts as I,Ae as In,Ai as It,jr as J,O as Jn,Oa as Jt,Vr as K,W as Kn,Wa as Kt,ws as L,ke as Ln,ki as Lt,Fs as M,Ie as Mn,Ii as Mt,zs as N,Ee as Nn,Ei as Nt,Vs as O,We as On,Wi as Ot,Ms as P,Ce as Pn,Ci as Pt,Mr as Q,C as Qn,Ca as Qt,ys as R,fe as Rn,fi as Rt,ho as S,dt as Sn,un as St,ao as T,tt as Tn,tn as Tt,as as U,te as Un,ti as Ut,ls as V,oe as Vn,oi as Vt,$r as W,Z as Wn,Za as Wt,Fr as X,I as Xn,Ia as Xt,Hr as Y,q as Yn,qa as Yt,zr as Z,E as Zn,Ea as Zt,xo as _,St as _n,Rn as _t,cl as a,oa as an,o as ar,lr as at,bo as b,ft as bn,yn as bt,el as c,Zt as cn,$n as ct,Qo as d,_t as dn,Gn as dt,Aa as en,A as er,Tr as et,No as f,Ot as fn,jn as ft,Lo as g,Ct as gn,Mn as gt,Do as h,Et as hn,zn as ht,hl as i,da as in,d as ir,ur as it,Hs as j,qe as jn,qi as jt,Gs as k,_e as kn,_i as kt,Yo as l,Jt as ln,Xn as lt,Po as m,It as mn,Fn as mt,bl as n,fa as nn,f as nr,yr as nt,sl as o,na as on,n as or,rr as ot,Uo as p,qt as pn,Hn as pt,Gr as q,_ as qn,_a as qt,gl as r,pa as rn,p as rr,mr as rt,il as s,ta as sn,t as sr,ar as st,vl as t,ka as tn,k as tr,wr as tt,Ko as u,Wt as un,Vn as ut,Bo as v,At as vn,Tn as vt,ro as w,nt as wn,rn as wt,go as x,pt as xn,mn as xt,vo as y,kt as yn,wn as yt,ms as z,pe as zn,pi as zt};